function safeStr(s) {
  return String(s ?? "").replace(/[<>&"]/g, (c) => ({ "<":"&lt;", ">":"&gt;", "&":"&amp;", '"':"&quot;" }[c]));
}

function escapeHtml(str){
  return String(str || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function simpleDiff(before, after){
  const beforeWords = String(before || "").split(/\s+/);
  const afterWords = String(after || "").split(/\s+/);

  const beforeSet = new Set(beforeWords);
  const afterSet = new Set(afterWords);

  const highlightedAfter = afterWords.map(w => {
    if (!beforeSet.has(w)) {
      return `<span style="background:#dcfce7;">${w}</span>`;
    }
    return w;
  }).join(" ");

  const highlightedBefore = beforeWords.map(w => {
    if (!afterSet.has(w)) {
      return `<span style="background:#fee2e2;">${w}</span>`;
    }
    return w;
  }).join(" ");

  return {
    before: highlightedBefore,
    after: highlightedAfter
  };
}


function workspaceDiffTokenize(text){
  return String(text || "").match(/\s+|[^\s]+/g) || [];
}

function workspaceIsWhitespaceToken(token){
  return /^\s+$/.test(String(token || ""));
}

function workspaceAiTrackChangesHtml(before, after){
  const a = workspaceDiffTokenize(before);
  const b = workspaceDiffTokenize(after);

  const maxTokens = 900;
  if (a.length > maxTokens || b.length > maxTokens) {
    return `
      <div class="ws-track-block">
        <div class="ws-track-label removed">Previous version</div>
        <div class="ws-track-old">${safeStr(before || "No previous text.")}</div>
        <div class="ws-track-label added">AI proposed version</div>
        <div class="ws-track-new">${safeStr(after || "")}</div>
      </div>
    `;
  }

  const dp = Array(a.length + 1).fill(null).map(() => Array(b.length + 1).fill(0));

  for (let i = a.length - 1; i >= 0; i--) {
    for (let j = b.length - 1; j >= 0; j--) {
      if (a[i] === b[j]) dp[i][j] = dp[i + 1][j + 1] + 1;
      else dp[i][j] = Math.max(dp[i + 1][j], dp[i][j + 1]);
    }
  }

  const out = [];
  let i = 0;
  let j = 0;

  while (i < a.length && j < b.length) {
    if (a[i] === b[j]) {
      out.push(safeStr(a[i]));
      i++;
      j++;
    } else if (dp[i + 1][j] >= dp[i][j + 1]) {
      out.push(workspaceIsWhitespaceToken(a[i]) ? safeStr(a[i]) : `<span class="ws-diff-removed">${safeStr(a[i])}</span>`);
      i++;
    } else {
      out.push(workspaceIsWhitespaceToken(b[j]) ? safeStr(b[j]) : `<span class="ws-diff-added">${safeStr(b[j])}</span>`);
      j++;
    }
  }

  while (i < a.length) {
    out.push(workspaceIsWhitespaceToken(a[i]) ? safeStr(a[i]) : `<span class="ws-diff-removed">${safeStr(a[i])}</span>`);
    i++;
  }

  while (j < b.length) {
    out.push(workspaceIsWhitespaceToken(b[j]) ? safeStr(b[j]) : `<span class="ws-diff-added">${safeStr(b[j])}</span>`);
    j++;
  }

  return out.join("");
}

function workspaceAiDiffOps(before, after){
  const a = workspaceDiffTokenize(before);
  const b = workspaceDiffTokenize(after);
  const maxTokens = 900;
  if (a.length > maxTokens || b.length > maxTokens) return null;
  const dp = Array(a.length + 1).fill(null).map(() => Array(b.length + 1).fill(0));
  for (let i = a.length - 1; i >= 0; i--) {
    for (let j = b.length - 1; j >= 0; j--) {
      if (a[i] === b[j]) dp[i][j] = dp[i + 1][j + 1] + 1;
      else dp[i][j] = Math.max(dp[i + 1][j], dp[i][j + 1]);
    }
  }
  const raw = [];
  let i = 0;
  let j = 0;
  while (i < a.length && j < b.length) {
    if (a[i] === b[j]) {
      raw.push({ type:"same", text:a[i] }); i++; j++;
    } else if (dp[i + 1][j] >= dp[i][j + 1]) {
      raw.push({ type:"removed", text:a[i] }); i++;
    } else {
      raw.push({ type:"added", text:b[j] }); j++;
    }
  }
  while (i < a.length) { raw.push({ type:"removed", text:a[i] }); i++; }
  while (j < b.length) { raw.push({ type:"added", text:b[j] }); j++; }
  const grouped = [];
  let current = null;
  let changeCounter = 0;
  const flush = () => { if (!current) return; grouped.push(current); current = null; };
  raw.forEach(op => {
    const type = String(op.type || "same");
    const text = String(op.text || "");
    if (type === "same" || workspaceIsWhitespaceToken(text)) {
      flush(); grouped.push({ type:"same", text }); return;
    }
    if (current && current.type === type) current.text += text;
    else { flush(); current = { type, text, change_id: `chg_${changeCounter++}` }; }
  });
  flush();
  return grouped;
}

function workspaceAiInteractiveTrackChangesHtml(before, after){
  const beforeTokens = workspaceDiffTokenize(before);
  const afterTokens = workspaceDiffTokenize(after);

  const maxTokens = 1200;

  const beforeWordSet = new Set(
    beforeTokens
      .filter(t => !workspaceIsWhitespaceToken(t))
      .map(t => String(t || "").toLowerCase())
  );

  let html = "";

  if (afterTokens.length > maxTokens || beforeTokens.length > maxTokens) {
    html = safeStr(after || "");
  } else {
    html = afterTokens.map(token => {
      const raw = String(token || "");
      if (!raw) return "";
      if (workspaceIsWhitespaceToken(raw)) return safeStr(raw);

      const normalized = raw.toLowerCase();
      const isAdded = !beforeWordSet.has(normalized);

      return isAdded
        ? `<span class="ws-diff-added ws-ai-added-text">${safeStr(raw)}</span>`
        : safeStr(raw);
    }).join("");
  }

  return `
    <div
      class="ws-ai-interactive-diff ws-ai-simple-editor"
      data-ai-interactive-diff
      contenteditable="true"
      spellcheck="true"
      role="textbox"
      aria-label="Editable AI proposed packet section"
    >${html}</div>
  `;
}

