const PRIOR_AUTH_DEFAULT_STATUS = "Auth Needed";

function normalizePriorAuthStatus(value){
  const raw = String(value || "").trim();
  if (!raw) return PRIOR_AUTH_DEFAULT_STATUS;

  const found = PRIOR_AUTH_STATUSES.find(s => s.toLowerCase() === raw.toLowerCase());
  if (found) return found;

  const compact = raw
    .toLowerCase()
    .replace(/[_-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  const aliases = {
    "needed": "Auth Needed",
    "auth needed": "Auth Needed",
    "authorization needed": "Auth Needed",
    "prior auth needed": "Auth Needed",
    "pa needed": "Auth Needed",

    "draft": "Draft",

    "submitted": "Submitted",
    "sent": "Submitted",
    "filed": "Submitted",

    "pending": "Pending",
    "in review": "Pending",
    "under review": "Pending",

    "missing docs": "Missing Documentation",
    "missing documentation": "Missing Documentation",
    "missing documents": "Missing Documentation",
    "needs docs": "Missing Documentation",

    "peer to peer": "Peer-to-Peer Needed",
    "peer-to-peer": "Peer-to-Peer Needed",
    "p2p": "Peer-to-Peer Needed",
    "peer review": "Peer-to-Peer Needed",

    "approved": "Approved",
    "authorized": "Approved",

    "partial": "Partially Approved",
    "partially approved": "Partially Approved",
    "partial approval": "Partially Approved",

    "denied": "Denied",
    "rejected": "Denied",

    "appeal needed": "Appeal Needed",
    "appeal required": "Appeal Needed",
    "appeal": "Appeal Needed",
    "appeal draft": "Appeal Needed",
    "appeal in progress": "Appeal Needed",
    "next appeal": "Appeal Needed",
    "next round": "Appeal Needed",
    "another round": "Appeal Needed",
    "prior auth appeal needed": "Appeal Needed",
    "pa appeal needed": "Appeal Needed",

    "appeal submitted": "Appeal Submitted",
    "appeal sent": "Appeal Submitted",
    "appeal filed": "Appeal Submitted",
    "next round submitted": "Appeal Submitted",
    "prior auth appeal submitted": "Appeal Submitted",
    "pa appeal submitted": "Appeal Submitted",

    "expiring": "Expiring Soon",
    "expiring soon": "Expiring Soon",

    "expired": "Expired",

    "ready": "Ready to Bill",
    "ready to bill": "Ready to Bill",

    "linked": "Linked to Claim",
    "linked to claim": "Linked to Claim",

    "not pursued": "Not Pursued",
    "do not pursue": "Not Pursued",
    "not pursuing": "Not Pursued",
    "service not performed": "Not Pursued",
    "service not done": "Not Pursued",
    "do not perform service": "Not Pursued",
    "do not do service": "Not Pursued",
    "cancel service": "Not Pursued",
    "cancelled service": "Not Pursued",
    "canceled service": "Not Pursued",
    "patient not proceeding": "Not Pursued",
    "not proceeding": "Not Pursued"
  };

  return aliases[compact] || PRIOR_AUTH_DEFAULT_STATUS;
}

function priorAuthCaseId(){
  return "pa_" + uuid();
}

function normalizePriorAuthListValue(value){
  if (Array.isArray(value)) {
    return value
      .map(v => String(v || "").trim())
      .filter(Boolean);
  }

  const raw = String(value || "").trim();
  if (!raw) return [];

  return raw
    .split(/[,\n|;]+/)
    .map(v => v.trim())
    .filter(Boolean);
}

function normalizePriorAuthBoolean(value){
  if (value === true) return true;
  const raw = String(value || "").trim().toLowerCase();
  return ["true", "yes", "y", "1", "required", "needed"].includes(raw);
}

