function priorAuthDedupeText(value){
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function priorAuthDedupeDate(value){
  const raw = String(value || "").trim();
  if (!raw) return "";
  const day = raw.slice(0, 10);
  return /^\d{4}-\d{2}-\d{2}$/.test(day) ? day : "";
}

function priorAuthCaseDedupeKey(row = {}){
  const payer = priorAuthDedupeText(row.payer);

  const authNumber = priorAuthDedupeText(
    row.auth_number ||
    row.authorization_number ||
    row.prior_auth_number
  );

  const patient = priorAuthDedupeText(
    row.patient_id ||
    row.patient_name
  );

  const service = priorAuthDedupeText(
    row.cpt_hcpcs ||
    row.cpt ||
    row.hcpcs ||
    row.procedure_code ||
    row.requested_service ||
    row.service ||
    row.procedure
  );

  const date = priorAuthDedupeDate(
    row.submitted_date ||
    row.determination_date ||
    row.expiration_date ||
    row.scheduled_service_date
  );

  if (payer && authNumber) return `auth:${payer}:${authNumber}`;
  if (authNumber && patient) return `authpatient:${authNumber}:${patient}`;
  if (payer && patient && service && date) return `svc:${payer}:${patient}:${service}:${date}`;

  return "";
}

function priorAuthFindDuplicateCaseIndex(rows = [], incoming = {}){
  const key = priorAuthCaseDedupeKey(incoming);
  if (!key) return -1;

  return (Array.isArray(rows) ? rows : []).findIndex(row =>
    priorAuthCaseDedupeKey(row) === key
  );
}


function priorAuthIncomingValueIsUseful(key, value, existing = {}){
  if (Array.isArray(value)) return value.length > 0;

  if (typeof value === "number") return Number.isFinite(value) && value !== 0;
  if (typeof value === "boolean") return value === true;

  const text = String(value || "").trim();
  if (!text) return false;

  if (
    key === "status" &&
    text === PRIOR_AUTH_DEFAULT_STATUS &&
    String(existing.status || "").trim() &&
    String(existing.status || "").trim() !== PRIOR_AUTH_DEFAULT_STATUS
  ) {
    return false;
  }

  return true;
}

function priorAuthMergeCaseForUpdate(existing = {}, incoming = {}, org_id = ""){
  const merged = { ...(existing || {}) };

  Object.entries(incoming || {}).forEach(([key, value]) => {
    if (["auth_case_id","org_id","created_at","created_by"].includes(key)) return;

    if (priorAuthIncomingValueIsUseful(key, value, existing)) {
      merged[key] = value;
    }
  });

  return {
    ...merged,
    auth_case_id: existing.auth_case_id || incoming.auth_case_id,
    org_id: String(org_id || existing.org_id || incoming.org_id || "").trim(),
    created_at: existing.created_at || incoming.created_at || nowISO(),
    created_by: existing.created_by || incoming.created_by || "",
    updated_at: nowISO()
  };
}

function getAllPriorAuthCases(){
  return readJSON(FILES.prior_auth_cases, []);
}

function getPriorAuthCases(org_id){
  const oid = String(org_id || "").trim();

  return getAllPriorAuthCases()
    .filter(x => String(x.org_id || "") === oid)
    .map(x => normalizePriorAuthCase(x));
}

function savePriorAuthCasesForOrg(org_id, rows){
  const oid = String(org_id || "").trim();
  const all = getAllPriorAuthCases();
  const keep = all.filter(x => String(x.org_id || "") !== oid);

  const normalized = (Array.isArray(rows) ? rows : [])
    .map(x => normalizePriorAuthCase(x, { org_id: oid }))
    .filter(x => String(x.org_id || "").trim());

  writeJSON(FILES.prior_auth_cases, [...keep, ...normalized]);
  return normalized;
}

function getPriorAuthCaseById(org_id, auth_case_id){
  const oid = String(org_id || "").trim();
  const id = String(auth_case_id || "").trim();

  if (!oid || !id) return null;

  return getPriorAuthCases(oid)
    .find(x => String(x.auth_case_id || "") === id) || null;
}

function upsertPriorAuthCase(org_id, input, user_id = ""){
  const source = input || {};
  const oid = String(org_id || source.org_id || "").trim();

  if (!oid) {
    return { ok:false, error:"missing_org_id", case:null };
  }

  const rows = getPriorAuthCases(oid);

  const incoming = normalizePriorAuthCase(source, {
    org_id: oid,
    created_by: user_id
  });

  let idx = rows.findIndex(x =>
    String(x.auth_case_id || "") === String(incoming.auth_case_id || "")
  );

  if (idx < 0) {
    idx = priorAuthFindDuplicateCaseIndex(rows, incoming);
  }

  let targetAuthCaseId = String(incoming.auth_case_id || "");

  if (idx >= 0) {
    const existing = rows[idx];

    rows[idx] = normalizePriorAuthCase(
      priorAuthMergeCaseForUpdate(existing, incoming, oid)
    );

    targetAuthCaseId = String(rows[idx].auth_case_id || targetAuthCaseId || "");
  } else {
    const created = normalizePriorAuthCase({
      ...incoming,
      org_id: oid,
      created_at: incoming.created_at || nowISO(),
      updated_at: nowISO(),
      created_by: incoming.created_by || user_id || ""
    });

    targetAuthCaseId = String(created.auth_case_id || targetAuthCaseId || "");
    rows.push(created);
  }

  const saved = savePriorAuthCasesForOrg(oid, rows);

  const found = saved.find(x =>
    String(x.auth_case_id || "") === String(targetAuthCaseId || "")
  );

  return { ok:true, case: found || incoming };
}

function deletePriorAuthCaseForSmokeOnly(org_id, auth_case_id){
  const oid = String(org_id || "").trim();
  const id = String(auth_case_id || "").trim();

  if (!oid || !id) return;

  const rows = getPriorAuthCases(oid)
    .filter(x => String(x.auth_case_id || "") !== id);

  savePriorAuthCasesForOrg(oid, rows);
}

function getPriorAuthUploads(org_id){
  const oid = String(org_id || "").trim();

  return readJSON(FILES.prior_auth_uploads, [])
    .filter(x => String(x.org_id || "") === oid);
}

function savePriorAuthUploadRecord(record = {}){
  const all = readJSON(FILES.prior_auth_uploads, []);
  const now = nowISO();

  const row = {
    upload_id: String(record.upload_id || "pau_" + uuid()).trim(),
    org_id: String(record.org_id || "").trim(),
    file_name: String(record.file_name || record.filename || "").trim(),
    file_type: String(record.file_type || record.mime_type || "").trim(),
    file_url: String(record.file_url || record.url || "").trim(),
    stored_path: String(record.stored_path || record.absPath || "").trim(),
    upload_purpose: String(record.upload_purpose || "prior_authorization").trim(),
    status: String(record.status || "stored").trim(),
    parsed_case_count: Number(record.parsed_case_count || 0) || 0,
    needs_review: record.needs_review !== false,
    created_at: String(record.created_at || now).trim(),
    created_by: String(record.created_by || "").trim(),
    text_excerpt: String(record.text_excerpt || "").trim(),
    extracted_text: String(record.extracted_text || "").trim(),
    appeal_submission_address: String(record.appeal_submission_address || "").trim(),
    notes: String(record.notes || "").trim()
  };

  all.push(row);
  writeJSON(FILES.prior_auth_uploads, all);
  return row;
}

function priorAuthUploadFileUrl(row = {}){
  const direct = String(row.file_url || row.url || "").trim();
  if (direct) return direct;

  const notes = String(row.notes || "");
  const m = notes.match(/Stored file:\s*(\/uploads\/support\/[^\s<>"']+)/);
  if (m && m[1]) return m[1];

  return "";
}

function priorAuthUploadStoredPath(row = {}){
  const direct = String(row.stored_path || row.absPath || "").trim();
  if (direct) return direct;

  const fileUrl = priorAuthUploadFileUrl(row);
  if (!fileUrl || !fileUrl.startsWith("/uploads/support/")) return "";

  const rel = fileUrl.replace(/^\/uploads\/support\//, "");
  return path.join(__dirname, "uploads", "support", rel);
}

function priorAuthSafeDeleteStoredUploadFile(row = {}){
  const abs = priorAuthUploadStoredPath(row);
  if (!abs) return false;

  const supportDir = path.join(__dirname, "uploads", "support");
  const resolved = path.resolve(abs);
  const resolvedSupport = path.resolve(supportDir);

  if (!resolved.startsWith(resolvedSupport)) return false;

  try {
    if (fs.existsSync(resolved)) {
      fs.unlinkSync(resolved);
      return true;
    }
  } catch (_) {}

  return false;
}

function deletePriorAuthUploadForOrg(org_id, upload_id){
  const oid = String(org_id || "").trim();
  const id = String(upload_id || "").trim();

  if (!oid || !id) return { ok:false, deleted:false, deleted_case_count:0 };

  const all = readJSON(FILES.prior_auth_uploads, []);
  const target = all.find(x =>
    String(x.org_id || "") === oid &&
    String(x.upload_id || "") === id
  );

  if (!target) return { ok:false, deleted:false, deleted_case_count:0 };

  priorAuthSafeDeleteStoredUploadFile(target);

  const keptUploads = all.filter(x =>
    !(String(x.org_id || "") === oid && String(x.upload_id || "") === id)
  );

  writeJSON(FILES.prior_auth_uploads, keptUploads);

  const beforeCases = getPriorAuthCases(oid);
  const keptCases = beforeCases.filter(x =>
    String(x.source_upload_batch_id || "") !== id
  );
  const deletedCaseCount = beforeCases.length - keptCases.length;

  if (deletedCaseCount > 0) {
    savePriorAuthCasesForOrg(oid, keptCases);
  }

  return { ok:true, deleted:true, deleted_case_count: deletedCaseCount };
}

function priorAuthNormalizeHeaderKey(value){
  return String(value || "")
    .toLowerCase()
    .replace(/[_-]+/g, " ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const PRIOR_AUTH_HEADER_ALIASES = {
  patient_id: [
    "patient id", "patient_id", "patient reference", "mrn",
    "member id", "member_id", "subscriber id"
  ],
  patient_name: [
    "patient name", "patient_name", "member name", "name"
  ],
  payer: [
    "payer", "payer name", "insurance", "insurance company", "health plan", "plan"
  ],
  provider: [
    "provider", "ordering provider", "rendering provider", "physician", "clinician"
  ],
  specialty: [
    "specialty", "department", "service line"
  ],
  cpt_hcpcs: [
    "cpt", "cpt code", "cpt_code", "hcpcs", "hcpcs code",
    "procedure code", "procedure_code", "service code", "service_code"
  ],
  icd10: [
    "icd10", "icd 10", "icd-10", "icd_10",
    "diagnosis code", "diagnosis_code", "dx", "dx code", "dx_code"
  ],
  requested_service: [
    "requested service", "service", "procedure", "requested procedure",
    "requested item", "auth service"
  ],
  submitted_date: [
    "submitted date", "submission date", "submitted", "date submitted",
    "auth submitted date"
  ],
  expiration_date: [
    "expiration date", "expires", "expires at", "auth expiration",
    "authorization expiration", "valid through"
  ],
  auth_number: [
    "auth number", "authorization number", "prior auth number", "pa number",
    "auth #", "authorization #", "approval number"
  ],
  status: [
    "status", "auth status", "authorization status", "prior auth status"
  ],
  denial_reason: [
    "denial reason", "denial", "reason denied", "reason", "payer reason"
  ],
  peer_to_peer_required: [
    "peer to peer", "peer-to-peer", "p2p", "peer review", "peer to peer required"
  ],
  missing_documentation: [
    "missing documentation", "missing docs", "missing documents", "docs needed",
    "documentation needed", "needed documents"
  ],
  estimated_revenue_at_risk: [
    "estimated revenue at risk", "revenue at risk", "amount at risk",
    "estimated value", "expected revenue"
  ],
  notes: [
    "notes", "note", "comments", "comment"
  ]
};

function priorAuthFieldForHeader(header){
  const normalized = priorAuthNormalizeHeaderKey(header);
  if (!normalized) return "";

  for (const [field, aliases] of Object.entries(PRIOR_AUTH_HEADER_ALIASES)) {
    if ((aliases || []).some(alias => priorAuthNormalizeHeaderKey(alias) === normalized)) {
      return field;
    }
  }

  return "";
}

function priorAuthRevenueEvidenceText(row = {}){
  return Object.entries(row || {})
    .map(([key, value]) => `${key}: ${value}`)
    .join(" ")
    .toLowerCase();
}

function priorAuthRevenueAtRiskIsDisclaimed(row = {}){
  const text = priorAuthRevenueEvidenceText(row);

  return [
    "testing placeholder",
    "test placeholder",
    "placeholder",
    "no dollar amount",
    "no dollar value",
    "no amount was shown",
    "no amount shown",
    "not shown in the letter",
    "not shown on the letter",
    "not available",
    "not provided",
    "unknown amount"
  ].some(token => text.includes(token));
}

function priorAuthUploadedRowHasExplicitRevenueAtRisk(row = {}){
  if (priorAuthRevenueAtRiskIsDisclaimed(row)) return false;

  return Object.entries(row || {}).some(([key, value]) => {
    const field = priorAuthFieldForHeader(key);
    if (field !== "estimated_revenue_at_risk") return false;

    const amount = Number(String(value || "").replace(/[^0-9.-]/g, ""));
    return Number.isFinite(amount) && amount > 0;
  });
}

function priorAuthApplyUploadedRevenueAtRiskGuard(input = {}, sourceRow = {}, defaults = {}){
  const allowTrustedInternalEstimate = defaults && defaults.prior_auth_allow_internal_revenue_estimate === true;

  if (allowTrustedInternalEstimate) return input;

  if (priorAuthUploadedRowHasExplicitRevenueAtRisk(sourceRow)) return input;

  if (
    input &&
    (input.estimated_revenue_at_risk != null || input.revenue_at_risk != null)
  ) {
    delete input.estimated_revenue_at_risk;
    delete input.revenue_at_risk;

    const existingNotes = String(input.notes || "").trim();
    const guardNote = "Estimated revenue at risk not determined from uploaded document.";
    input.notes = existingNotes
      ? `${existingNotes} ${guardNote}`
      : guardNote;
  }

  return input;
}

function priorAuthRevenueAtRiskDisplay(value){
  const amount = Number(value || 0) || 0;
  return amount > 0 ? formatMoneyUI(amount) : "Not determined";
}

function tjhpPriorAuthNextActionLabel(row = {}){
  const status = String(row.status || "").trim();

  if (status === "Missing Documentation") return "Upload/collect missing docs";
  if (status === "Peer-to-Peer Needed") return "Schedule peer-to-peer";
  if (status === "Denied") return "Continue Prior Auth Appeal";
  if (status === "Appeal Needed") return "Continue Prior Auth Appeal";
  if (status === "Appeal Submitted") {
    const followUp = String(row.appeal_follow_up_date || "").trim();
    return followUp ? `Follow up with payer by ${followUp}` : "Upload Payer Response";
  }
  if (status === "Partially Approved") return "Review approval limits";
  if (status === "Expiring Soon") return "Renew or confirm service timing";
  if (status === "Expired") return "Re-submit or renew authorization";
  if (status === "Pending" || status === "Submitted") return "Follow up with payer";
  if (status === "Auth Needed" || status === "Draft") return "Complete authorization request";

  if (status === "Ready to Bill") return "Link to billed claim";
  if (status === "Not Pursued") return "No further action";

  return "Review prior authorization";
}

function tjhpPriorAuthLifecycleGroupForRow(row = {}){
  const status = String(row.status || "").trim();

  if (["Auth Needed", "Draft"].includes(status)) return "intake";
  if (["Submitted", "Pending"].includes(status)) return "pending";
  if (["Denied", "Partially Approved", "Appeal Needed", "Missing Documentation", "Peer-to-Peer Needed"].includes(status)) return "denied_partial";
  if (status === "Appeal Submitted") return "appeal_submitted";
  if (["Approved", "Ready to Bill", "Expiring Soon", "Expired"].includes(status)) return "approved_ready";

  return "";
}

function tjhpPriorAuthLifecycleLaneDefinitions(){
  return [
    {
      key: "intake",
      label: "Intake / Draft",
      helper: "Manual or uploaded prior-auth cases not yet submitted.",
      href: "/data-management?tab=upload&dm_view=prior-auth#prior-auth-upload-activity"
    },
    {
      key: "pending",
      label: "Submitted / Pending",
      helper: "Prior-auth requests submitted or awaiting payer response.",
      href: "/actions?tab=prior-auth"
    },
    {
      key: "denied_partial",
      label: "Denied / Partial",
      helper: "Denied, partially approved, missing documentation, or peer-to-peer cases.",
      href: "/actions?tab=prior-auth"
    },
    {
      key: "appeal_submitted",
      label: "Appeal Submitted",
      helper: "Manual appeal submission logged and awaiting payer response.",
      href: "/actions?tab=prior-auth"
    },
    {
      key: "approved_ready",
      label: "Approved / Ready",
      helper: "Approved, ready-to-bill, expiring, or expired authorizations.",
      href: "/actions?tab=prior-auth"
    }
  ];
}

function tjhpPriorAuthLifecycleLaneModel(org_id = ""){
  const rows = getPriorAuthCases(org_id).map(normalizePriorAuthCase);
  const definitions = tjhpPriorAuthLifecycleLaneDefinitions();

  const groups = new Map(
    definitions.map(def => [
      def.key,
      {
        ...def,
        count: 0,
        known_revenue_at_risk: 0,
        not_determined_count: 0,
        latest_follow_up_date: "",
        latest_case: null,
        statuses: {}
      }
    ])
  );

  rows.forEach(row => {
    const groupKey = tjhpPriorAuthLifecycleGroupForRow(row);
    if (!groupKey || !groups.has(groupKey)) return;

    const bucket = groups.get(groupKey);
    bucket.count += 1;

    const status = String(row.status || "Unknown").trim() || "Unknown";
    bucket.statuses[status] = (bucket.statuses[status] || 0) + 1;

    const revenue = Number(row.estimated_revenue_at_risk || 0) || 0;
    if (revenue > 0) {
      bucket.known_revenue_at_risk += revenue;
    } else {
      bucket.not_determined_count += 1;
    }

    const submission = tjhpPriorAuthLatestSubmission(row);
    const followUp = String(
      row.appeal_follow_up_date ||
      (submission && submission.follow_up_date) ||
      ""
    ).trim();

    if (followUp && (!bucket.latest_follow_up_date || followUp < bucket.latest_follow_up_date)) {
      bucket.latest_follow_up_date = followUp;
    }

    const currentUpdated = new Date(row.updated_at || row.created_at || 0).getTime() || 0;
    const latestUpdated = bucket.latest_case
      ? (new Date(bucket.latest_case.updated_at || bucket.latest_case.created_at || 0).getTime() || 0)
      : 0;

    if (!bucket.latest_case || currentUpdated > latestUpdated) {
      bucket.latest_case = row;
    }
  });

  const activeCount = Array.from(groups.values()).reduce((sum, item) => sum + item.count, 0);
  const knownRevenueAtRisk = Array.from(groups.values()).reduce((sum, item) => sum + item.known_revenue_at_risk, 0);

  return {
    rows,
    groups: Array.from(groups.values()),
    active_count: activeCount,
    known_revenue_at_risk: knownRevenueAtRisk,
    not_determined_count: rows.filter(row => (Number(row.estimated_revenue_at_risk || 0) || 0) <= 0).length
  };
}

function tjhpPriorAuthLifecycleLaneHtml(org_id = ""){
  const model = tjhpPriorAuthLifecycleLaneModel(org_id);
  const groups = model.groups || [];

  const cardHtml = groups.map(group => {
    const hasRows = Number(group.count || 0) > 0;
    const revenueText = group.known_revenue_at_risk > 0
      ? `Known at risk: ${formatMoneyUI(group.known_revenue_at_risk)}`
      : "Revenue at risk: Not determined";

    const statusText = Object.entries(group.statuses || {})
      .map(([status, count]) => `${status}: ${formatNumberUI(count)}`)
      .join(" · ");

    const followUpText = group.latest_follow_up_date
      ? `Next follow-up: ${group.latest_follow_up_date}`
      : "";

    return `
      <a href="${safeStr(group.href)}" style="text-decoration:none;color:inherit;flex:1;min-width:170px;">
        <div style="border:1px solid var(--border);border-radius:12px;padding:12px;background:var(--card);height:100%;">
          <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start;">
            <div style="font-weight:950;">${safeStr(group.label)}</div>
            <span class="badge ${hasRows ? "warn" : "ok"}">${formatNumberUI(group.count || 0)}</span>
          </div>
          <div class="muted small" style="margin-top:4px;">${safeStr(group.helper)}</div>
          ${hasRows ? `
            <div class="muted small" style="margin-top:8px;">${safeStr(revenueText)}</div>
            ${statusText ? `<div class="muted small" style="margin-top:4px;">${safeStr(statusText)}</div>` : ""}
            ${followUpText ? `<div class="muted small" style="margin-top:4px;">${safeStr(followUpText)}</div>` : ""}
          ` : `
            <div class="muted small" style="margin-top:8px;">No prior-auth cases in this lane.</div>
          `}
        </div>
      </a>
    `;
  }).join("");

  return `
    <div class="insight-card" id="pre-service-prior-auth-lane" style="margin-top:14px;">
      <div style="display:flex;justify-content:space-between;gap:12px;align-items:flex-end;flex-wrap:wrap;">
        <div>
          <h3 style="margin:0;">Pre-Service Prior Authorization <span class="tooltip" data-tip="Read-only pre-service visibility based on prior authorization cases created from uploads or manual entry. This does not use EHR or payer portal automation.">ⓘ</span></h3>
          <p class="muted small" style="margin:4px 0 0;">
            Manual/upload-driven prior-auth visibility before claims enter the post-submission lifecycle.
          </p>
        </div>
        <div class="muted small">
          Active prior-auth cases: ${formatNumberUI(model.active_count || 0)}
        </div>
      </div>

      <div style="display:flex;gap:12px;flex-wrap:wrap;margin-top:10px;">
        ${cardHtml}
      </div>

      <div class="muted small" style="margin-top:10px;">
        This lane does not create auth-needed tasks automatically, does not check payer portals, and does not change claim lifecycle totals.
      </div>
    </div>
  `;
}

// PRIOR_AUTH_CLAIMS_LIFECYCLE_PRE_SERVICE_LANE_OK

function tjhpPriorAuthLatestSubmission(row = {}){
  const submissions = Array.isArray(row.prior_auth_submissions)
    ? row.prior_auth_submissions
    : [];

  const latestFromHistory = submissions
    .filter(s => s && typeof s === "object" && String(s.status || "") === "submitted")
    .sort((a, b) => new Date(b.submitted_at || 0) - new Date(a.submitted_at || 0))[0];

  if (latestFromHistory) return latestFromHistory;

  if (
    row.prior_auth_submission &&
    typeof row.prior_auth_submission === "object" &&
    String(row.prior_auth_submission.status || "") === "submitted"
  ) {
    return row.prior_auth_submission;
  }

  if (String(row.appeal_submission_status || "") === "submitted" || String(row.status || "") === "Appeal Submitted") {
    return {
      status: "submitted",
      method: row.appeal_submission_method || "",
      submitted_at: row.appeal_submitted_at || "",
      submitted_by: row.appeal_submitted_by || "",
      follow_up_date: row.appeal_follow_up_date || "",
      note: row.appeal_submission_note || "",
      round: row.appeal_submission_round || 1,
      manual_submission: true
    };
  }

  return null;
}

function tjhpPriorAuthNextSubmissionRound(row = {}){
  const submissions = Array.isArray(row.prior_auth_submissions) ? row.prior_auth_submissions : [];
  const maxRound = submissions.reduce((max, s) => Math.max(max, Number(s && s.round || 0) || 0), 0);
  const existingRound = Number(row.appeal_submission_round || 0) || 0;
  return Math.max(1, maxRound || existingRound || 1);
}

function tjhpPriorAuthDefaultFollowUpDate(days = 14){
  return addDaysISO(nowISO(), Number(days || 14)).slice(0, 10);
}

function tjhpPriorAuthSubmissionMethod(value = ""){
  const raw = String(value || "").trim();
  const allowed = ["Portal", "Fax", "Mail", "Phone", "Payer website", "Other"];
  return allowed.find(x => x.toLowerCase() === raw.toLowerCase()) || "Portal";
}

function tjhpPriorAuthSubmissionReadiness(org = {}, row = {}){
  const layout = tjhpPriorAuthAppealWorkspaceLayoutModel(org, row);
  const metrics = layout.command_center_metrics || {};
  const editableKeys = tjhpPriorAuthPayerFacingEditableSectionKeys();
  const renderedSections = tjhpPriorAuthWorkspacePacketSectionsForRender(org, row);
  const sectionsByKey = new Map(
    (Array.isArray(renderedSections) ? renderedSections : [])
      .map(section => [String(section && section.key || "").trim(), section])
  );

  const completedDraftSections = editableKeys.filter(key => {
    const section = sectionsByKey.get(key);
    return String(section && section.body || "").trim().length >= 20;
  });

  const evidenceItems = tjhpPriorAuthWorkspaceEvidenceItemsForRender(org, row);
  const payerFacingEvidence = tjhpPriorAuthPayerFacingEvidenceKeySet();

  const requiredEvidence = (Array.isArray(evidenceItems) ? evidenceItems : [])
    .filter(item =>
      item &&
      item.required === true &&
      payerFacingEvidence.has(String(item.key || "").trim()) &&
      item.excluded !== true
    );

  const attachedRequiredEvidence = requiredEvidence.filter(item =>
    tjhpPriorAuthEvidenceIncludedInPacketContents(org, row, item.key)
  );

  const missingRequiredEvidence = requiredEvidence
    .filter(item => !tjhpPriorAuthEvidenceIncludedInPacketContents(org, row, item.key))
    .map(item => String(item.label || item.title || item.key || "").trim())
    .filter(Boolean);

  const pct = (num, den) => den > 0 ? Math.max(0, Math.min(100, Math.round((num / den) * 100))) : 100;

  const draftPct = pct(completedDraftSections.length, editableKeys.length);
  const sourcePct = pct(attachedRequiredEvidence.length, requiredEvidence.length);

  return {
    source_proof_readiness_pct: sourcePct,
    draft_readiness_pct: draftPct,
    packet_readiness_pct: Math.round((sourcePct * 0.55) + (draftPct * 0.45)),
    required_source_proof_count: requiredEvidence.length,
    source_proof_attached_count: attachedRequiredEvidence.length,
    source_proof_needed_count: missingRequiredEvidence.length,
    missing_source_proof_labels: missingRequiredEvidence,
    preview_section_count: editableKeys.length + requiredEvidence.length,
    completed_preview_section_count: completedDraftSections.length + attachedRequiredEvidence.length,
    metrics
  };
}

function tjhpPriorAuthSubmissionWorkflowHtml(org = {}, row = {}, ctx = {}, opts = {}){
  const readiness = tjhpPriorAuthSubmissionReadiness(org, row);
  const latest = tjhpPriorAuthLatestSubmission(row);
  const isSubmitted = latest && String(latest.status || "") === "submitted";
  const round = tjhpPriorAuthNextSubmissionRound(row);
  const sourceProofIncomplete = Number(readiness.source_proof_needed_count || 0) > 0;
  const missingLabels = readiness.missing_source_proof_labels || [];
  const followUpDefaultDays = 14;
  const blocked = String(opts.blocked || "").trim();

  const statusChip = isSubmitted
    ? `<span class="ws-chip ok">Submitted</span>`
    : sourceProofIncomplete
      ? `<span class="ws-chip warn">Source proof needed</span>`
      : `<span class="ws-chip ok">Ready to submit</span>`;

  const submittedSummary = isSubmitted ? `
    <div class="ws-callout ok" style="margin-top:10px;">
      <strong>Prior auth appeal manually submitted.</strong><br/>
      Submitted via: ${safeStr(latest.method || row.appeal_submission_method || "N/A")}<br/>
      Submitted: ${safeStr(latest.submitted_at || row.appeal_submitted_at || "-")}<br/>
      Follow-up date: ${safeStr(latest.follow_up_date || row.appeal_follow_up_date || "-")}<br/>
      Round: ${safeStr(latest.round || row.appeal_submission_round || round)}
      ${latest.note ? `<br/>Note: ${safeStr(latest.note)}` : ""}
    </div>
  ` : "";

  return `
    <div id="prior-auth-submission-workflow" class="ws-panel" data-prior-auth-submission-card>
      <h3>Prior Auth Submission Workflow</h3>
      <p class="muted small">
        Use this panel to log manual submission of the prior authorization appeal packet. This does not automatically send anything to a payer.
      </p>

      ${blocked === "confirm_missing_source_docs_required" ? `<div class="ws-callout warn" style="margin-bottom:10px;" data-prior-auth-submit-error>Confirm that you want to proceed with missing or system-found source proof before marking this packet submitted.</div>` : `<div class="ws-callout warn" style="display:none;margin-bottom:10px;" data-prior-auth-submit-error></div>`}

      <div class="ws-score">
        <div class="ws-score-num">${formatNumberUI(readiness.source_proof_readiness_pct || 0)}%</div>
        <div class="ws-score-sub">
          Source proof readiness ${formatNumberUI(readiness.source_proof_readiness_pct || 0)}% · Draft readiness ${formatNumberUI(readiness.draft_readiness_pct || 0)}% · ${formatNumberUI(readiness.completed_preview_section_count || 0)} of ${formatNumberUI(readiness.preview_section_count || 0)} packet elements completed
        </div>
      </div>

      <div class="ws-chip-row">
        ${statusChip}
        <span class="ws-chip">Round ${formatNumberUI(round)}</span>
        ${isSubmitted ? `<span class="ws-chip ok">Pending payer response</span>` : `<span class="ws-chip warn">Manual submission log</span>`}
      </div>

      ${sourceProofIncomplete ? `
        <div class="ws-callout warn" style="margin-top:10px;">
          <strong>Source proof needed:</strong> ${safeStr(missingLabels.join(", ") || "Required source proof is still missing.")}
        </div>
      ` : `
        <div class="ws-callout ok" style="margin-top:10px;">
          Required source proof items included or attached for the payer-facing packet.
        </div>
      `}

      ${submittedSummary}

      <form method="POST" action="/prior-auth/appeal-workspace/submit" class="ws-submit-form" data-prior-auth-submit-form data-source-proof-incomplete="${sourceProofIncomplete ? "1" : "0"}" style="margin-top:12px;">
        <input type="hidden" name="auth_case_id" value="${safeStr(ctx.auth_case_id || row.auth_case_id || "")}" />

        <div class="ws-submit-grid">
          <div class="ws-submit-field">
            <label class="small">Method</label>
            <select name="method">
              <option>Portal</option>
              <option>Fax</option>
              <option>Mail</option>
              <option>Phone</option>
              <option>Payer website</option>
              <option>Other</option>
            </select>
          </div>

          <div class="ws-submit-field">
            <label class="small">Follow-up Date</label>
            <input type="date" name="follow_up_date" value="${safeStr(row.appeal_follow_up_date || "")}" />
            <div class="small muted" style="margin-top:4px;">If left blank, the system will set a default follow-up date ${formatNumberUI(followUpDefaultDays)} days after submission.</div>
          </div>

          <div class="ws-submit-field" style="grid-column:1 / -1;">
            <label class="small">Submission note</label>
            <textarea name="submission_note" placeholder="Optional. Example: Submitted through payer site with cover letter, denial letter, LMN, clinical documentation, and source proof attached." style="min-height:84px;">${safeStr(row.appeal_submission_note || "")}</textarea>
          </div>

          <div class="ws-submit-field" style="grid-column:1 / -1;">
            <label class="small">Optional reason for submitting with missing source proof</label>
            <textarea name="override_reason" placeholder="Optional. Add context if staff is proceeding with system-found evidence or missing source proof." style="min-height:74px;">${safeStr(row.appeal_submission_override_reason || "")}</textarea>
          </div>
        </div>

        <label class="small ws-submit-confirm">
          <input type="checkbox" name="confirm_missing_source_docs" value="1" ${row.appeal_submission_confirmed_missing_source_docs ? "checked" : ""}/>
          Proceed with system-found evidence or missing source proof
        </label>

        <button class="btn" type="submit" style="margin-top:8px;">
          Mark Submitted · Round ${formatNumberUI(round)}
        </button>
        <span class="muted small" style="margin-left:8px;">Manual tracking only. No automated payer submission occurs.</span>
      </form>

      <script>
(function(){
  if (window.__tjhpPriorAuthSubmitGuardBound) return;
  window.__tjhpPriorAuthSubmitGuardBound = true;

  function showPriorAuthSubmitError(form, message, focusEl){
    var card = form && form.closest ? form.closest("[data-prior-auth-submission-card]") : null;
    var box = form ? form.querySelector("[data-prior-auth-submit-error]") : null;
    if (box) { box.textContent = message; box.style.display = "block"; }
    try { (card || form).scrollIntoView({ behavior: "smooth", block: "center" }); } catch(e) {}
    if (focusEl && typeof focusEl.focus === "function") setTimeout(function(){ focusEl.focus(); }, 180);
  }

  document.addEventListener("submit", function(e){
    var form = e.target;
    if (!form || !form.matches || !form.matches("[data-prior-auth-submit-form]")) return;

    var incomplete = String(form.getAttribute("data-source-proof-incomplete") || "") === "1";
    if (!incomplete) return;

    var checkbox = form.querySelector("[name='confirm_missing_source_docs']");
    if (!checkbox || !checkbox.checked) {
      e.preventDefault();
      showPriorAuthSubmitError(form, "Confirm that you want to proceed with system-found evidence or missing source proof before marking this packet submitted.", checkbox);
      return false;
    }
  }, true);
})();
</script>
    </div>
  `;
}

function tjhpPriorAuthActionCenterRows(org_id){
  const rows = getPriorAuthCases(org_id);

  const actionableStatuses = new Set([
    "Auth Needed",
    "Draft",
    "Submitted",
    "Pending",
    "Missing Documentation",
    "Peer-to-Peer Needed",
    "Partially Approved",
    "Denied",
    "Appeal Needed",
    "Appeal Submitted",
    "Expiring Soon",
    "Expired",
    "Ready to Bill"
  ]);

  return rows
    .filter(x => actionableStatuses.has(String(x.status || "")))
    .sort((a, b) => {
      const riskRank = { High:3, Medium:2, Low:1 };
      const ar = riskRank[String(a.risk_level || "")] || 0;
      const br = riskRank[String(b.risk_level || "")] || 0;
      if (br !== ar) return br - ar;

      const ad = new Date(a.expiration_date || a.scheduled_service_date || a.submitted_date || a.updated_at || a.created_at || 0).getTime() || 0;
      const bd = new Date(b.expiration_date || b.scheduled_service_date || b.submitted_date || b.updated_at || b.created_at || 0).getTime() || 0;

      return ad - bd;
    });
}



function tjhpPriorAuthStaffStatusOptions(){
  return PRIOR_AUTH_STATUSES.filter(s => s !== "Linked to Claim");
}

function tjhpPriorAuthStaffStatusAllowed(status){
  const raw = String(status || "").trim();
  if (!raw) return false;

  const compact = raw
    .toLowerCase()
    .replace(/[_-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  const allowedAliases = new Set([
    "auth needed",
    "needed",
    "authorization needed",
    "prior auth needed",
    "pa needed",
    "draft",
    "submitted",
    "sent",
    "filed",
    "pending",
    "in review",
    "under review",
    "missing documentation",
    "missing docs",
    "missing documents",
    "needs docs",
    "peer to peer",
    "peer-to-peer",
    "p2p",
    "peer review",
    "approved",
    "authorized",
    "partially approved",
    "partial approval",
    "partial",
    "denied",
    "rejected",
    "appeal needed",
    "appeal required",
    "appeal",
    "appeal draft",
    "appeal in progress",
    "next appeal",
    "next round",
    "another round",
    "prior auth appeal needed",
    "pa appeal needed",
    "appeal submitted",
    "appeal sent",
    "appeal filed",
    "next round submitted",
    "prior auth appeal submitted",
    "pa appeal submitted",
    "expiring soon",
    "expiring",
    "expired",
    "ready to bill",
    "ready",
    "not pursued",
    "do not pursue",
    "not pursuing",
    "service not performed",
    "service not done",
    "do not perform service",
    "do not do service",
    "cancel service",
    "cancelled service",
    "canceled service",
    "patient not proceeding",
    "not proceeding"
  ]);

  const exactAllowed = tjhpPriorAuthStaffStatusOptions()
    .some(s => s.toLowerCase() === raw.toLowerCase());

  if (!exactAllowed && !allowedAliases.has(compact)) return false;

  const normalized = normalizePriorAuthStatus(raw);
  return tjhpPriorAuthStaffStatusOptions().includes(normalized);
}


function tjhpPriorAuthCanMoveToReadyToBill(row = {}){
  const status = normalizePriorAuthStatus(row.status || "");
  return ["Approved", "Partially Approved"].includes(status);
}

function tjhpPriorAuthCandidateText(value){
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function tjhpPriorAuthClaimField(row = {}, keys = []){
  for (const key of keys) {
    const value = row ? row[key] : "";
    if (value != null && String(value).trim()) return String(value).trim();
  }
  return "";
}

function tjhpPriorAuthMoneyField(row = {}, keys = []){
  for (const key of keys) {
    const raw = row ? row[key] : "";
    const n = Number(String(raw || "").replace(/[^0-9.-]/g, ""));
    if (Number.isFinite(n) && n > 0) return n;
  }
  return 0;
}

function tjhpPriorAuthClaimCandidateScore(priorAuth = {}, claim = {}){
  const reasons = [];
  let score = 0;

  const paPayer = tjhpPriorAuthCandidateText(priorAuth.payer);
  const claimPayer = tjhpPriorAuthCandidateText(
    tjhpPriorAuthClaimField(claim, ["payer","payer_name","insurance","health_plan"])
  );

  if (paPayer && claimPayer && (paPayer === claimPayer || paPayer.includes(claimPayer) || claimPayer.includes(paPayer))) {
    score += 4;
    reasons.push("payer match");
  }

  const paPatient = tjhpPriorAuthCandidateText(priorAuth.patient_id || priorAuth.patient_name);
  const claimPatient = tjhpPriorAuthCandidateText(
    tjhpPriorAuthClaimField(claim, ["patient_id","patient_name","patient","member_id","member_name"])
  );

  if (paPatient && claimPatient && (paPatient === claimPatient || paPatient.includes(claimPatient) || claimPatient.includes(paPatient))) {
    score += 5;
    reasons.push("patient match");
  }

  const paCpt = tjhpPriorAuthCandidateText(priorAuth.cpt_hcpcs);
  const claimCpt = tjhpPriorAuthCandidateText(
    tjhpPriorAuthClaimField(claim, ["cpt_hcpcs","cpt","cpt_code","hcpcs","procedure_code"])
  );

  if (paCpt && claimCpt && (paCpt === claimCpt || paCpt.includes(claimCpt) || claimCpt.includes(paCpt))) {
    score += 5;
    reasons.push("CPT/HCPCS match");
  }

  const paIcd = tjhpPriorAuthCandidateText(priorAuth.icd10);
  const claimIcd = tjhpPriorAuthCandidateText(
    tjhpPriorAuthClaimField(claim, ["icd10","icd_10","diagnosis_code","dx_code"])
  );

  if (paIcd && claimIcd && (paIcd === claimIcd || paIcd.includes(claimIcd) || claimIcd.includes(paIcd))) {
    score += 3;
    reasons.push("ICD-10 match");
  }

  const paAuth = tjhpPriorAuthCandidateText(priorAuth.auth_number);
  const claimAuth = tjhpPriorAuthCandidateText(
    tjhpPriorAuthClaimField(claim, ["auth_number","authorization_number","prior_auth_number","pa_number"])
  );

  if (paAuth && claimAuth && paAuth === claimAuth) {
    score += 8;
    reasons.push("auth number match");
  }

  const paService = tjhpPriorAuthCandidateText(priorAuth.requested_service);
  const claimService = tjhpPriorAuthCandidateText(
    tjhpPriorAuthClaimField(claim, ["requested_service","service","procedure","description","service_description"])
  );

  if (paService && claimService && (paService.includes(claimService) || claimService.includes(paService))) {
    score += 2;
    reasons.push("service text match");
  }

  const confidence =
    score >= 12 ? "high" :
    score >= 7 ? "medium" :
    score >= 3 ? "low" :
    "none";

  return { score, confidence, reasons };
}

function tjhpPriorAuthClaimCandidatesForCase(org_id, priorAuth = {}, options = {}){
  const oid = String(org_id || priorAuth.org_id || "").trim();
  const limit = Math.max(1, Math.min(Number(options.limit || 10) || 10, 25));

  if (!oid || !priorAuth) return [];

  const allBilled = readJSON(FILES.billed, []);
  const orgClaims = (Array.isArray(allBilled) ? allBilled : [])
    .filter(x => String(x.org_id || "") === oid);

  return orgClaims
    .map(claim => {
      const match = tjhpPriorAuthClaimCandidateScore(priorAuth, claim);
      const billed_id = tjhpPriorAuthClaimField(claim, ["billed_id","claim_id","claim_number"]);
      const claim_number = tjhpPriorAuthClaimField(claim, ["claim_number","claim_id","billed_id"]);

      return {
        billed_id,
        claim_number,
        payer: tjhpPriorAuthClaimField(claim, ["payer","payer_name","insurance","health_plan"]),
        patient: tjhpPriorAuthClaimField(claim, ["patient_name","patient_id","patient","member_name","member_id"]),
        cpt_hcpcs: tjhpPriorAuthClaimField(claim, ["cpt_hcpcs","cpt","cpt_code","hcpcs","procedure_code"]),
        icd10: tjhpPriorAuthClaimField(claim, ["icd10","icd_10","diagnosis_code","dx_code"]),
        date_of_service: tjhpPriorAuthClaimField(claim, ["date_of_service","dos","service_date"]),
        billed_amount: tjhpPriorAuthMoneyField(claim, ["amount_billed","billed_amount","charge_amount","charges"]),
        score: match.score,
        confidence: match.confidence,
        reasons: match.reasons
      };
    })
    .filter(x => x.score > 0)
    .sort((a, b) => {
      if (b.score !== a.score) return b.score - a.score;
      return String(a.claim_number || "").localeCompare(String(b.claim_number || ""));
    })
    .slice(0, limit);
}


function tjhpPriorAuthFindBilledClaimForLink(org_id, billed_id){
  const oid = String(org_id || "").trim();
  const id = String(billed_id || "").trim();

  if (!oid || !id) return null;

  const allBilled = readJSON(FILES.billed, []);

  return (Array.isArray(allBilled) ? allBilled : []).find(x => {
    if (String(x.org_id || "") !== oid) return false;

    return [
      x.billed_id,
      x.claim_id,
      x.claim_number
    ].some(v => String(v || "").trim() === id);
  }) || null;
}

function tjhpPriorAuthClaimLinkEligibility(org_id, priorAuth = {}, billed_id = ""){
  const oid = String(org_id || priorAuth.org_id || "").trim();
  const id = String(billed_id || "").trim();

  if (!oid) {
    return { ok:false, reason:"missing_org_id", claim:null, score:0, confidence:"none", reasons:[] };
  }

  if (!priorAuth || !String(priorAuth.auth_case_id || "").trim()) {
    return { ok:false, reason:"missing_prior_auth_case", claim:null, score:0, confidence:"none", reasons:[] };
  }

  const status = normalizePriorAuthStatus(priorAuth.status || "");

  if (status !== "Ready to Bill") {
    return { ok:false, reason:"prior_auth_not_ready_to_bill", claim:null, score:0, confidence:"none", reasons:[] };
  }

  const claim = tjhpPriorAuthFindBilledClaimForLink(oid, id);

  if (!claim) {
    return { ok:false, reason:"billed_claim_not_found", claim:null, score:0, confidence:"none", reasons:[] };
  }

  const match = tjhpPriorAuthClaimCandidateScore(priorAuth, claim);

  if (!match || Number(match.score || 0) <= 0) {
    return {
      ok:false,
      reason:"selected_claim_has_no_prior_auth_match_signal",
      claim,
      score:Number(match && match.score || 0),
      confidence:String(match && match.confidence || "none"),
      reasons:Array.isArray(match && match.reasons) ? match.reasons : []
    };
  }

  return {
    ok:true,
    reason:"candidate_match",
    claim,
    billed_id:tjhpPriorAuthClaimField(claim, ["billed_id","claim_id","claim_number"]),
    claim_number:tjhpPriorAuthClaimField(claim, ["claim_number","claim_id","billed_id"]),
    score:Number(match.score || 0),
    confidence:String(match.confidence || "none"),
    reasons:Array.isArray(match.reasons) ? match.reasons : []
  };
}


function tjhpPriorAuthAppealWorkspaceEligible(row = {}){
  const status = normalizePriorAuthStatus(row.status || "");
  return [
    "Denied",
    "Partially Approved",
    "Appeal Needed",
    "Appeal Submitted",
    "Peer-to-Peer Needed",
    "Missing Documentation"
  ].includes(status);
}

function tjhpPriorAuthAppealWorkspaceNextStepLabel(row = {}){
  const status = normalizePriorAuthStatus(row.status || "");

  if (status === "Denied") return "Start appeal / next round";
  if (status === "Partially Approved") return "Review approval limits and appeal gap";
  if (status === "Appeal Needed") return "Build prior auth appeal packet";
  if (status === "Appeal Submitted") return "Follow up on prior auth appeal";
  if (status === "Peer-to-Peer Needed") return "Prepare peer-to-peer review";
  if (status === "Missing Documentation") return "Collect and attach missing documentation";

  return "No appeal workspace action";
}

function tjhpPriorAuthAppealWorkspaceEvidenceChecklist(row = {}){
  const status = normalizePriorAuthStatus(row.status || "");
  const items = [
    "Denial or partial approval letter",
    "Original prior authorization request",
    "Payer medical policy or guideline",
    "Physician order / referral",
    "Clinical notes supporting medical necessity",
    "Relevant imaging, lab, or diagnostic results",
    "CPT / HCPCS and ICD-10 rationale",
    "Prior payer correspondence"
  ];

  if (status === "Peer-to-Peer Needed") {
    items.push("Peer-to-peer notes, if applicable");
  }

  if (
    status === "Missing Documentation" ||
    normalizePriorAuthListValue(row.missing_documentation).length > 0
  ) {
    items.push("Missing documentation requested by payer");
  }

  return Array.from(new Set(items));
}

function tjhpPriorAuthAppealWorkspaceContext(org = {}, row = {}){
  const normalized = normalizePriorAuthCase(row, {
    org_id: String(org.org_id || row.org_id || "").trim()
  });

  return {
    workspace_type: "prior_auth_appeal",
    eligible: tjhpPriorAuthAppealWorkspaceEligible(normalized),
    next_step: tjhpPriorAuthAppealWorkspaceNextStepLabel(normalized),

    auth_case_id: String(normalized.auth_case_id || "").trim(),
    org_id: String(normalized.org_id || org.org_id || "").trim(),

    patient: String(normalized.patient_name || normalized.patient_id || "").trim(),
    payer: String(normalized.payer || "").trim(),
    provider: String(normalized.provider || "").trim(),
    specialty: String(normalized.specialty || "").trim(),

    requested_service: String(normalized.requested_service || "").trim(),
    cpt_hcpcs: String(normalized.cpt_hcpcs || "").trim(),
    icd10: String(normalized.icd10 || "").trim(),
    auth_number: String(normalized.auth_number || "").trim(),

    status: String(normalized.status || "").trim(),
    denial_reason: String(normalized.denial_reason || "").trim(),
    partial_approval_reason: String(normalized.partial_approval_reason || "").trim(),
    missing_documentation: normalizePriorAuthListValue(normalized.missing_documentation),
    estimated_revenue_at_risk: Number(normalized.estimated_revenue_at_risk || 0) || 0,

    evidence_checklist: tjhpPriorAuthAppealWorkspaceEvidenceChecklist(normalized),

    created_at: String(normalized.created_at || "").trim(),
    updated_at: String(normalized.updated_at || "").trim()
  };
}


function tjhpPriorAuthAppealEvidenceItems(ctx = {}){
  const status = normalizePriorAuthStatus(ctx.status || "");
  const hasDenial = !!String(ctx.denial_reason || "").trim();
  const hasPartial = !!String(ctx.partial_approval_reason || "").trim();
  const missingDocs = normalizePriorAuthListValue(ctx.missing_documentation);
  const hasMissingDocs = missingDocs.length > 0 || status === "Missing Documentation";
  const hasP2P = status === "Peer-to-Peer Needed";

  const item = (key, label, description, options = {}) => {
    const required = options.required !== false;
    const found = options.found === true;
    const optional = options.optional === true;

    return {
      key,
      label,
      description,
      required,
      source: String(options.source || "Prior Auth Appeal Packet Standard").trim(),
      status: found ? "found_in_system" : (required ? "source_proof_needed" : "optional"),
      status_label: found ? "Found in System" : (required ? "Required — Source Proof Needed" : "Optional"),
      packet_impact: String(options.packet_impact || (required ? "High Impact" : "Recommended")).trim(),
      optional
    };
  };

  return [
    item(
      "original_prior_auth_request",
      "Original Prior Authorization Request",
      "Initial authorization request, submitted service, requested units, coding, diagnosis, and supporting rationale.",
      { required:true, found: !!(ctx.auth_number || ctx.requested_service || ctx.cpt_hcpcs || ctx.icd10) }
    ),
    item(
      "denial_or_partial_approval_letter",
      "Denial or Partial Approval Letter",
      "Payer decision letter showing the denial, partial approval limit, appeal rights, policy basis, or missing criteria.",
      { required:true, found: hasDenial || hasPartial }
    ),
    item(
      "letter_of_medical_necessity",
      "Letter of Medical Necessity",
      "Provider narrative explaining diagnosis, severity, failed alternatives, clinical rationale, and why the requested service should be approved.",
      { required:true, found:false }
    ),
    item(
      "clinical_documentation",
      "Clinical Documentation",
      "Progress notes, specialist notes, therapy notes, imaging/lab/pathology/genetic results, medication history, and records supporting medical necessity.",
      { required:true, found:false }
    ),
    item(
      "payer_policy_guidelines",
      "Payer Policy / Guidelines",
      "Relevant payer medical policy, clinical guideline, coverage criterion, or plan rule mapped to the patient evidence.",
      { required:true, found:false }
    ),
    item(
      "coding_rationale",
      "CPT / HCPCS and ICD-10 Rationale",
      "Rationale connecting requested service, CPT/HCPCS, ICD-10, requested units, and site of service to the clinical need.",
      { required:true, found: !!(ctx.cpt_hcpcs || ctx.icd10) }
    ),
    item(
      "diagnostic_results",
      "Relevant Imaging, Lab, or Diagnostic Results",
      "Imaging, lab, pathology, test, or diagnostic reports supporting the requested service.",
      { required:true, found:false }
    ),
    item(
      "missing_documentation_response",
      "Missing Documentation Response",
      "A response packet that addresses each document or criterion the payer said was missing.",
      { required:hasMissingDocs, found:hasMissingDocs, optional:!hasMissingDocs }
    ),
    item(
      "peer_to_peer_notes",
      "Peer-to-Peer Notes",
      "Peer-to-peer schedule, reviewer information, call notes, clinical rationale, and outcome if peer-to-peer is required or completed.",
      { required:hasP2P, found:false, optional:!hasP2P }
    ),
    item(
      "authorization_history",
      "Evidence of Authorization / Request History",
      "Prior authorization approval, request history, portal confirmation, reference number, or evidence that authorization was previously requested.",
      { required:false, found: !!ctx.auth_number }
    ),
    item(
      "provider_authorization_form",
      "Provider Authorization Form",
      "Signed patient/provider authorization, appeal representative form, plan appeal form, or provider attestation when required by payer.",
      { required:true, found:false, packet_impact:"Recommended" }
    ),
    item(
      "prior_payer_correspondence",
      "Prior Payer Correspondence",
      "Payer messages, portal notes, fax confirmations, prior case notes, or staff correspondence related to the prior authorization.",
      { required:false, found:false }
    )
  ];
}

function tjhpPriorAuthAppealPacketSections(ctx = {}, org = {}){
  const orgName = String(org.org_name || org.name || ctx.org_name || "Practice").trim();
  const today = new Date().toISOString().slice(0, 10);
  const missingDocs = normalizePriorAuthListValue(ctx.missing_documentation);
  const revenueDisplay = priorAuthRevenueAtRiskDisplay(ctx.estimated_revenue_at_risk);

  const section = (key, title, subtitle, body, options = {}) => ({
    key,
    title,
    subtitle,
    body: String(body || "").trim(),
    complete: options.complete === true,
    editable_later: options.editable_later !== false
  });

  const requestedAction =
    normalizePriorAuthStatus(ctx.status || "") === "Partially Approved"
      ? "Approve the full requested service, requested units, or requested authorization scope that was not included in the partial approval."
      : "Approve the requested prior authorization based on medical necessity and the supporting clinical documentation.";

  return [
    section(
      "header",
      "Header",
      "Prior authorization appeal identifiers.",
      [
        orgName,
        "Date: " + today,
        "Prior Auth Case ID: " + (ctx.auth_case_id || "-"),
        "Payer: " + (ctx.payer || "-"),
        "Auth #: " + (ctx.auth_number || "-")
      ].join("\n"),
      { complete:true }
    ),
    section(
      "case_summary",
      "Prior Authorization Case Summary",
      "Patient, payer, requested service, and coding context.",
      [
        "Patient: " + (ctx.patient || "-"),
        "Payer: " + (ctx.payer || "-"),
        "Requested Service: " + (ctx.requested_service || "-"),
        "CPT / HCPCS: " + (ctx.cpt_hcpcs || "-"),
        "ICD-10: " + (ctx.icd10 || "-"),
        "Status: " + (ctx.status || "-")
      ].join("\n"),
      { complete:!!(ctx.patient || ctx.requested_service || ctx.payer) }
    ),
    section(
      "clinical_summary",
      "Clinical Summary",
      "Medical necessity context for the requested service.",
      [
        "Diagnosis / Condition:",
        "- Summarize the diagnosis, clinical condition, symptoms, severity, and functional impact.",
        "",
        "Clinical History:",
        "- Summarize relevant treatment history, prior conservative care, failed alternatives, medications, therapy, procedures, or other interventions.",
        "",
        "Reason Requested Service Is Clinically Appropriate:",
        "- Explain why " + (ctx.requested_service || "the requested service") + " is medically necessary and appropriate for this patient.",
        "",
        "Supporting Evidence:",
        "- Reference the attached clinical documentation, diagnostic results, payer criteria, and any prior authorization history that supports approval."
      ].join("\n"),
      { complete:false }
    ),
    section(
      "service_revenue_impact",
      "Service / Revenue Impact Summary",
      "Service at risk and known financial exposure, when available.",
      [
        "Requested Service: " + (ctx.requested_service || "-"),
        "Estimated Revenue At Risk: " + revenueDisplay,
        "Note: Prior authorization appeals are pre-service and should focus on medical necessity and coverage criteria. Revenue is shown only when reliably known."
      ].join("\n"),
      { complete:true }
    ),
    section(
      "appeal_narrative",
      "Prior Authorization Appeal Narrative",
      "Core prior-auth appeal argument and medical necessity explanation.",
      tjhpPriorAuthAppealNarrativeDraft(ctx, org),
      { complete:!!(ctx.denial_reason || ctx.partial_approval_reason || ctx.requested_service) }
    ),
    section(
      "requested_action",
      "Requested Action",
      "Specific authorization action requested from payer.",
      requestedAction,
      { complete:true }
    ),
    section(
      "attachments_index",
      "Attachments Index",
      "Index of packet evidence and source proof.",
      "Attach or reference source proof for the denial/partial approval letter, original request, medical necessity letter, clinical documentation, payer policy, coding rationale, missing-documentation response, peer-to-peer notes, and payer correspondence.",
      { complete:false }
    ),
    section(
      "evidence_summary",
      "Evidence Summary",
      "Summary of source proof and criteria support.",
      "Summarize which evidence items are found in system, uploaded, still needed, or optional for this prior-auth appeal packet.",
      { complete:false }
    ),
    section(
      "letter_of_medical_necessity",
      "Letter of Medical Necessity",
      "Editable provider letter explaining medical necessity and payer-criteria support.",
      [
        "Letter of Medical Necessity",
        "",
        "Patient: " + (ctx.patient || "[Patient Name]"),
        "Requested Service: " + (ctx.requested_service || "[Requested Service]"),
        "Prior Authorization / Reference Number: " + (ctx.auth_number || ctx.auth_case_id || "[Authorization Number]"),
        "Payer: " + (ctx.payer || "Payer"),
        "CPT / HCPCS: " + (ctx.cpt_hcpcs || "-"),
        "ICD-10: " + (ctx.icd10 || "-"),
        "",
        "To Whom It May Concern,",
        "",
        "I am writing to document the medical necessity of the requested service: " + (ctx.requested_service || "[Requested Service]") + ".",
        "",
        "Medical Necessity Rationale:",
        "- Describe the patient's diagnosis, symptoms, severity, functional limitations, and why the requested service is clinically appropriate.",
        "",
        "Prior Treatment / Failed Alternatives:",
        "- Summarize conservative measures, prior treatments, medications, therapy, testing, or alternative services that were tried, insufficient, contraindicated, or not appropriate.",
        "",
        "Payer Criteria / Coverage Support:",
        "- Map the patient's clinical facts to the payer's medical policy or coverage criteria when available.",
        "",
        "Requested Authorization Action:",
        "- Please approve the requested prior authorization or approve the remaining requested scope if the prior decision was a partial approval.",
        "",
        "Supporting Documentation:",
        "- Clinical records, diagnostic results, payer policy references, authorization history, and other source proof are attached or referenced in this packet.",
        "",
        "Sincerely,"
      ].join("\n"),
      { complete:false }
    ),
    section(
      "clinical_documentation",
      "Clinical Documentation",
      "Clinical records that support medical necessity.",
      "Attach progress notes, specialist notes, therapy notes, diagnostic reports, labs, imaging, pathology, genetic testing support, prior treatment history, and failed alternatives.",
      { complete:false }
    ),
    section(
      "payer_policy_guidelines",
      "Payer Policy / Guidelines",
      "Coverage criteria and medical policy match.",
      "Map each payer policy criterion to the supporting chart evidence. Avoid generic chart dumps; show why the patient meets criteria.",
      { complete:false }
    ),
    section(
      "evidence_of_authorization",
      "Evidence of Authorization",
      "Original authorization request and history.",
      "Include original request, portal confirmation, fax confirmation, auth/reference number, request history, and any prior approval or denial correspondence.",
      { complete:!!ctx.auth_number }
    ),
    section(
      "provider_authorization_form",
      "Provider Authorization Form",
      "Plan-specific or representative authorization form.",
      "Include patient/provider representative form, provider attestation, payer appeal form, or signed authorization if required by payer.",
      { complete:false }
    ),
    section(
      "peer_to_peer_notes",
      "Peer-to-Peer Notes",
      "Peer-to-peer scheduling, rationale, and outcome.",
      "Document reviewer name, scheduled time, physician notes, outcome, and appeal handoff when peer-to-peer is required.",
      { complete:normalizePriorAuthStatus(ctx.status || "") !== "Peer-to-Peer Needed" }
    ),
    section(
      "missing_documentation_response",
      "Missing Documentation Response",
      "Response to payer-requested missing items.",
      missingDocs.length
        ? "Address requested missing items: " + missingDocs.join(", ")
        : "No missing documentation listed. If payer requests missing documentation, list each item and attach source proof.",
      { complete:missingDocs.length === 0 }
    )
  ];
}

function tjhpPriorAuthAppealCommandCenterMetrics(ctx = {}){
  const evidenceItems = tjhpPriorAuthAppealEvidenceItems(ctx);
  const sections = tjhpPriorAuthAppealPacketSections(ctx, {});
  const required = evidenceItems.filter(x => x.required);
  const found = required.filter(x => String(x.status || "") === "found_in_system");
  const completedSections = sections.filter(x => x.complete);

  const pct = (num, den) => den > 0 ? Math.max(0, Math.min(100, Math.round((num / den) * 100))) : 0;

  const sourceProofReadiness = pct(found.length, required.length);
  const draftReadiness = pct(completedSections.length, sections.length);
  const clinicalSignals = [
    ctx.denial_reason,
    ctx.partial_approval_reason,
    ctx.requested_service,
    ctx.cpt_hcpcs,
    ctx.icd10,
    normalizePriorAuthListValue(ctx.missing_documentation).join(" ")
  ].filter(x => String(x || "").trim()).length;
  const clinicalStrength = Math.max(0, Math.min(100, 30 + clinicalSignals * 10));

  return {
    packet_readiness_pct: Math.round((sourceProofReadiness * 0.45) + (draftReadiness * 0.35) + (clinicalStrength * 0.20)),
    source_proof_readiness_pct: sourceProofReadiness,
    draft_readiness_pct: draftReadiness,
    clinical_necessity_strength_pct: clinicalStrength,
    required_source_proof_count: required.length,
    source_proof_attached_count: found.length,
    source_proof_needed_count: Math.max(0, required.length - found.length),
    preview_section_count: sections.length,
    completed_preview_section_count: completedSections.length,
    estimated_revenue_at_risk: Number(ctx.estimated_revenue_at_risk || 0) || 0,
    estimated_revenue_at_risk_display: priorAuthRevenueAtRiskDisplay(ctx.estimated_revenue_at_risk),
    status_label: String(ctx.status || "-").trim() || "-",
    workspace_badge: "Prior Auth"
  };
}

function tjhpPriorAuthAppealNarrativeDraft(ctx = {}, org = {}){
  const orgName = String(org.org_name || org.name || "our practice").trim();
  const service = String(ctx.requested_service || "the requested service").trim();
  const cpt = String(ctx.cpt_hcpcs || "").trim();
  const icd = String(ctx.icd10 || "").trim();
  const auth = String(ctx.auth_number || "").trim();
  const denial = String(ctx.denial_reason || "").trim();
  const partial = String(ctx.partial_approval_reason || "").trim();

  const reasonLine = denial
    ? "The denial reason provided was: " + denial + "."
    : (partial ? "The authorization was partially approved, but the approval does not fully cover the requested service: " + partial + "." : "The request requires additional review based on the available clinical and authorization documentation.");

  const codingLine = [
    cpt ? "CPT/HCPCS " + cpt : "",
    icd ? "ICD-10 " + icd : ""
  ].filter(Boolean).join(" and ");

  return [
    "To the Prior Authorization Appeals Department,",
    "",
    orgName + " requests reconsideration of the prior authorization decision for " + service + ".",
    auth ? "Authorization / reference number: " + auth + "." : "",
    codingLine ? "The requested service is supported by " + codingLine + "." : "",
    reasonLine,
    "",
    "The attached packet is intended to demonstrate medical necessity, coverage-criteria support, the clinical rationale for the requested service, and any documentation requested by the payer.",
    "",
    "Requested action: approve the requested prior authorization, or approve the remaining requested scope if the prior decision was a partial approval.",
    "",
    "This request is not a billed-claim payment appeal. It is a pre-service authorization appeal focused on medical necessity and coverage criteria."
  ].filter(x => x !== "").join("\n");
}

function tjhpPriorAuthAppealWorkspaceLayoutModel(org = {}, row = {}){
  const context = tjhpPriorAuthAppealWorkspaceContext(org, row);
  const evidenceItems = tjhpPriorAuthAppealEvidenceItems(context);
  const packetSections = tjhpPriorAuthAppealPacketSections(context, org);
  const commandCenterMetrics = tjhpPriorAuthAppealCommandCenterMetrics(context);

  return {
    workspace_type: "prior_auth_appeal_command_center",
    title: "Prior Auth Appeal Packet Command Center",
    subtitle: "Prepare a prior authorization appeal or next-round packet using medical necessity evidence, payer criteria, and source proof.",
    context,
    command_center_metrics: commandCenterMetrics,
    evidence_items: evidenceItems,
    packet_sections: packetSections,
    narrative_draft: tjhpPriorAuthAppealNarrativeDraft(context, org),
    workflow: {
      round_label: "Round 1",
      status_label: String(context.status || "-").trim() || "-",
      next_step: String(context.next_step || "").trim(),
      submission_methods: ["Portal", "Fax", "Phone", "Mail", "Other"],
      default_submission_method: "Portal",
      follow_up_days: 14
    },
    guardrails: {
      read_only: true,
      no_payer_submission: true,
      no_claim_mutation: true,
      no_payment_mutation: true,
      no_contract_mutation: true,
      no_document_ingest_mutation: true,
      no_agent_workspace_creation: true
    }
  };
}


function tjhpPriorAuthWorkspaceEditableSectionKeys(org = {}, row = {}){
  const ctx = tjhpPriorAuthAppealWorkspaceContext(org, row);
  const sections = tjhpPriorAuthAppealPacketSections(ctx, org);

  return (Array.isArray(sections) ? sections : [])
    .map(section => String(section && section.key || "").trim())
    .filter(Boolean);
}

function tjhpPriorAuthWorkspacePacketSectionsForRender(org = {}, row = {}){
  const layout = tjhpPriorAuthAppealWorkspaceLayoutModel(org, row);
  const rawSavedSections =
    row &&
    row.workspace_packet_sections &&
    typeof row.workspace_packet_sections === "object" &&
    !Array.isArray(row.workspace_packet_sections)
      ? row.workspace_packet_sections
      : {};

  const sections = Array.isArray(layout.packet_sections) ? layout.packet_sections : [];

  return sections.map(section => {
    const key = String(section && section.key || "").trim();
    const hasSaved = !!key && Object.prototype.hasOwnProperty.call(rawSavedSections, key);
    const generatedBody = String(section && section.body != null ? section.body : "").trimEnd();
    const savedBody = hasSaved ? String(rawSavedSections[key] || "") : "";

    return {
      ...section,
      key,
      generated_body: generatedBody,
      body: hasSaved ? savedBody : generatedBody,
      saved: hasSaved
    };
  });
}

function tjhpPriorAuthWorkspaceEvidenceBySection(layout = {}){
  const evidenceItems = Array.isArray(layout && layout.evidence_items)
    ? layout.evidence_items
    : [];

  const evidenceByKey = evidenceItems.reduce((acc, item) => {
    const key = String(item && item.key || "").trim();
    if (key) acc[key] = item;
    return acc;
  }, {});

  const sectionToEvidenceKey = {
    original_prior_auth_request: "original_prior_auth_request",
    denial_or_partial_approval_letter: "denial_or_partial_approval_letter",
    letter_of_medical_necessity: "letter_of_medical_necessity",
    clinical_documentation: "clinical_documentation",
    payer_policy_guidelines: "payer_policy_guidelines",
    coding_rationale: "coding_rationale",
    diagnostic_results: "diagnostic_results",
    missing_documentation_response: "missing_documentation_response",
    peer_to_peer_notes: "peer_to_peer_notes",
    evidence_of_authorization: "authorization_history",
    provider_authorization_form: "provider_authorization_form",
    prior_payer_correspondence: "prior_payer_correspondence",

    case_summary: "original_prior_auth_request",
    clinical_summary: "clinical_documentation",
    service_revenue_impact: "original_prior_auth_request",
    appeal_narrative: "denial_or_partial_approval_letter",
    requested_action: "denial_or_partial_approval_letter",
    attachments_index: "prior_payer_correspondence",
    evidence_summary: "prior_payer_correspondence"
  };

  return Object.entries(sectionToEvidenceKey).reduce((acc, pair) => {
    const sectionKey = pair[0];
    const evidenceKey = pair[1];
    if (evidenceByKey[evidenceKey]) acc[sectionKey] = evidenceByKey[evidenceKey];
    return acc;
  }, {});
}



function tjhpPriorAuthGeneratedPacketAttachmentText(value = ""){
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function tjhpPriorAuthIsGeneratedPacketAttachment(value = {}){
  if (!value || typeof value !== "object") return false;

  const fileName = tjhpPriorAuthGeneratedPacketAttachmentText(
    value.file_name ||
    value.originalName ||
    value.filename ||
    value.name ||
    ""
  );

  const urlPath = tjhpPriorAuthGeneratedPacketAttachmentText([
    value.url,
    value.path,
    value.absPath,
    value.storedPath,
    value.stored_path,
    value.file_url
  ].filter(Boolean).join(" "));

  const combined = [fileName, urlPath].filter(Boolean).join(" ");

  if (!combined) return false;

  return (
    /\bprior auth appeal packet\b/.test(combined) ||
    /\bprior authorization appeal packet\b/.test(combined) ||
    /\bprior auth packet preview\b/.test(combined) ||
    /\bprior auth appeal packet pdf\b/.test(combined) ||
    /\bprior authorization appeal packet pdf\b/.test(combined)
  );
}

function tjhpPriorAuthEvidenceUploadText(value = ""){
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function tjhpPriorAuthEvidenceKeyForUploadedSource(priorAuth = {}, upload = {}, parsedFile = {}){
  if (tjhpPriorAuthIsGeneratedPacketAttachment(upload) || tjhpPriorAuthIsGeneratedPacketAttachment(parsedFile)) return "";

  const status = normalizePriorAuthStatus(priorAuth.status || "");
  const text = tjhpPriorAuthEvidenceUploadText([
    upload.file_name,upload.filename,upload.originalName,upload.notes,upload.status,upload.file_type,upload.mimeType,parsedFile.kind,priorAuth.status,priorAuth.denial_reason,priorAuth.partial_approval_reason,priorAuth.requested_service,priorAuth.notes
  ].filter(Boolean).join(" "));
  if (status === "Missing Documentation" || /missing documentation|additional information|additional documentation|documentation request/.test(text)) return "missing_documentation_response";
  if (status === "Peer-to-Peer Needed" || /peer to peer|p2p|peer review/.test(text)) return "peer_to_peer_notes";
  if (status === "Denied" || status === "Partially Approved" || status === "Appeal Needed" || status === "Appeal Submitted" || String(priorAuth.denial_reason || "").trim() || String(priorAuth.partial_approval_reason || "").trim() || /denied|denial|partial approval|partially approved|adverse determination|determination letter|decision letter|denied service|not meet|medical necessity/.test(text)) return "denial_or_partial_approval_letter";
  if (/authorization request|prior authorization request|prior auth request|request confirmation|portal confirmation|authorization history|auth history|auth request/.test(text)) return "original_prior_auth_request";
  return "";
}

function tjhpPriorAuthUploadedSourceAttachmentForEvidence(upload = {}, uploadId = "", userId = ""){
  const fileName = String(upload.file_name || upload.originalName || upload.filename || "").trim();
  const fileType = String(upload.file_type || upload.mimeType || upload.mime_type || "").trim();
  const fileUrl = String(upload.file_url || upload.url || "").trim() || priorAuthUploadFileUrl(upload);
  const storedPath = String(upload.stored_path || upload.absPath || "").trim() || priorAuthUploadStoredPath(upload);
  const id = String(uploadId || upload.upload_id || "").trim();
  return {
    attachment_id: id ? "paev_src_" + id : "paev_" + uuid(),
    source: "prior_auth_source_upload",
    source_upload_id: id,
    file_name: fileName,
    file_type: fileType,
    url: fileUrl,
    path: storedPath,
    absPath: storedPath,
    storedPath,
    uploaded_at: String(upload.created_at || nowISO()).trim(),
    uploaded_by: String(userId || upload.created_by || "").trim(),
    text_excerpt: String(upload.text_excerpt || "").trim(),
    extracted_text: String(upload.extracted_text || "").trim(),
    appeal_submission_address: String(upload.appeal_submission_address || "").trim(),
    appeal_instructions: String(upload.appeal_instructions || "").trim()
  };
}

function tjhpPriorAuthEvidenceAttachmentEquivalent(a = {}, b = {}){
  const aSource = String(a.source_upload_id || "").trim();
  const bSource = String(b.source_upload_id || "").trim();
  if (aSource && bSource && aSource === bSource) return true;
  const aUrl = String(a.url || "").trim();
  const bUrl = String(b.url || "").trim();
  if (aUrl && bUrl && aUrl === bUrl) return true;
  const aPath = String(a.absPath || a.storedPath || a.path || "").trim();
  const bPath = String(b.absPath || b.storedPath || b.path || "").trim();
  if (aPath && bPath && aPath === bPath) return true;
  const aName = String(a.file_name || "").trim();
  const bName = String(b.file_name || "").trim();
  return !!(aName && bName && aName === bName && aSource === bSource);
}



function tjhpPriorAuthParseEvidencePageList(value = ""){
  const out = new Set();

  const rawParts = Array.isArray(value)
    ? value
    : String(value || "").split(/[,;\s]+/);

  rawParts.forEach(part => {
    const raw = String(part || "").trim();
    if (!raw) return;

    const range = raw.match(/^(\d+)\s*-\s*(\d+)$/);
    if (range) {
      const start = Math.max(1, Number(range[1] || 0) || 0);
      const end = Math.max(1, Number(range[2] || 0) || 0);
      const lo = Math.min(start, end);
      const hi = Math.max(start, end);
      for (let n = lo; n <= hi && n <= 10000; n += 1) out.add(n);
      return;
    }

    const n = Math.max(1, Number(raw.replace(/[^0-9]/g, "") || 0) || 0);
    if (n > 0) out.add(n);
  });

  return out;
}

function tjhpPriorAuthNormalizeEvidencePageList(value = ""){
  return Array.from(tjhpPriorAuthParseEvidencePageList(value))
    .sort((a, b) => a - b)
    .join(", ");
}

function tjhpPriorAuthEvidenceAttachmentMatchesToken(att = {}, attachmentId = "", sourceUploadId = ""){
  const targetAttachmentId = String(attachmentId || "").trim();
  const targetSourceUploadId = String(sourceUploadId || "").trim();

  if (targetAttachmentId && String(att.attachment_id || "").trim() === targetAttachmentId) return true;
  if (targetSourceUploadId && String(att.source_upload_id || "").trim() === targetSourceUploadId) return true;

  return false;
}

function tjhpPriorAuthAttachUploadedSourceEvidence(row = {}, evidenceKey = "", attachment = {}){
  const key = String(evidenceKey || "").trim();
  if (!key || !attachment || typeof attachment !== "object") return row;

  const currentEvidence =
    row &&
    row.workspace_evidence &&
    typeof row.workspace_evidence === "object" &&
    !Array.isArray(row.workspace_evidence)
      ? row.workspace_evidence
      : {};

  const currentState = tjhpPriorAuthWorkspaceEvidenceState(row, key);
  const attachments = Array.isArray(currentState.attachments) ? [...currentState.attachments] : [];

  if (!attachments.some(existing => tjhpPriorAuthEvidenceAttachmentEquivalent(existing, attachment))) {
    attachments.push(attachment);
  }

  return {
    ...row,
    workspace_evidence: {
      ...currentEvidence,
      [key]: {
        excluded: false,
        attachments
      }
    }
  };
}

function tjhpPriorAuthAttachSourceUploadEvidenceForCaseId(org_id, auth_case_id, upload = {}, uploadId = "", userId = "", parsedFile = {}){
  const oid = String(org_id || "").trim();
  const caseId = String(auth_case_id || "").trim();
  if (!oid || !caseId) return null;

  const currentCase = getPriorAuthCaseById(oid, caseId);
  if (!currentCase) return null;

  const caseForSourceEvidence = {
    ...currentCase,
    org_id: oid,
    source_upload_batch_id: String(currentCase.source_upload_batch_id || uploadId || "").trim()
  };

  const evidenceKey = tjhpPriorAuthEvidenceKeyForUploadedSource(caseForSourceEvidence, upload, parsedFile);
  if (!evidenceKey) return null;

  const attachment = tjhpPriorAuthUploadedSourceAttachmentForEvidence(upload, uploadId, userId);
  const hasSource = String(
    attachment.url ||
    attachment.path ||
    attachment.absPath ||
    attachment.storedPath ||
    ""
  ).trim();

  if (!hasSource) return null;

  const updatedCase = tjhpPriorAuthAttachUploadedSourceEvidence(caseForSourceEvidence, evidenceKey, attachment);
  return upsertPriorAuthCase(oid, updatedCase, userId || "");
}

function tjhpPriorAuthSourceUploadAttachmentForEvidence(row = {}, evidenceKey = ""){
  const key = String(evidenceKey || "").trim();
  const sourceUploadId = String(row.source_upload_batch_id || "").trim();
  if (!key || !sourceUploadId) return null;
  const uploads = getPriorAuthUploads(row.org_id || "");
  const upload = uploads.find(x => String(x.upload_id || "") === sourceUploadId) || null;
  if (!upload) return null;
  const inferredKey = tjhpPriorAuthEvidenceKeyForUploadedSource(row, upload, {});
  if (String(inferredKey || "") !== key) return null;
  const attachment = tjhpPriorAuthUploadedSourceAttachmentForEvidence(upload, sourceUploadId, upload.created_by || row.created_by || "");
  if (!String(attachment.url || attachment.path || attachment.absPath || attachment.storedPath || "").trim()) return null;
  return attachment;
}

function tjhpPriorAuthWorkspaceEvidenceState(row = {}, evidenceKey = ""){
  const key = String(evidenceKey || "").trim();
  const rawEvidence =
    row &&
    row.workspace_evidence &&
    typeof row.workspace_evidence === "object" &&
    !Array.isArray(row.workspace_evidence)
      ? row.workspace_evidence
      : {};
  const itemState =
    key &&
    rawEvidence[key] &&
    typeof rawEvidence[key] === "object" &&
    !Array.isArray(rawEvidence[key])
      ? rawEvidence[key]
      : {};
  const attachments = Array.isArray(itemState.attachments)
    ? itemState.attachments
      .filter(x => x && typeof x === "object")
      .filter(x => !tjhpPriorAuthIsGeneratedPacketAttachment(x))
      .map(x => ({ ...x }))
    : [];

  const sourceUploadAttachment = tjhpPriorAuthSourceUploadAttachmentForEvidence(row, key);
  if (
    sourceUploadAttachment &&
    !attachments.some(existing => tjhpPriorAuthEvidenceAttachmentEquivalent(existing, sourceUploadAttachment))
  ) {
    attachments.unshift(sourceUploadAttachment);
  }

  return {
    excluded: itemState.excluded === true,
    attachments
  };
}

function tjhpPriorAuthWorkspaceEvidenceItemsForRender(org = {}, row = {}){
  const layout = tjhpPriorAuthAppealWorkspaceLayoutModel(org, row);
  const evidenceItems = Array.isArray(layout.evidence_items) ? layout.evidence_items : [];
  const priorAuthEditableTextOnlyEvidenceKeys = new Set([
    "header",
    "case_summary",
    "prior_authorization_case_summary",
    "clinical_summary",
    "service_revenue_impact",
    "letter_of_medical_necessity",
    "appeal_narrative",
    "requested_action",
    "attachments_index",
    "evidence_summary"
  ]);
  return evidenceItems
  .filter(item => !priorAuthEditableTextOnlyEvidenceKeys.has(String(item && item.key || "").trim()))
  .map(item => {
    const key = String(item && item.key || "").trim();
    const state = tjhpPriorAuthWorkspaceEvidenceState(row, key);
    const itemStatus = String(item && (item.status_label || item.status) || "").trim();
    let status_label = "Optional";
    let status_class = "muted";
    let proof_label = "Optional";
    if (state.excluded) {
      status_label = "Excluded from packet";
      status_class = "warn";
      proof_label = "Excluded";
    } else if (state.attachments.length > 0) {
      status_label = "Source Proof Attached";
      status_class = "ok";
      proof_label = "Uploaded";
    } else if (itemStatus === "Found in System") {
      status_label = "Found in System";
      status_class = "ok";
      proof_label = "System evidence";
    } else if (item && item.required === true) {
      status_label = "Required — Source Proof Needed";
      status_class = "warn";
      proof_label = "Source Proof Needed";
    }
    return {
      ...item,
      key,
      excluded: state.excluded,
      attachments: state.attachments,
      status_label,
      status_class,
      proof_label
    };
  });
}

function tjhpPriorAuthWorkspaceEditablePacketSectionsOnly(org = {}, row = {}){
  const allowed = new Set([
    "header",
    "case_summary",
    "prior_authorization_case_summary",
    "clinical_summary",
    "service_revenue_impact",
    "letter_of_medical_necessity",
    "appeal_narrative",
    "requested_action",
    "attachments_index",
    "evidence_summary"
  ]);
  return tjhpPriorAuthWorkspacePacketSectionsForRender(org, row)
    .filter(section => allowed.has(String(section && section.key || "").trim()));
}

function tjhpPriorAuthAiSectionLabel(sectionKey){
  const labels = {
    appeal_narrative: "Prior Authorization Appeal Cover Letter",
    letter_of_medical_necessity: "Letter of Medical Necessity",
    clinical_summary: "Clinical Summary"
  };
  return labels[String(sectionKey || "").trim()] || "Prior Authorization Packet Section";
}

function tjhpPriorAuthAiEditableSectionKeys(){
  return tjhpPriorAuthPayerFacingEditableSectionKeys();
}

function tjhpPriorAuthAiTargetFromPrompt(prompt, selectedTarget){
  const editableKeys = new Set(tjhpPriorAuthAiEditableSectionKeys());
  const selected = String(selectedTarget || "").trim();
  if (selected && selected !== "auto" && editableKeys.has(selected)) return selected;

  const text = String(prompt || "").toLowerCase();
  if (/\b(lmn|medical necessity)\b|letter of medical necessity|necessity rationale/.test(text)) return "letter_of_medical_necessity";
  if (/clinical|criteria|payer criteria|facts|policy|missing proof|source proof|evidence|peer-to-peer|peer to peer/.test(text)) return "clinical_summary";
  if (/cover|appeal letter|intro|closing/.test(text)) return "appeal_narrative";
  return "appeal_narrative";
}

// PRIOR_AUTH_AI_DRAFT_PLACEMENT_REGEN_OK
function tjhpPriorAuthFirstValue(...values){
  if (typeof workspaceFirstValue === "function") {
    return workspaceFirstValue(...values);
  }

  for (const value of values) {
    const clean = String(value || "").trim();
    if (clean) return clean;
  }

  return "";
}

function tjhpPriorAuthPracticeIdentityContext(org = {}, row = {}){
  const orgId = String(org.org_id || row.org_id || row.organization_id || "").trim();
  let orgCtx = {};

  try {
    orgCtx = orgId && typeof workspaceOrgIdentityContext === "function"
      ? workspaceOrgIdentityContext(orgId)
      : {};
  } catch (err) {
    orgCtx = {};
  }

  const settings = orgCtx.settings || {};
  const identity = orgCtx.identity || {};
  const orgRecord = orgCtx.orgRecord || org || {};

  const manualAddress = [
    org.practice_address,
    org.address,
    org.address_line1,
    org.address_line2,
    org.city && org.state ? `${org.city}, ${org.state} ${org.zip || ""}` : ""
  ].filter(x => String(x || "").trim()).join("\n");

  const orgName = tjhpPriorAuthFirstValue(
    orgCtx.orgName,
    identity.legal_name,
    identity.dba_name,
    settings.practice_name,
    settings.legal_name,
    org.legal_name,
    org.dba_name,
    org.org_name,
    org.name,
    "Practice"
  );

  const addressBlock = tjhpPriorAuthFirstValue(
    orgCtx.addressBlock,
    orgCtx.primaryAddress,
    orgCtx.mailingAddress,
    manualAddress,
    "[Practice Address]"
  );

  const phone = tjhpPriorAuthFirstValue(
    orgCtx.phone,
    identity.phone,
    identity.practice_phone,
    settings.phone,
    settings.practice_phone,
    settings.billing_phone,
    org.phone,
    org.main_phone,
    org.practice_phone,
    "[Phone Number]"
  );

  const fax = tjhpPriorAuthFirstValue(
    orgCtx.fax,
    identity.fax,
    settings.fax,
    org.fax,
    org.practice_fax
  );

  const email = tjhpPriorAuthFirstValue(
    orgCtx.email,
    identity.email,
    identity.practice_email,
    settings.email,
    settings.practice_email,
    settings.billing_email,
    org.email,
    org.org_email,
    org.practice_email,
    "[Email]"
  );

  const npi = tjhpPriorAuthFirstValue(
    orgCtx.npi,
    identity.npi,
    settings.npi,
    settings.provider_npi,
    org.npi,
    org.org_npi,
    org.provider_npi,
    "[NPI Number]"
  );

  const taxId = tjhpPriorAuthFirstValue(
    orgCtx.taxId,
    identity.tax_id,
    settings.tax_id,
    org.tax_id,
    org.tin,
    org.tax_identifier,
    "[Tax ID]"
  );

  const signatureName = tjhpPriorAuthFirstValue(
    settings.practice_signature && settings.practice_signature.typed_name,
    identity.provider_name,
    settings.provider_name,
    settings.physician_name,
    org.provider_name,
    orgName
  );

  return {
    orgId,
    orgName,
    addressBlock,
    phone,
    fax,
    email,
    npi,
    taxId,
    signatureName
  };
}

function tjhpPriorAuthPracticeLetterheadBlock(org = {}, row = {}){
  const identity = tjhpPriorAuthPracticeIdentityContext(org, row);

  return [
    identity.orgName,
    identity.addressBlock,
    `Phone: ${identity.phone}`,
    identity.fax ? `Fax: ${identity.fax}` : "",
    `Email: ${identity.email}`,
    `NPI: ${identity.npi}`,
    `Tax ID: ${identity.taxId}`
  ].filter(x => String(x || "").trim()).join("\n");
}

