function tjhpPriorAuthPayerFacingSectionLabel(sectionKey = ""){
  const key = String(sectionKey || "").trim();

  const labels = {
    appeal_narrative: "Prior Authorization Appeal Cover Letter",
    letter_of_medical_necessity: "Letter of Medical Necessity",
    clinical_summary: "Clinical Summary"
  };

  return labels[key] || tjhpPriorAuthAiSectionLabel(key);
}

function tjhpPriorAuthEvidenceLabelForPacketContents(org = {}, row = {}, evidenceKey = ""){
  const key = String(evidenceKey || "").trim();
  if (!key) return "";

  try {
    const items = tjhpPriorAuthWorkspaceEvidenceItemsForRender(org, row);
    const item = (Array.isArray(items) ? items : [])
      .find(x => String(x && x.key || "").trim() === key);

    if (item && item.excluded === true) return "";

    const label = String(item && (item.label || item.title) || "").trim();
    if (label) return label;
  } catch (err) {}

  const fallback = {
    original_prior_auth_request: "Original Prior Authorization Request",
    denial_or_partial_approval_letter: "Denial or Partial Approval Letter",
    clinical_documentation: "Clinical Documentation",
    diagnostic_results: "Diagnostic / Lab / Imaging / Genetic Results",
    payer_policy_guidelines: "Payer Policy / Medical Criteria Support",
    coding_rationale: "Coding Rationale",
    authorization_history: "Authorization History",
    evidence_of_authorization: "Evidence of Authorization",
    provider_authorization_form: "Provider Authorization Form",
    prior_payer_correspondence: "Prior Payer Correspondence",
    peer_to_peer_notes: "Peer-to-Peer Notes",
    missing_documentation_response: "Missing Documentation Response"
  };

  return fallback[key] || key.replace(/_/g, " ");
}

function tjhpPriorAuthPacketContentLabel(org = {}, row = {}, kind = "", key = ""){
  const cleanKind = String(kind || "").trim();
  const cleanKey = String(key || "").trim();

  if (cleanKind === "section") return tjhpPriorAuthPayerFacingSectionLabel(cleanKey);
  if (cleanKind === "evidence") return tjhpPriorAuthEvidenceLabelForPacketContents(org, row, cleanKey);

  return "";
}

function tjhpPriorAuthNormalizeAppealAddressLine(line = ""){
  return String(line || "")
    .replace(/\u00a0/g, " ")
    .replace(/\s+/g, " ")
    .replace(/^[•\-\*\u2022]+\s*/, "")
    .trim();
}

function tjhpPriorAuthAppealAddressLineLooksUseful(line = ""){
  const clean = tjhpPriorAuthNormalizeAppealAddressLine(line);
  if (!clean) return false;

  return (
    /appeals?|appeal department|prior authorization|blue\s*cross|bluecross|blue shield|aetna|cigna|united|uhc|humana|anthem|healthselect|health select|claims department|benefits department/i.test(clean) ||
    /\bP\.?\s*O\.?\s*Box\b/i.test(clean) ||
    /\bPO Box\b/i.test(clean) ||
    /\b\d{2,6}\s+[A-Za-z0-9 .'-]+(?:street|st\.|road|rd\.|drive|dr\.|avenue|ave\.|boulevard|blvd\.|lane|ln\.|way|parkway|pkwy|suite|ste\.?)\b/i.test(clean) ||
    /\b[A-Z][a-zA-Z .'-]+,\s*(?:AL|AK|AZ|AR|CA|CO|CT|DE|FL|GA|HI|IA|ID|IL|IN|KS|KY|LA|MA|MD|ME|MI|MN|MO|MS|MT|NC|ND|NE|NH|NJ|NM|NV|NY|OH|OK|OR|PA|RI|SC|SD|TN|TX|UT|VA|VT|WA|WI|WV|WY|Texas)\s+\d{5}(?:-\d{4})?\b/i.test(clean) ||
    /\bFax\b|\bfax\s*[:#]?\s*\(?\d{3}\)?/i.test(clean)
  );
}

function tjhpPriorAuthAppealAddressStopLine(line = ""){
  const clean = tjhpPriorAuthNormalizeAppealAddressLine(line);
  if (!clean) return true;

  return /^(include the following information|include all|for faster|you may also|if you need|what if|what should|please note|this notice|protected health information|if you are not|para confirmar|si usted|call us|contact us|web site|website|visit|member services|customer service|be certain)/i.test(clean);
}

function tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(value = ""){
  const text = String(value || "").trim();

  if (!text) return false;
  if (/^\[?\s*payer address\s*\]?$/i.test(text)) return false;
  if (/^\[.*\]$/.test(text) && text.length < 80) return false;

  const hasZip = /\b\d{5}(?:-\d{4})?\b/.test(text);
  const hasPoBoxOrStreet =
    /\bP\.?\s*O\.?\s*Box\b|\bPO Box\b/i.test(text) ||
    /\b\d{2,6}\s+[A-Za-z0-9 .'-]+(?:street|st\.|road|rd\.|drive|dr\.|avenue|ave\.|boulevard|blvd\.|lane|ln\.|way|parkway|pkwy|suite|ste\.?)\b/i.test(text);

  const hasAppealPayerContext =
    /appeals?|prior authorization|department|blue\s*cross|bluecross|blue shield|aetna|cigna|united|uhc|humana|anthem|healthselect|health select/i.test(text);

  const looksLikePatientProvider =
    /carlos postal|301 university|galveston,\s*tx\s*77555|patient address|provider address|recipient address/i.test(text);

  return hasZip && hasPoBoxOrStreet && hasAppealPayerContext && !looksLikePatientProvider;
}

function tjhpPriorAuthExtractCompactAppealSubmissionAddress(text = ""){
  const raw = String(text || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/\u00a0/g, " ")
    .replace(/[ \t]+/g, " ")
    .trim();

  if (!raw) return "";

  const compact = raw
    .replace(/\n+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  const lower = compact.toLowerCase();

  const anchors = [
    "at the following address",
    "following address",
    "how do i file an appeal",
    "submit your appeal",
    "submitting your appeal",
    "send your appeal",
    "mail your appeal",
    "appeal to us in writing"
  ];

  const windows = [];

  anchors.forEach(anchor => {
    let idx = lower.indexOf(anchor);
    while (idx >= 0) {
      windows.push(compact.slice(idx, idx + 1100));
      idx = lower.indexOf(anchor, idx + anchor.length);
    }
  });

  if (!windows.length) {
    const appealIdx = lower.indexOf("appeal");
    if (appealIdx >= 0) windows.push(compact.slice(appealIdx, appealIdx + 1100));
  }

  const payerPattern = /(Blue\s*Cross\s*(?:and\s*)?Blue\s*Shield(?:\s*of\s*Texas)?|BlueCross\s*BlueShield\s*of\s*Texas|BCBSTX|Aetna|Cigna|UnitedHealthcare|United\s*Healthcare|UHC|Humana|Anthem|HealthSelect|Health\s*Select)/i;
  const poPattern = /\bP\.?\s*O\.?\s*Box\s+\d+\b|\bPO Box\s+\d+\b/i;
  const cityStateZipPattern = /\b[A-Z][A-Za-z .'-]+,\s*(?:AL|AK|AZ|AR|CA|CO|CT|DE|FL|GA|HI|IA|ID|IL|IN|KS|KY|LA|MA|MD|ME|MI|MN|MO|MS|MT|NC|ND|NE|NH|NJ|NM|NV|NY|OH|OK|OR|PA|RI|SC|SD|TN|TX|Texas|UT|VA|VT|WA|WI|WV|WY)\s+\d{5}(?:-\d{4})?\b/i;
  const faxPattern = /\bFax\s*[:#]?\s*\(?\d{3}\)?[-.\s]*\d{3}[-.\s]*\d{4}\b/i;

  const candidates = [];

  windows.forEach(windowText => {
    let w = String(windowText || "");

    const addressIntro = w.match(/(?:at the following address|following address|send(?:ing)?(?:\s+your)?\s+appeal(?:\s+to)?|submit(?:ting)?(?:\s+your)?\s+appeal(?:\s+to\s+us)?(?:\s+in\s+writing)?(?:\s+at)?|mail(?:\s+your)?\s+appeal(?:\s+to)?)[\s:,-]*(.*)$/i);
    if (addressIntro && addressIntro[1]) w = addressIntro[1];

    const payerMatch = w.match(payerPattern);
    const poMatch = w.match(poPattern);
    const cityMatch = w.match(cityStateZipPattern);
    const faxMatch = w.match(faxPattern);

    if (!poMatch || !cityMatch) return;

    const lines = [];

    if (payerMatch) {
      let payer = payerMatch[0].replace(/\s+/g, " ").trim();
      if (/^Blue\s*Cross/i.test(payer) && !/Blue\s*Shield/i.test(payer)) payer = "Blue Cross and Blue Shield of Texas";
      if (/BlueCross\s*BlueShield/i.test(payer)) payer = "Blue Cross and Blue Shield of Texas";
      lines.push(payer);
    }

    lines.push(poMatch[0].replace(/\s+/g, " ").replace(/^P\s*O/i, "PO").trim());
    lines.push(cityMatch[0].replace(/\s+/g, " ").trim());
    if (faxMatch) lines.push(faxMatch[0].replace(/\s+/g, " ").trim());

    const candidate = lines
      .filter(Boolean)
      .filter((line, idx, arr) => arr.findIndex(x => x.toLowerCase() === line.toLowerCase()) === idx)
      .join("\n");

    if (tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(candidate)) {
      candidates.push(candidate);
    }
  });

  return candidates[0] || "";
}

function tjhpPriorAuthExtractAppealSubmissionAddress(text = ""){
  const raw = String(text || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/\u00a0/g, " ")
    .trim();

  if (!raw) return "";

  const compactAddress = tjhpPriorAuthExtractCompactAppealSubmissionAddress(raw);
  if (tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(compactAddress)) return compactAddress;

  const normalized = raw
    .split("\n")
    .map(tjhpPriorAuthNormalizeAppealAddressLine)
    .join("\n")
    .replace(/\n{3,}/g, "\n\n");

  const appealWindows = [];

  const patterns = [
    /(?:how do i file an appeal\??)[\s\S]{0,1100}/ig,
    /(?:submit(?:ting)?\s+(?:your\s+)?appeal(?:\s+to\s+us)?(?:\s+in\s+writing)?(?:\s+at\s+the\s+following\s+address)?)[\s\S]{0,900}/ig,
    /(?:send(?:\s+your)?\s+appeal(?:\s+to)?)[\s\S]{0,900}/ig,
    /(?:mail(?:\s+your)?\s+appeal(?:\s+to)?)[\s\S]{0,900}/ig,
    /(?:appeal(?:s)?\s+(?:department|address|submission|request))[\s\S]{0,900}/ig,
    /(?:if\s+i\s+don['’]?t\s+agree\s+with\s+this\s+decision)[\s\S]{0,1200}/ig
  ];

  patterns.forEach(pattern => {
    const matches = normalized.match(pattern) || [];
    matches.forEach(match => {
      const clean = String(match || "").trim();
      if (clean) appealWindows.push(clean);
    });
  });

  if (!appealWindows.length) {
    const fallbackAppealIndex = normalized.toLowerCase().indexOf("appeal");
    if (fallbackAppealIndex >= 0) {
      appealWindows.push(normalized.slice(fallbackAppealIndex, fallbackAppealIndex + 1000));
    }
  }

  const scoreCandidate = candidate => {
    const c = String(candidate || "");
    let score = 0;
    if (/\bP\.?\s*O\.?\s*Box\b|\bPO Box\b/i.test(c)) score += 5;
    if (/\b[A-Z][a-zA-Z .'-]+,\s*(?:TX|Texas)\s+\d{5}(?:-\d{4})?\b/i.test(c)) score += 4;
    if (/\b[A-Z][a-zA-Z .'-]+,\s*(?:AL|AK|AZ|AR|CA|CO|CT|DE|FL|GA|HI|IA|ID|IL|IN|KS|KY|LA|MA|MD|ME|MI|MN|MO|MS|MT|NC|ND|NE|NH|NJ|NM|NV|NY|OH|OK|OR|PA|RI|SC|SD|TN|UT|VA|VT|WA|WI|WV|WY)\s+\d{5}(?:-\d{4})?\b/i.test(c)) score += 4;
    if (/appeals?|prior authorization|department/i.test(c)) score += 3;
    if (/blue\s*cross|bluecross|blue shield|aetna|cigna|united|uhc|humana|anthem|healthselect|health select/i.test(c)) score += 3;
    if (/\bfax\b/i.test(c)) score += 1;
    if (/university|patient|member address|provider address|recipient|carlos|galveston/i.test(c)) score -= 3;
    return score;
  };

  const candidates = [];

  appealWindows.forEach(windowText => {
    let body = String(windowText || "");

    const introMatch = body.match(/(?:following\s+address|send(?:\s+your)?\s+appeal\s+to|submit(?:ting)?(?:\s+your)?\s+appeal(?:\s+to\s+us)?(?:\s+in\s+writing)?(?:\s+at)?|mail(?:\s+your)?\s+appeal\s+to)\s*:?\s*([\s\S]{0,700})/i);
    if (introMatch && introMatch[1]) body = introMatch[1];

    const lines = body
      .split("\n")
      .map(tjhpPriorAuthNormalizeAppealAddressLine)
      .filter(Boolean);

    const useful = [];
    let started = false;

    for (const line of lines) {
      if (tjhpPriorAuthAppealAddressStopLine(line)) {
        if (started && useful.length) break;
        continue;
      }

      const looksUseful = tjhpPriorAuthAppealAddressLineLooksUseful(line);

      if (!started && looksUseful) started = true;
      if (!started) continue;

      if (!looksUseful && useful.length >= 3) break;
      if (!looksUseful && useful.length < 3) continue;

      if (/^(what if|how do|you may|include|contact|call|visit|web)/i.test(line)) continue;

      if (!useful.some(existing => existing.toLowerCase() === line.toLowerCase())) useful.push(line);
      if (useful.length >= 8) break;
    }

    if (useful.length >= 2) {
      const candidate = useful.join("\n").trim();
      if (candidate) candidates.push(candidate);
    }
  });

  candidates.sort((a, b) => scoreCandidate(b) - scoreCandidate(a));

  const best = candidates.find(candidate =>
    scoreCandidate(candidate) >= 4 &&
    (/\bP\.?\s*O\.?\s*Box\b|\bPO Box\b|\b\d{2,6}\s+[A-Za-z0-9 .'-]+(?:street|st\.|road|rd\.|drive|dr\.|avenue|ave\.|boulevard|blvd\.|lane|ln\.|way|parkway|pkwy|suite|ste\.?)\b/i.test(candidate)) &&
    /\b\d{5}(?:-\d{4})?\b/.test(candidate)
  ) || candidates[0] || "";

  const cleanedBest = String(best || "")
    .split("\n")
    .map(tjhpPriorAuthNormalizeAppealAddressLine)
    .filter(Boolean)
    .filter((line, idx, arr) => arr.findIndex(x => x.toLowerCase() === line.toLowerCase()) === idx)
    .slice(0, 8)
    .join("\n");

  return tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(cleanedBest) ? cleanedBest : "";
}
function tjhpPriorAuthDenialSubmissionContextText(org = {}, row = {}){
  const chunks = [];

  [
    row.appeal_address,
    row.appeal_submission_address,
    row.payer_appeal_address,
    row.payer_submission_address,
    row.payer_mailing_address,
    row.denial_letter_appeal_address,
    row.denial_appeal_instructions,
    row.appeal_instructions,
    row.submission_instructions
  ].forEach(value => {
    const clean = String(value || "").trim();
    if (clean) chunks.push(clean);
  });

  try {
    const item = tjhpPriorAuthWorkspaceEvidenceItemsForRender(org, row)
      .find(x => String(x && x.key || "") === "denial_or_partial_approval_letter");

    const attachments = Array.isArray(item && item.attachments) ? item.attachments : [];
    attachments.forEach(att => {
      [
        att.appeal_address,
        att.appeal_submission_address,
        att.submission_address,
        att.appeal_instructions,
        att.text,
        att.extracted_text,
        att.summary,
        att.notes,
        att.file_name
      ].forEach(value => {
        const clean = String(value || "").trim();
        if (clean) chunks.push(clean);
      });
    });
  } catch (err) {}

  return chunks.join("\n");
}

function tjhpPriorAuthAttachmentStoredPath(att = {}){
  const candidates = [
    att.absPath,
    att.storedPath,
    att.stored_path,
    att.filepath,
    att.file_path,
    att.local_path,
    att.path
  ]
    .map(value => String(value || "").trim())
    .filter(Boolean);

  for (const candidate of candidates) {
    if (fs.existsSync(candidate)) return candidate;

    const clean = candidate.replace(/^\/+/, "");
    const abs = path.join(__dirname, clean);
    if (fs.existsSync(abs)) return abs;
  }

  const url = String(att.url || att.file_url || "").trim();

  if (url && url.startsWith("/uploads/")) {
    const rel = url.replace(/^\/+/, "");
    const abs = path.join(__dirname, rel);
    if (fs.existsSync(abs)) return abs;
  }

  if (url && url.startsWith("uploads/")) {
    const abs = path.join(__dirname, url);
    if (fs.existsSync(abs)) return abs;
  }

  return "";
}

async function tjhpPriorAuthAttachmentTextForAppealAddress(att = {}){
  const direct = [
    att.appeal_submission_address,
    att.appeal_address,
    att.submission_address,
    att.appeal_instructions,
    att.extracted_text,
    att.text_excerpt,
    att.text,
    att.summary,
    att.notes
  ].map(x => String(x || "").trim()).filter(Boolean).join("\n");

  if (direct && direct.length > 60) return direct;

  const storedPath = tjhpPriorAuthAttachmentStoredPath(att);
  if (!storedPath) return direct;

  const fileName = String(att.file_name || att.filename || att.originalName || path.basename(storedPath)).trim();
  const fileType = String(att.file_type || att.mimeType || "").trim();

  try {
    const text = await tjhpExtractTextFromUploadedFileForParsing({
      filename: fileName,
      originalName: fileName,
      file_name: fileName,
      mimeType: fileType,
      file_type: fileType,
      absPath: storedPath,
      path: storedPath
    });

    const normalized = tjhpNormalizeExtractedUploadText(text).slice(0, 40000);
    return [direct, normalized].filter(Boolean).join("\n");
  } catch (err) {
    return direct;
  }
}

async function tjhpPriorAuthHydrateAppealSubmissionAddressFromEvidence(org = {}, row = {}){
  const already = [
    row.appeal_address,
    row.appeal_submission_address,
    row.payer_appeal_address,
    row.payer_submission_address,
    row.denial_letter_appeal_address
  ]
    .map(value => String(value || "").trim())
    .find(value => tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(value));

  if (already) {
    return {
      ...row,
      appeal_submission_address: already,
      payer_appeal_address: already,
      denial_letter_appeal_address: already
    };
  }

  let evidenceState = {};
  try {
    evidenceState = tjhpPriorAuthWorkspaceEvidenceState(row, "denial_or_partial_approval_letter") || {};
  } catch (err) {
    evidenceState = {};
  }

  const attachments = Array.isArray(evidenceState.attachments) ? evidenceState.attachments : [];
  const chunks = [tjhpPriorAuthDenialSubmissionContextText(org, row)];

  for (const att of attachments.slice(0, 4)) {
    const text = await tjhpPriorAuthAttachmentTextForAppealAddress(att);
    if (text) chunks.push(text);

    const extracted = tjhpPriorAuthExtractAppealSubmissionAddress(chunks.join("\n"));
    if (tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(extracted)) {
      return {
        ...row,
        appeal_submission_address: extracted,
        payer_appeal_address: extracted,
        denial_letter_appeal_address: extracted,
        appeal_submission_address_source: "denial_or_partial_approval_letter"
      };
    }
  }

  const extracted = tjhpPriorAuthExtractAppealSubmissionAddress(chunks.join("\n"));

  if (!tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(extracted)) return row;

  return {
    ...row,
    appeal_submission_address: extracted,
    payer_appeal_address: extracted,
    denial_letter_appeal_address: extracted,
    appeal_submission_address_source: "denial_or_partial_approval_letter"
  };
}

function tjhpPriorAuthAppealSubmissionAddressBlock(org = {}, row = {}, ctx = {}){
  const manual = tjhpPriorAuthManualAppealSubmissionAddress(row, ctx);
  if (manual) return manual;

  const explicit = tjhpPriorAuthFirstValue(
    row.appeal_address,
    row.appeal_submission_address,
    row.payer_appeal_address,
    row.payer_submission_address,
    ctx.appeal_address,
    ctx.appeal_submission_address
  );

  if (tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(explicit)) return explicit;

  const denialText = tjhpPriorAuthDenialSubmissionContextText(org, row);
  const extracted = tjhpPriorAuthExtractAppealSubmissionAddress(denialText);
  if (tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(extracted)) return extracted;

  return "";
}

function tjhpPriorAuthManualAppealAddressLooksUsable(value = ""){
  const text = String(value || "").trim();

  if (!text) return false;
  if (/^\[?\s*payer address\s*\]?$/i.test(text)) return false;
  if (/^\[.*\]$/.test(text) && text.length < 80) return false;

  return text.length >= 8;
}

function tjhpPriorAuthManualAppealSubmissionAddress(row = {}, ctx = {}){
  let denialEvidenceState = {};
  try {
    denialEvidenceState = tjhpPriorAuthWorkspaceEvidenceState(row, "denial_or_partial_approval_letter") || {};
  } catch (err) {
    denialEvidenceState = {};
  }

  const source = String(
    row.appeal_submission_address_source ||
    row.denial_letter_appeal_address_source ||
    denialEvidenceState.appeal_submission_address_source ||
    ctx.appeal_submission_address_source ||
    ""
  ).trim();

  const candidates = [
    row.manual_appeal_submission_address,
    denialEvidenceState.manual_appeal_submission_address,
    ctx.manual_appeal_submission_address,
    denialEvidenceState.appeal_submission_address,
    row.appeal_submission_address,
    row.payer_appeal_address,
    row.denial_letter_appeal_address,
    ctx.appeal_submission_address
  ];

  for (const candidate of candidates) {
    const clean = String(candidate || "").trim();
    if (!clean) continue;

    if (
      source === "manual_denial_letter" ||
      source === "workspace_evidence_manual" ||
      tjhpPriorAuthManualAppealAddressLooksUsable(clean)
    ) {
      return clean;
    }
  }

  return "";
}

function tjhpPriorAuthEvidenceIncludedInPacketContents(org = {}, row = {}, evidenceKey = ""){
  const key = String(evidenceKey || "").trim();
  if (!key) return false;

  let state = {};
  try {
    state = tjhpPriorAuthWorkspaceEvidenceState(row, key) || {};
  } catch (err) {
    state = {};
  }

  if (state.excluded === true) return false;

  const attachments = Array.isArray(state.attachments) ? state.attachments : [];

  return attachments.some(att => {
    if (!att || typeof att !== "object") return false;
    const hasFile =
      String(att.url || "").trim() ||
      String(att.path || "").trim() ||
      String(att.storedPath || "").trim() ||
      String(att.absPath || "").trim() ||
      String(att.file_name || att.filename || att.originalName || "").trim();

    return Boolean(hasFile);
  });
}

function tjhpPriorAuthCoverLetterApplyAppealAddress(org = {}, row = {}, text = "", ctx = {}){
  let out = String(text || "").trim();
  if (!out) return out;

  const address = tjhpPriorAuthAppealSubmissionAddressBlock(org, row, ctx);
  if (!tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(address)) return out;

  const payer = tjhpPriorAuthFirstValue(
    ctx.payer,
    row.payer,
    row.payer_name,
    row.insurance,
    "Payer"
  );

  const payerBlock = [
    payer,
    "Prior Authorization Appeals Department",
    address
  ].filter(x => String(x || "").trim()).join("\n");

  if (out.includes("[Payer Address]")) {
    out = out.replace(/\[Payer Address\]/g, address);
  }

  const genericBlockPattern = new RegExp(
    String(payer || "Payer").replace(/[.*+?^${}()|[\]\\]/g, "\\$&") +
      "\\s*\\n\\s*Prior Authorization Appeals Department\\s*\\n\\s*\\[Payer Address\\]",
    "i"
  );

  if (genericBlockPattern.test(out)) {
    out = out.replace(genericBlockPattern, payerBlock);
  }

  if (!out.includes(address) && /Prior Authorization Appeals Department/i.test(out)) {
    out = out.replace(
      /(Prior Authorization Appeals Department)(?![\s\S]{0,160}(?:PO Box|P\.?\s*O\.?\s*Box|\d{5}(?:-\d{4})?|\[Payer Address\]))/i,
      `$1\n${address}`
    );
  }

  return out.replace(/\n{3,}/g, "\n\n").trim();
}

function tjhpPriorAuthPayerAddressBlock(row = {}, ctx = {}, org = {}){
  const payer = tjhpPriorAuthFirstValue(
    ctx.payer,
    row.payer,
    row.payer_name,
    row.insurance,
    "Payer"
  );

  const appealSubmissionBlock = tjhpPriorAuthAppealSubmissionAddressBlock(org, row, ctx);
  const cleanAppealSubmissionBlock = tjhpPriorAuthLooksLikeRealAppealSubmissionAddress(appealSubmissionBlock)
    ? appealSubmissionBlock
    : "";

  const payerAddress = tjhpPriorAuthFirstValue(
    cleanAppealSubmissionBlock,
    row.payer_address,
    row.payer_mailing_address,
    row.insurance_address,
    "[Payer Address]"
  );

  if (cleanAppealSubmissionBlock) return payerAddress;

  return [
    payer,
    "Prior Authorization Appeals Department",
    payerAddress
  ].filter(x => String(x || "").trim()).join("\n");
}

function tjhpPriorAuthCoverLetterPacketContentsLines(org = {}, row = {}){
  const lines = [];

  tjhpPriorAuthPayerFacingPacketContentOrder().forEach(pair => {
    const kind = pair[0];
    const key = pair[1];

    if (kind === "section") {
      const label = tjhpPriorAuthPacketContentLabel(org, row, kind, key);
      if (!label) return;
      if (lines.some(existing => existing.toLowerCase() === label.toLowerCase())) return;
      lines.push(label);
      return;
    }

    if (kind === "evidence") {
      if (!tjhpPriorAuthEvidenceIncludedInPacketContents(org, row, key)) return;

      const label = tjhpPriorAuthPacketContentLabel(org, row, kind, key);
      if (!label) return;
      if (lines.some(existing => existing.toLowerCase() === label.toLowerCase())) return;
      lines.push(label);
    }
  });

  return lines;
}

function tjhpPriorAuthCoverLetterPacketContentsBlock(org = {}, row = {}){
  const lines = tjhpPriorAuthCoverLetterPacketContentsLines(org, row);
  return [
    "Enclosures / packet contents include:",
    ...lines.map(line => `- ${line}`)
  ].join("\n");
}

function tjhpPriorAuthRemoveLeadingDuplicatePracticeName(text = "", org = {}, row = {}){
  const identity = tjhpPriorAuthPracticeIdentityContext(org, row);
  const orgName = String(identity.orgName || "").trim();
  let out = String(text || "").trimStart();

  if (!orgName) return out;

  const firstLine = out.split(/\n/)[0] || "";
  if (firstLine.trim().toLowerCase() === orgName.toLowerCase()) {
    out = out.split(/\n/).slice(1).join("\n").trimStart();
  }

  return out;
}

function tjhpPriorAuthEnsureCoverLetterProfessionalBlocks(org = {}, row = {}, text = ""){
  let out = tjhpPriorAuthAiCleanPriorGeneratedAdditions(String(text || "").trim());
  const identity = tjhpPriorAuthPracticeIdentityContext(org, row);
  const letterhead = tjhpPriorAuthPracticeLetterheadBlock(org, row);
  const lower = out.toLowerCase();

  const hasLetterhead =
    lower.includes("phone:") ||
    lower.includes("email:") ||
    lower.includes("npi:") ||
    lower.includes("tax id:") ||
    lower.includes("[practice address]");

  if (!hasLetterhead) {
    out = tjhpPriorAuthRemoveLeadingDuplicatePracticeName(out, org, row);
    out = `${letterhead}\n\n${out}`.replace(/\n{3,}/g, "\n\n").trim();
  }

  if (!/enclosures\s*\/?\s*packet contents include|packet contents include|attachments included/i.test(out)) {
    out = tjhpPriorAuthAiInsertBeforeClosing(
      out,
      tjhpPriorAuthCoverLetterPacketContentsBlock(org, row)
    );
  }

  if (!/(sincerely,|respectfully,|thank you,)/i.test(out)) {
    out = `${out}\n\nSincerely,\n${identity.signatureName || identity.orgName}`.replace(/\n{3,}/g, "\n\n").trim();
  }

  out = tjhpPriorAuthCoverLetterApplyAppealAddress(org, row, out);
  return out.replace(/\n{3,}/g, "\n\n").trim();
}

function tjhpPriorAuthCoverLetterDefaultText(org = {}, row = {}, ctx = {}){
  const identity = tjhpPriorAuthPracticeIdentityContext(org, row);
  let context = {};

  try {
    context = tjhpPriorAuthAppealWorkspaceContext(org, row) || {};
  } catch (err) {
    context = {};
  }

  context = { ...context, ...(ctx || {}) };

  const patient = tjhpPriorAuthFirstValue(context.patient, row.patient_name, "[Patient Name]");
  const payer = tjhpPriorAuthFirstValue(context.payer, row.payer, "[Payer]");
  const service = tjhpPriorAuthFirstValue(context.requested_service, row.requested_service, "[Requested Service]");
  const auth = tjhpPriorAuthFirstValue(context.auth_number, row.auth_number, context.auth_case_id, row.auth_case_id, "[Authorization Number]");
  const cpt = tjhpPriorAuthFirstValue(context.cpt_hcpcs, row.cpt_hcpcs, "-");
  const icd10 = tjhpPriorAuthFirstValue(context.icd10, row.icd10, "-");
  const status = tjhpPriorAuthFirstValue(context.status, row.status, "-");
  const denialReason = tjhpPriorAuthFirstValue(context.denial_reason, row.denial_reason);
  const partialReason = tjhpPriorAuthFirstValue(context.partial_approval_reason, row.partial_approval_reason);
  const requestedAction = tjhpPriorAuthFirstValue(
    context.requested_action_text,
    context.requested_action,
    "Please approve the requested prior authorization based on the attached Letter of Medical Necessity, clinical documentation, payer-criteria support, and source proof."
  );

  const decisionContext = denialReason
    ? `Decision Reason / Context: ${denialReason}`
    : (partialReason ? `Partial Approval Context: ${partialReason}` : "");

  const body = [
    tjhpPriorAuthPracticeLetterheadBlock(org, row),
    "",
    new Date().toISOString().slice(0, 10),
    "",
    tjhpPriorAuthPayerAddressBlock(row, context, org),
    "",
    "Re: Prior Authorization Appeal / Reconsideration",
    `Patient: ${patient}`,
    `Requested Service: ${service}`,
    `Authorization / Reference Number: ${auth}`,
    `Payer: ${payer}`,
    `CPT / HCPCS: ${cpt}`,
    `ICD-10: ${icd10}`,
    `Current Status: ${status}`,
    decisionContext,
    "",
    "To the Prior Authorization Appeals Department,",
    "",
    `${identity.orgName} respectfully requests reconsideration of the prior authorization decision for ${service}. The attached packet supports medical necessity, payer-criteria review, and approval of the requested authorization.`,
    "",
    "Requested Action:",
    requestedAction,
    "",
    tjhpPriorAuthCoverLetterPacketContentsBlock(org, row),
    "",
    "Sincerely,",
    identity.signatureName || identity.orgName
  ].filter(line => line !== null && line !== undefined).join("\n");

  return body.replace(/\n{3,}/g, "\n\n").trim();
}

function tjhpPriorAuthExportPacketSectionText(org = {}, row = {}, sectionKey = "", fallbackText = ""){
  const cleanKey = String(sectionKey || "").trim();
  const packetSections =
    row &&
    row.workspace_packet_sections &&
    typeof row.workspace_packet_sections === "object" &&
    !Array.isArray(row.workspace_packet_sections)
      ? row.workspace_packet_sections
      : {};

  const savedText = String(packetSections[cleanKey] || "").trim();

  if (savedText) {
    return cleanKey === "appeal_narrative"
      ? tjhpPriorAuthCoverLetterApplyAppealAddress(org, row, savedText)
      : savedText;
  }

  if (cleanKey === "appeal_narrative") {
    let ctx = {};
    try {
      ctx = tjhpPriorAuthAppealWorkspaceContext(org, row) || {};
    } catch (err) {
      ctx = {};
    }

    return tjhpPriorAuthCoverLetterApplyAppealAddress(
      org,
      row,
      tjhpPriorAuthCoverLetterDefaultText(org, row, ctx),
      ctx
    );
  }

  return String(fallbackText || "").trim();
}

function tjhpPriorAuthAiInsertBeforeClosing(text = "", addition = ""){
  const body = String(text || "").trimEnd();
  const add = String(addition || "").trim();
  if (!body || !add) return body || add;

  const lower = body.toLowerCase();
  const closingMatches = [
    "\nsincerely,",
    "\nrespectfully,",
    "\nthank you,"
  ];

  let insertAt = -1;
  for (const marker of closingMatches) {
    const idx = lower.lastIndexOf(marker);
    if (idx >= 0) {
      insertAt = idx + 1;
      break;
    }
  }

  if (insertAt < 0) {
    return `${body}\n\n${add}`.replace(/\n{3,}/g, "\n\n").trim();
  }

  const before = body.slice(0, insertAt).trimEnd();
  const after = body.slice(insertAt).trimStart();

  return `${before}\n\n${add}\n\n${after}`.replace(/\n{3,}/g, "\n\n").trim();
}

function tjhpPriorAuthAiCleanPriorGeneratedAdditions(text = ""){
  let out = String(text || "").replace(/\r\n/g, "\n").trim();

  const generatedPatterns = [
    /(?:\n\n|^)\s*This request is supported by the attached Letter of Medical Necessity, clinical documentation, payer-criteria support, authorization history, and source proof included in this packet\.\s*/gi,
    /(?:\n\n|^)\s*This request is supported by the attached medical-necessity documentation, payer-criteria support, authorization history, and source proof included in this packet\.\s*/gi,
    /(?:\n\n|^)\s*The payer should compare the attached documentation to the applicable medical-necessity criteria and identify any criterion that remains unmet\.\s*/gi,
    /(?:\n\n|^)\s*We appreciate timely review of the enclosed documentation and a written determination based on the complete record\.\s*/gi,
    /(?:\n\n|^)\s*This revision is intentionally concise and focused on the payer action requested\.\s*/gi,
    /(?:\n\n|^)\s*If any portion remains denied, please provide the specific medical policy criterion, clinical rationale, and documentation requirement needed for reconsideration\.\s*/gi,
    /(?:\n\n|^)\s*For peer-to-peer discussion, focus on diagnosis, severity, failed alternatives, clinical risk of delay, and the requested authorization outcome\.\s*/gi,
    /(?:\n\n|^)\s*Payer Criteria Match Rationale:\s*The clinical facts should be mapped to the payer[’']s medical-necessity criteria, including diagnosis, severity, failed alternatives, diagnostic support, and why the requested service is appropriate now\.\s*/gi
  ];

  generatedPatterns.forEach(pattern => {
    out = out.replace(pattern, "\n\n");
  });

  return out.replace(/[ \t]+\n/g, "\n").replace(/\n{3,}/g, "\n\n").trim();
}

function tjhpPriorAuthAiHasMeaning(text = "", phrase = ""){
  return String(text || "").toLowerCase().includes(String(phrase || "").toLowerCase());
}

function tjhpPriorAuthAiRegenerateInstruction(regeneratePrompt = "", preview = {}){
  const raw = String(regeneratePrompt || "").trim();
  if (raw) return raw;

  const count = Number(preview && preview.regenerate_count || 0) || 0;
  const variants = [
    "Make the wording more firm and payer-facing.",
    "Make the wording more concise and direct.",
    "Add clearer payer-criteria and source-proof language.",
    "Make the wording more professional and medically focused."
  ];

  return variants[count % variants.length];
}

function tjhpPriorAuthAiDraftForSection(org = {}, row = {}, sectionKey = "", prompt = "", currentText = "", regeneratePrompt = ""){
  const cleanKey = String(sectionKey || "").trim();
  const patient = String(row.patient_name || "the patient").trim() || "the patient";
  const payer = String(row.payer || "the payer").trim() || "the payer";
  const service = String(row.requested_service || "the requested service").trim() || "the requested service";
  const authNumber = String(row.auth_number || "").trim();
  const status = String(row.status || "").trim();
  const denialReason = String(row.denial_reason || "").trim();
  const partialReason = String(row.partial_approval_reason || "").trim();
  const cpt = String(row.cpt_hcpcs || "").trim();
  const icd10 = String(row.icd10 || "").trim();
  const orgName = String(org.org_name || org.name || "the requesting provider").trim() || "the requesting provider";
  const NL = "\n";

  const contextText = [prompt, regeneratePrompt].join(" ").toLowerCase();
  const wantsFirm = /firm|strong|stronger|assertive|payer-facing|appeal/i.test(contextText);
  const wantsConcise = /concise|short|brief|direct/i.test(contextText);
  const wantsCriteria = /criteria|policy|medical necessity|payer criteria|coverage/i.test(contextText);
  const wantsProfessional = /professional|polished|clear|clean/i.test(contextText);

  const caseFacts = [
    `Patient: ${patient}`,
    `Payer: ${payer}`,
    `Requested service: ${service}`,
    authNumber ? `Authorization / Reference Number: ${authNumber}` : "",
    status ? `Current Status: ${status}` : "",
    cpt ? `CPT / HCPCS: ${cpt}` : "",
    icd10 ? `ICD-10: ${icd10}` : "",
    denialReason ? `Decision Reason / Context: ${denialReason}` : "",
    partialReason ? `Partial Approval Context: ${partialReason}` : ""
  ].filter(Boolean);

  const baseRaw = String(currentText || "").trim();
  const base = tjhpPriorAuthAiCleanPriorGeneratedAdditions(baseRaw);

  const fallbackCover = tjhpPriorAuthCoverLetterDefaultText(org, row, {
    patient,
    payer,
    requested_service: service,
    auth_number: authNumber,
    status,
    denial_reason: denialReason,
    partial_approval_reason: partialReason,
    cpt_hcpcs: cpt,
    icd10,
    requested_action_text: "Please approve the requested prior authorization based on the attached Letter of Medical Necessity, clinical documentation, payer-criteria support, and source proof."
  });

  if (cleanKey === "appeal_narrative") {
    let next = base || fallbackCover;

    next = next
      .replace(/We are requesting reconsideration/gi, "We respectfully request reconsideration")
      .replace(/Approve the requested prior authorization based on medical necessity and the supporting clinical documentation\./gi, "Please approve the requested prior authorization based on the attached Letter of Medical Necessity, clinical documentation, payer-criteria support, and source proof.");

    let addition = "";

    if (wantsConcise) {
      addition = "The attached packet provides the medical-necessity rationale, payer-criteria support, and source proof needed to complete review of this authorization request.";
    } else if (wantsCriteria) {
      addition = "The attached documentation should be reviewed against the applicable payer medical-necessity criteria, including the clinical rationale, diagnostic support, authorization history, and source proof included with this packet.";
    } else if (wantsFirm) {
      addition = "If any portion of this request remains denied, please provide the specific medical policy criterion, clinical rationale, and documentation requirement needed for reconsideration.";
    } else if (wantsProfessional) {
      addition = "We appreciate a timely review of the complete prior authorization packet and a written determination based on the attached medical-necessity documentation and source proof.";
    } else {
      addition = "This request is supported by the attached Letter of Medical Necessity, clinical documentation, payer-criteria support, authorization history, and source proof included in this packet.";
    }

    if (!tjhpPriorAuthAiHasMeaning(next, addition)) {
      next = tjhpPriorAuthAiInsertBeforeClosing(next, addition);
    }

    next = tjhpPriorAuthEnsureCoverLetterProfessionalBlocks(org, row, next);
    return next.replace(/\n{3,}/g, "\n\n").trim();
  }

  if (cleanKey === "letter_of_medical_necessity") {
    let next = base || [
      "Letter of Medical Necessity",
      "",
      `${service} is medically necessary for ${patient} based on the documented diagnosis, clinical severity, treatment history, diagnostic support, and expected clinical benefit.`,
      "",
      caseFacts.join(NL),
      "",
      "Medical Necessity Rationale:",
      "The requested service should be evaluated in the context of the patient’s documented clinical need, prior treatment course, and risk of delayed or unavailable care.",
      "",
      "Requested Action:",
      "Please authorize the requested service based on the attached clinical documentation and payer-criteria support."
    ].join(NL);

    const addition = wantsCriteria || wantsFirm
      ? `Payer Criteria Support:${NL}The clinical facts should be mapped directly to the applicable payer criteria, including diagnosis, severity, failed alternatives, diagnostic findings, and why ${service} is medically necessary now.`
      : `Clinical Rationale:${NL}The available documentation should demonstrate why ${service} is clinically appropriate, medically necessary, and supported by the patient’s current condition and treatment history.`;

    if (!tjhpPriorAuthAiHasMeaning(next, "Payer Criteria Support") && !tjhpPriorAuthAiHasMeaning(next, "Clinical Rationale")) {
      next = `${next.trim()}\n\n${addition}`;
    }

    return next.replace(/\n{3,}/g, "\n\n").trim();
  }

  if (cleanKey === "clinical_summary") {
    let next = base || [
      "Clinical Summary",
      "",
      `Patient: ${patient}`,
      `Requested Service: ${service}`,
      "",
      "Clinical Need:",
      "Summarize the diagnosis, symptoms, severity, functional impact, prior treatment history, failed alternatives, and relevant diagnostic results supporting the requested service."
    ].join(NL);

    const criteriaBlock = [
      "Payer Criteria Match Rationale:",
      `The clinical facts should be tied to ${payer}'s medical-necessity criteria for ${service}. Include diagnosis, severity, failed alternatives, diagnostic support, and why the requested service is appropriate now.`
    ].join(NL);

    if (!tjhpPriorAuthAiHasMeaning(next, "Payer Criteria Match Rationale")) {
      next = `${next.trim()}\n\n${criteriaBlock}`;
    }

    return next.replace(/\n{3,}/g, "\n\n").trim();
  }

  if (cleanKey === "requested_action") {
    const current = base || `Please approve ${service} for ${patient} based on the attached Letter of Medical Necessity and supporting clinical documentation.`;
    const addition = "If any portion remains denied, please provide the specific medical policy criterion, clinical rationale, and documentation requirement needed for reconsideration.";
    return tjhpPriorAuthAiHasMeaning(current, "specific medical policy criterion")
      ? current
      : `${current.trim()}\n\n${addition}`;
  }

  if (cleanKey === "attachments_index") {
    return base || [
      "Attachments Index",
      "",
      "1. Payer decision letter or partial approval notice",
      "2. Original prior authorization request",
      "3. Letter of Medical Necessity",
      "4. Clinical documentation and diagnostic support",
      "5. Payer policy or criteria support",
      "6. Authorization history and related correspondence",
      "7. Peer-to-peer notes or missing-documentation response, if applicable"
    ].join(NL);
  }

  if (cleanKey === "evidence_summary") {
    let next = base || [
      "Evidence Summary",
      "",
      `The packet should include source proof supporting ${service} for ${patient}, including clinical documentation, diagnostic support, authorization history, payer correspondence, and any missing-documentation response relevant to the current determination.`
    ].join(NL);

    const ehrNote = /ehr|enterprise/i.test(contextText)
      ? "EHR retrieval is available only for Enterprise plans with EHR integration enabled. If EHR is not connected, upload clinical notes, labs, imaging, medication history, treatment records, and provider documentation manually."
      : "Before payer submission, confirm that each referenced source document is attached, previewed, included, or intentionally excluded from the packet.";

    if (!tjhpPriorAuthAiHasMeaning(next, ehrNote)) {
      next = `${next.trim()}\n\n${ehrNote}`;
    }

    return next.replace(/\n{3,}/g, "\n\n").trim();
  }

  return (base || caseFacts.join(NL)).replace(/\n{3,}/g, "\n\n").trim();
}

function tjhpPriorAuthAiEvidencePromptContext(org = {}, row = {}){
  let items = [];
  try {
    items = tjhpPriorAuthWorkspaceEvidenceItemsForRender(org, row);
  } catch (err) {
    items = [];
  }

  const lines = (Array.isArray(items) ? items : []).slice(0, 20).map(item => {
    const label = String(item.label || item.title || item.key || "").trim();
    const status = String(item.status_label || item.status || "").trim();
    const proof = String(item.proof_label || "").trim();
    const excluded = item.excluded === true ? "excluded from packet" : "";
    const attachments = Array.isArray(item.attachments)
      ? item.attachments
          .filter(att => att && typeof att === "object")
          .slice(0, 6)
          .map(att => {
            const name = String(att.file_name || att.filename || att.name || att.originalName || "attached document").trim();
            const pages = String(att.excluded_pages || "").trim();
            return pages ? `${name} (excluded pages: ${pages})` : name;
          })
      : [];

    return [
      label ? `Evidence item: ${label}` : "",
      status ? `Status: ${status}` : "",
      proof ? `Proof: ${proof}` : "",
      excluded ? `Packet handling: ${excluded}` : "",
      attachments.length ? `Attachments: ${attachments.join("; ")}` : ""
    ].filter(Boolean).join(" | ");
  }).filter(Boolean);

  if (!lines.length) {
    return "No uploaded prior-auth source-proof attachments are currently summarized in the workspace. Use bracketed placeholders where source proof is missing.";
  }

  return lines.join("\n");
}

function tjhpPriorAuthAiEhrPromptContext(org = {}, row = {}, prompt = ""){
  const wantsEhr = /ehr|emr|clinical note|clinical notes|progress note|labs?|imaging|medication|treatment history|pull records?|retrieve records?/i.test(String(prompt || ""));
  let integrationsEnabled = false;
  let connectedEhrCount = 0;

  try {
    integrationsEnabled = typeof isIntegrationsEnabledForOrg === "function" && isIntegrationsEnabledForOrg(org);
  } catch (err) {
    integrationsEnabled = false;
  }

  try {
    connectedEhrCount = typeof getOrgEhrIntegrations === "function"
      ? (getOrgEhrIntegrations(org.org_id) || []).filter(i => String(i.status || "") === "connected").length
      : 0;
  } catch (err) {
    connectedEhrCount = 0;
  }

  if (!wantsEhr) {
    return [
      `Enterprise integrations enabled: ${integrationsEnabled ? "yes" : "no"}`,
      `Connected EHR integrations: ${connectedEhrCount}`,
      "Do not claim EHR records were retrieved unless they are already uploaded or present in workspace evidence."
    ].join("\n");
  }

  if (!integrationsEnabled) {
    return [
      "User asked about EHR/clinical records.",
      "EHR retrieval requires an Enterprise plan with integrations enabled.",
      "No live EHR data pull occurred in this drafting request.",
      "If records are missing, tell staff to upload clinical notes, labs, imaging, medication history, treatment history, and provider documentation manually."
    ].join("\n");
  }

  if (!connectedEhrCount) {
    return [
      "User asked about EHR/clinical records.",
      "Enterprise integrations are enabled, but no connected EHR integration is available.",
      "No live EHR data pull occurred in this drafting request.",
      "If records are missing, tell staff to connect EHR integration or upload clinical documentation manually."
    ].join("\n");
  }

  return [
    "User asked about EHR/clinical records.",
    "Enterprise EHR integration appears configured.",
    "No live EHR data pull occurred in this drafting request.",
    "Use only uploaded/source-proof evidence already present in the workspace. If additional EHR documents are needed, describe what should be retrieved in a future EHR retrieval action."
  ].join("\n");
}

function tjhpPriorAuthAiCleanModelOutput(text = ""){
  const cleaner = typeof workspaceCleanAiSectionOutput === "function"
    ? workspaceCleanAiSectionOutput
    : value => String(value || "")
        .replace(/```[a-zA-Z]*\n?/g, "")
        .replace(/```/g, "")
        .replace(/\*\*(.*?)\*\*/g, "$1")
        .replace(/^\s*Here is (the )?(revised|updated).*?:\s*/i, "")
        .replace(/^\s*Updated section:\s*/i, "")
        .replace(/\r\n/g, "\n")
        .replace(/\n{3,}/g, "\n\n")
        .trim();

  return cleaner(text);
}

function tjhpPriorAuthAiNormalizeModelDraft(sectionKey = "", text = ""){
  const cleanKey = String(sectionKey || "").trim();
  let out = tjhpPriorAuthAiCleanModelOutput(text);

  out = tjhpPriorAuthAiCleanPriorGeneratedAdditions(out);

  if (cleanKey === "appeal_narrative") {
    const lower = out.toLowerCase();
    const closingMarkers = ["\nsincerely,", "\nrespectfully,", "\nthank you,"];
    let closingAt = -1;

    for (const marker of closingMarkers) {
      const idx = lower.lastIndexOf(marker);
      if (idx >= 0) {
        closingAt = idx + 1;
        break;
      }
    }

    if (closingAt >= 0) {
      const before = out.slice(0, closingAt).trimEnd();
      const closingAndAfter = out.slice(closingAt).trimStart();
      const closingLines = closingAndAfter.split("\n");
      const closingBlock = closingLines.slice(0, 3).join("\n").trim();
      const trailing = closingLines.slice(3).join("\n").trim();

      if (trailing) {
        out = `${before}\n\n${trailing}\n\n${closingBlock}`.replace(/\n{3,}/g, "\n\n").trim();
      }
    }
  }

  return out.replace(/[ \t]+\n/g, "\n").replace(/\n{3,}/g, "\n\n").trim();
}

async function tjhpPriorAuthAiDraftForSectionSmart({ org = {}, row = {}, sectionKey = "", prompt = "", currentText = "", regeneratePrompt = "" } = {}){
  const fallbackText = tjhpPriorAuthAiDraftForSection(org, row, sectionKey, prompt, currentText, regeneratePrompt);
  const cleanKey = String(sectionKey || "").trim();
  const sectionLabel = tjhpPriorAuthAiSectionLabel(cleanKey);
  const userPrompt = String(prompt || "").trim() || `Improve ${sectionLabel}.`;
  const regen = String(regeneratePrompt || "").trim();

  if (!process.env.OPENAI_API_KEY) {
    return {
      after: fallbackText,
      source: "deterministic_fallback",
      model: "",
      fallback_reason: "OPENAI_API_KEY not configured"
    };
  }

  const caseContext = [
    `Organization: ${String(org.org_name || org.name || "").trim() || "-"}`,
    `Patient: ${String(row.patient_name || row.patient_id || "").trim() || "-"}`,
    `Payer: ${String(row.payer || "").trim() || "-"}`,
    `Requested service: ${String(row.requested_service || "").trim() || "-"}`,
    `CPT / HCPCS: ${String(row.cpt_hcpcs || "").trim() || "-"}`,
    `ICD-10: ${String(row.icd10 || "").trim() || "-"}`,
    `Auth number: ${String(row.auth_number || "").trim() || "-"}`,
    `Status: ${String(row.status || "").trim() || "-"}`,
    `Denial reason: ${String(row.denial_reason || "").trim() || "-"}`,
    `Partial approval reason: ${String(row.partial_approval_reason || "").trim() || "-"}`,
    `Missing documentation: ${normalizePriorAuthListValue(row.missing_documentation).join("; ") || "-"}`
  ].join("\n");

  const evidenceContext = tjhpPriorAuthAiEvidencePromptContext(org, row);
  const ehrContext = tjhpPriorAuthAiEhrPromptContext(org, row, `${userPrompt} ${regen}`);
  const currentSection = String(currentText || "").trim();
  const practiceContext = tjhpPriorAuthPracticeLetterheadBlock(org, row);
  const packetContentsContext = tjhpPriorAuthCoverLetterPacketContentsBlock(org, row);

  const systemPrompt = [
    "You are TJ Healthcare Pro's Prior Authorization packet section editor.",
    "Rewrite only the targeted editable prior-authorization packet section.",
    "Return clean plain text only. No markdown. No bullets unless the section already uses bullets or the user asks for bullets.",
    "Use the current section text as the source of truth. Preserve staff edits and section structure unless the user asks to rewrite.",
    "Use the practice letterhead/account identity when drafting or improving the cover letter.",
    "Cover letters should include practice name, address, phone, email, NPI, Tax ID when available or placeholders when missing.",
    "Cover letters should include a concise Enclosures / packet contents summary before the closing/signature.",
    "Do not place packet contents or new requested-action language after the closing/signature.",
    "Do not invent symptoms, diagnoses, treatment history, payer criteria, authorization history, EHR facts, or uploaded evidence.",
    "If proof is missing, use cautious wording or bracketed placeholders.",
    "For cover letters, never place new content after Sincerely/signature. Keep the closing/signature last.",
    "For medical necessity and clinical summary sections, map clinical facts to payer criteria only when the facts are present in case/evidence context.",
    "Do not submit anything to a payer."
  ].join(" ");

  const userContent = [
    `Target section: ${sectionLabel}`,
    `Section key: ${cleanKey}`,
    `User request: ${userPrompt}`,
    regen ? `Regeneration instruction: ${regen}` : "",
    "",
    "Prior Auth case context:",
    caseContext,
    "",
    "Practice / letterhead context:",
    practiceContext,
    "",
    "Packet contents / enclosures context:",
    packetContentsContext,
    "",
    "Evidence/source-proof context:",
    evidenceContext,
    "",
    "Enterprise/EHR context:",
    ehrContext,
    "",
    "Current section text. This may include unsaved staff edits and must be treated as the latest draft:",
    currentSection || "[This section is blank. Draft using only safe known facts and bracketed placeholders where needed.]"
  ].filter(Boolean).join("\n");

  try {
    const completion = await requestOpenAIChatCompletion({
      temperature: 0.25,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userContent }
      ]
    });

    if (completion && completion.aiError) {
      return {
        after: fallbackText,
        source: "deterministic_fallback",
        model: "",
        fallback_reason: completion.message || "OpenAI request failed"
      };
    }

    const aiText = completion && completion.choices && completion.choices[0] && completion.choices[0].message
      ? completion.choices[0].message.content
      : "";

    let cleaned = tjhpPriorAuthAiNormalizeModelDraft(cleanKey, aiText);
    if (cleanKey === "appeal_narrative") {
      cleaned = tjhpPriorAuthEnsureCoverLetterProfessionalBlocks(org, row, cleaned);
    }

    if (!cleaned || cleaned.length < 20) {
      return {
        after: fallbackText,
        source: "deterministic_fallback",
        model: "",
        fallback_reason: "OpenAI response was empty or too short"
      };
    }

    return {
      after: cleaned,
      source: "openai",
      model: process.env.OPENAI_MODEL || "gpt-4o-mini",
      fallback_reason: ""
    };
  } catch (err) {
    return {
      after: fallbackText,
      source: "deterministic_fallback",
      model: "",
      fallback_reason: err && err.message ? err.message : String(err || "OpenAI request failed")
    };
  }
}

