function tjhpLetterPersonalizationValues({ org_id, claim } = {}) {
  const orgSettings = org_id ? getOrgSettings(org_id) : {};
  return {
    patient_name: workspaceFirstValue(workspaceClaimValue(claim, ["patient_name", "patient", "member_name", "patient_full_name"]), "Patient Name"),
    diagnosis: workspaceFirstValue(workspaceClaimValue(claim, ["diagnosis", "diagnosis_description", "condition"]), "Diagnosis/Condition"),
    diagnosis_code: workspaceFirstValue(workspaceClaimValue(claim, ["icd10_code", "diagnosis_code", "dx_code", "dx"]), "ICD-10 Code"),
    procedure: workspaceFirstValue(workspaceClaimValue(claim, ["procedure_description", "service_description", "treatment_name", "product_name", "equipment_name"]), workspaceClaimValue(claim, ["procedure_code", "cpt_code", "cpt", "hcpcs"]), "Procedure"),
    date_of_service: workspaceFirstValue(workspaceClaimValue(claim, ["dos", "date_of_service", "service_date"]), "Date of Service"),
    payer: workspaceFirstValue(workspaceClaimValue(claim, ["payer", "payer_name", "insurance", "insurance_company"]), "Payer"),
    claim_number: workspaceFirstValue(workspaceClaimValue(claim, ["claim_number", "claim_id"]), "Claim Number"),
    practice_name: workspaceFirstValue(orgSettings?.identity?.legal_name, orgSettings?.identity?.dba_name, "Practice Name")
  };
}

function tjhpApplyLetterPersonalizationPlaceholders(text, values = {}) {
  let out = String(text || "");
  const mapping = {
    "Patient Name": String(values.patient_name || ""),
    "Diagnosis": String(values.diagnosis || ""),
    "Diagnosis Code": String(values.diagnosis_code || ""),
    "Procedure": String(values.procedure || ""),
    "Date of Service": String(values.date_of_service || ""),
    "Payer": String(values.payer || ""),
    "Claim Number": String(values.claim_number || ""),
    "Practice Name": String(values.practice_name || "")
  };
  Object.keys(mapping).forEach((key) => {
    const escaped = key.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    out = out.replace(new RegExp(`\\[${escaped}\\]`, "g"), mapping[key]);
  });
  out = out.replace(/\{\{\s*patient_name\s*\}\}/gi, mapping["Patient Name"]);
  out = out.replace(/\{\{\s*diagnosis\s*\}\}/gi, mapping["Diagnosis"]);
  out = out.replace(/\{\{\s*diagnosis_code\s*\}\}/gi, mapping["Diagnosis Code"]);
  out = out.replace(/\{\{\s*procedure\s*\}\}/gi, mapping["Procedure"]);
  out = out.replace(/\{\{\s*date_of_service\s*\}\}/gi, mapping["Date of Service"]);
  out = out.replace(/\{\{\s*payer\s*\}\}/gi, mapping["Payer"]);
  out = out.replace(/\{\{\s*claim_number\s*\}\}/gi, mapping["Claim Number"]);
  out = out.replace(/\{\{\s*practice_name\s*\}\}/gi, mapping["Practice Name"]);
  return out;
}

function getUserByEmail(email) {
  const e = (email || "").toLowerCase();
  return readJSON(FILES.users, []).find(u => (u.email || "").toLowerCase() === e);
}
function getUserById(user_id) {
  return readJSON(FILES.users, []).find(u => u.user_id === user_id);
}
function getPilot(org_id) {
  return readJSON(FILES.pilots, []).find(p => p.org_id === org_id);
}
function ensurePilot(org_id) {
  const pilots = readJSON(FILES.pilots, []);
  let p = pilots.find(x => x.org_id === org_id);
  if (!p) {
    const started = nowISO();
    const ends = addDaysISO(started, PILOT_DAYS);
    p = { pilot_id: uuid(), org_id, status:"active", started_at: started, ends_at: ends, retention_delete_at: null };
    pilots.push(p);
    writeJSON(FILES.pilots, pilots);
  }
  return p;
}
function getSub(org_id) {
  return readJSON(FILES.subscriptions, []).find(s => s.org_id === org_id);
}
function getEffectivePlan(org_id, sess) {
  if (sess && sess.simulating && sess.simulated_plan) {
    return String(sess.simulated_plan).toLowerCase();
  }

  const sub = getSub(org_id);
  return String((sub && sub.plan) || "starter").toLowerCase();
}
function getBillingSummaryForOrg(org_id) {
  const pilot = getPilot(org_id);
  const sub = getSub(org_id);

  let planKey = "starter";
  let status = "inactive";

  if (pilot && pilot.status === "active") {
    planKey = "trial";
    status = "active";
  } else if (sub && sub.plan) {
    planKey = String(sub.plan || "starter").toLowerCase();
    status = String(sub.status || "active");
  }

  const cfg = PLAN_RUNTIME_DEFAULTS[planKey] || PLAN_RUNTIME_DEFAULTS.starter;

  let currentPeriodEnd = "";

  if (pilot && pilot.status === "active") {
    currentPeriodEnd = String(pilot.ends_at || "");
  } else {
    currentPeriodEnd = String(sub?.current_period_end || "");
  }

  return {
    plan: planKey,
    status,
    stripe_customer_id: String(sub?.stripe_customer_id || ""),
    stripe_subscription_id: String(sub?.stripe_subscription_id || ""),
    current_period_end: currentPeriodEnd,
    case_credits_per_month: Number(cfg.case_credits_per_month || 0),
    payment_tracking_credits_per_month: Number(cfg.payment_tracking_credits_per_month || 0),
    ai_chat_limit: Number(cfg.ai_chat_limit || 0),
    copilot_limit: Number(cfg.copilot_limit || 0),
    workspace_limit: Number(cfg.workspace_limit || 0)
  };
}
function currentMonthKey() {
  const d = new Date();
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth()+1).padStart(2,"0")}`;
}
function getUsage(org_id) {
  const usage = readJSON(FILES.usage, []);
  let u = usage.find(x => x.org_id === org_id);
  if (!u) {
    u = {
      org_id,
      pilot_cases_used: 0,
      pilot_payment_rows_used: 0,
      month_key: currentMonthKey(),
      monthly_case_credits_used: 0,
      monthly_case_overage_count: 0,
      monthly_payment_rows_used: 0,
      monthly_payment_credits_used: 0,
      monthly_ai_generations_used: 0,
      monthly_agent_workspace_edits: 0,
      ai_workspace_used: 0,
      ai_job_timestamps: [],
      ai_chat_used: 0,
      copilot_used: 0,
      copilot_questions_used: 0,
      ai_copilot_queries_used: 0,
      ai_copilot_query_limit: 0,
      claims_processed: 0
    };
    usage.push(u);
    writeJSON(FILES.usage, usage);
  }
  if (u.month_key !== currentMonthKey()) {
    u.month_key = currentMonthKey();
    u.monthly_case_credits_used = 0;
    u.monthly_case_overage_count = 0;
    u.monthly_payment_rows_used = 0;
    u.monthly_payment_credits_used = 0;
    u.monthly_ai_generations_used = 0;
    u.monthly_agent_workspace_edits = 0;
    u.ai_chat_used = 0;
    u.copilot_used = 0;
    u.copilot_questions_used = 0;
    u.ai_copilot_queries_used = 0;
    u.ai_copilot_query_limit = 0;
    u.claims_processed = 0;
    writeJSON(FILES.usage, usage);
  }
  if (typeof u.monthly_ai_generations_used !== "number") u.monthly_ai_generations_used = 0;
  if (typeof u.monthly_agent_workspace_edits !== "number") u.monthly_agent_workspace_edits = 0;
  if (typeof u.ai_workspace_used !== "number") u.ai_workspace_used = 0;

  // 🔥 CANONICAL COPILOT USAGE (single source of truth)
  if (typeof u.copilot_used !== "number") {
    u.copilot_used = Number(
      u.copilot_used ??
      u.ai_copilot_queries_used ??
      u.copilot_questions_used ??
      0
    );
  }

  // force ALL legacy fields to match
  u.ai_copilot_queries_used = u.copilot_used;
  u.copilot_questions_used = u.copilot_used;
  writeJSON(FILES.usage, usage);
  if (typeof u.ai_copilot_query_limit !== "number") u.ai_copilot_query_limit = Number(getCopilotLimit(org_id) || 0);
  if (typeof u.claims_processed !== "number") u.claims_processed = Number(u.monthly_case_credits_used || u.pilot_cases_used || 0);
  return u;
}
function saveUsage(u) {
  const usage = readJSON(FILES.usage, []);
  const idx = usage.findIndex(x => x.org_id === u.org_id);
  if (idx >= 0) usage[idx] = u; else usage.push(u);
  writeJSON(FILES.usage, usage);
}
function auditLog(entry) {
  const audit = readJSON(FILES.audit, []);
  audit.push({ ...entry, at: nowISO() });
  writeJSON(FILES.audit, audit);
}


