  return readJSON(FILES.agent_messages, [])
    .filter(m => m.org_id === org_id && m.workspace_id === ws.workspace_id && m.billed_id === billed_id)
    .sort((a,b)=> new Date(a.created_at||0).getTime() - new Date(b.created_at||0).getTime());
