function workspaceFirstValue(...values){
  for (const value of values) {
    const v = String(value ?? "").trim();
    if (v) return v;
  }
  return "";
}

function workspaceClaimValue(claim, keys, fallback=""){
  for (const key of keys) {
    const v = String(claim?.[key] ?? "").trim();
    if (v) return v;
  }
  return fallback;
}

function workspaceFormatCityStateZip(city, state, zip){
  const c = String(city || "").trim();
  const s = String(state || "").trim();
  const z = String(zip || "").trim();

  if (c && (s || z)) return `${c}, ${[s, z].filter(Boolean).join(" ")}`;
  return [c, s, z].filter(Boolean).join(" ");
}

function workspaceFormatOrgAddressBlock(settings, orgRecord, mode){
  const identity = settings?.identity || {};
  const primary = identity.addr_primary || {};
  const mailing = identity.addr_mailing || {};
  const mailingSame = typeof identity.mailing_same_as_primary === "boolean"
    ? identity.mailing_same_as_primary
    : true;

  let src = primary;
  if (mode === "mailing") src = mailingSame ? primary : mailing;

  const line1 = workspaceFirstValue(
    src.line1,
    mode === "mailing" ? orgRecord?.addr_mailing_line1 : orgRecord?.addr_primary_line1,
    orgRecord?.address_line1,
    orgRecord?.address
  );

  const line2 = workspaceFirstValue(
    src.line2,
    mode === "mailing" ? orgRecord?.addr_mailing_line2 : orgRecord?.addr_primary_line2,
    orgRecord?.address_line2
  );

  const city = workspaceFirstValue(
    src.city,
    mode === "mailing" ? orgRecord?.addr_mailing_city : orgRecord?.addr_primary_city,
    orgRecord?.city
  );

  const state = workspaceFirstValue(
    src.state,
    mode === "mailing" ? orgRecord?.addr_mailing_state : orgRecord?.addr_primary_state,
    orgRecord?.state
  );

  const zip = workspaceFirstValue(
    src.zip,
    mode === "mailing" ? orgRecord?.addr_mailing_zip : orgRecord?.addr_primary_zip,
    orgRecord?.zip
  );

  return [
    line1,
    line2,
    workspaceFormatCityStateZip(city, state, zip)
  ].filter(Boolean).join("\n");
}

function workspaceResolveOrgLogoPath(settings){
  const candidates = [
    settings?.logo_pdf_path,
    settings?.logo_path
  ].filter(Boolean);

  for (const candidate of candidates) {
    const raw = String(candidate || "").trim();
    if (!raw) continue;

    const resolved = path.isAbsolute(raw)
      ? raw
      : path.join(process.cwd(), raw);

    if (fs.existsSync(resolved)) return resolved;
  }

  return "";
}

function workspaceIsPdfSafeImagePath(filePath){
  const ext = path.extname(String(filePath || "")).toLowerCase();
  return [".png", ".jpg", ".jpeg"].includes(ext);
}

async function workspaceTryCreatePdfSafeLogoPath(sourcePath){
  const raw = String(sourcePath || "").trim();
  if (!raw) return "";

  const resolved = path.isAbsolute(raw) ? raw : path.join(process.cwd(), raw);
  if (!fs.existsSync(resolved)) return "";

  if (workspaceIsPdfSafeImagePath(resolved)) return resolved;

  const ext = path.extname(resolved).toLowerCase();
  if (![".webp", ".gif"].includes(ext)) return "";

  let sharp = null;
  try { sharp = require("sharp"); } catch(e) { sharp = null; }
  if (!sharp) return "";

  const outPath = `${resolved}.pdf.png`;

  try {
    await sharp(resolved).png().toFile(outPath);
    if (fs.existsSync(outPath)) return outPath;
  } catch(e) {
    return "";
  }

  return "";
}

async function workspaceEnsurePdfLogoForOrg(org_id){
  const settings = getOrgSettings(org_id) || {};

  const existingPdf = String(settings.logo_pdf_path || "").trim();
  if (existingPdf) {
    const resolvedPdf = path.isAbsolute(existingPdf) ? existingPdf : path.join(process.cwd(), existingPdf);
    if (fs.existsSync(resolvedPdf) && workspaceIsPdfSafeImagePath(resolvedPdf)) {
      return resolvedPdf;
    }
  }

  const rawLogo = String(settings.logo_path || "").trim(
);
  if (!rawLogo) return "";

  const pdfLogoPath = await workspaceTryCreatePdfSafeLogoPath(rawLogo);

  if (pdfLogoPath) {
    saveOrgSettings(org_id, {
      logo_pdf_path: pdfLogoPath,
      logo_pdf_updated_at: nowISO()
    });
    return pdfLogoPath;
  }

  return "";
}

function workspacePdfKitSupportedLogoPath(settings){
  const candidates = [
    settings?.logo_pdf_path,
    settings?.logo_path
  ].filter(Boolean);

  for (const candidate of candidates) {
    const raw = String(candidate || "").trim();
    if (!raw) continue;

    const resolved = path.isAbsolute(raw) ? raw : path.join(process.cwd(), raw);

    if (fs.existsSync(resolved) && workspaceIsPdfSafeImagePath(resolved)) {
      return resolved;
    }
  }

  return "";
}

function workspaceOrgIdentityContext(org_id){
  const orgRecord = org_id && typeof getOrg === "function" ? (getOrg(org_id) || {}) : {};
  const settings = org_id && typeof getOrgSettings === "function" ? (getOrgSettings(org_id) || {}) : {};
  const identity = settings.identity || {};

  const primaryAddress = workspaceFormatOrgAddressBlock(settings, orgRecord, "primary");
  const mailingAddress = workspaceFormatOrgAddressBlock(settings, orgRecord, "mailing");

  const orgName = workspaceFirstValue(
    identity.legal_name,
    identity.dba_name,
    settings.practice_name,
    settings.legal_name,
    orgRecord.legal_name,
    orgRecord.org_name,
    "Practice"
  );

  const phone = workspaceFirstValue(identity.phone, identity.practice_phone, settings.phone, settings.practice_phone, settings.billing_phone, orgRecord.phone, orgRecord.main_phone, orgRecord.practice_phone, orgRecord.billing_phone);
  const email = workspaceFirstValue(identity.email, identity.practice_email, settings.email, settings.practice_email, settings.billing_email, orgRecord.org_email, orgRecord.billing_email, orgRecord.email, orgRecord.practice_email);
  const npi = workspaceFirstValue(identity.npi, settings.npi, settings.provider_npi, orgRecord.org_npi, orgRecord.npi_number, orgRecord.npi);
  const taxId = workspaceFirstValue(identity.tax_id, settings.tax_id, orgRecord.tax_id, orgRecord.tin, orgRecord.tax_identifier);
  const fax = workspaceFirstValue(identity.fax, settings.fax, orgRecord.fax);

  return { settings, orgRecord, identity, orgName, primaryAddress, mailingAddress, addressBlock: primaryAddress || mailingAddress, phone, email, fax, npi, taxId, logoPath: workspaceResolveOrgLogoPath(settings), pdfLogoPath: workspacePdfKitSupportedLogoPath(settings) };
}


function buildWorkspaceLetterOfMedicalNecessityTemplate({ org_id, claim, ws } = {}){
  const orgCtx = workspaceOrgIdentityContext(org_id);
  const orgName = workspaceFirstValue(orgCtx.orgName, "[Provider Letterhead]");
  const practiceAddress = workspaceFirstValue(orgCtx.addressBlock, "[Practice Address]");
  const phoneNumber = workspaceFirstValue(orgCtx.phone, "[Phone Number]");
  const emailAddress = workspaceFirstValue(orgCtx.email, "[Email]");
  const physicianName = workspaceFirstValue(workspaceClaimValue(claim, ["physician_name", "provider_name", "rendering_provider", "ordering_provider"]), orgCtx.settings?.provider_name, orgCtx.settings?.physician_name, orgCtx.identity?.provider_name, orgCtx.identity?.legal_name, orgCtx.identity?.dba_name, orgCtx.orgName, "[Physician Name and Credentials]");
  const npi = workspaceFirstValue(workspaceClaimValue(claim, ["provider_npi", "rendering_npi", "npi"]), orgCtx.npi, "[NPI Number]");
  const payer = workspaceFirstValue(workspaceClaimValue(claim, ["payer", "payer_name", "insurance", "insurance_company"]), "[Insurance Company Name]");
  const payerAddress = workspaceFirstValue(workspaceClaimValue(claim, ["payer_address", "insurance_address"]), "[Address]");
  const patientName = workspaceFirstValue(workspaceClaimValue(claim, ["patient_name", "patient", "member_name", "patient_full_name"]), "[Patient Name]");
  const policyNumber = workspaceFirstValue(workspaceClaimValue(claim, ["policy_number", "member_id", "subscriber_id", "plan_id"]), "[Policy Number]");
  const caseReference = workspaceFirstValue(workspaceClaimValue(claim, ["denial_case_id", "case_reference", "reference_number", "auth_reference"]), workspaceClaimValue(claim, ["claim_number", "claim_id"]), "[If applicable]");
  const claimNumber = workspaceFirstValue(workspaceClaimValue(claim, ["claim_number", "claim_id"]), "[Claim Number]");
  const treatment = workspaceFirstValue(workspaceClaimValue(claim, ["procedure_description", "service_description", "treatment_name", "product_name", "equipment_name"]), workspaceClaimValue(claim, ["procedure_code", "cpt_code", "cpt", "hcpcs"]), "[Name of treatment/product/equipment]");
  const diagnosis = workspaceFirstValue(workspaceClaimValue(claim, ["diagnosis", "diagnosis_description", "condition"]), "[Diagnosis/Condition]");
  const diagnosisCode = workspaceFirstValue(workspaceClaimValue(claim, ["icd10_code", "diagnosis_code", "dx_code", "dx"]), "[ICD-10 Code]");
  const dateOfService = workspaceFirstValue(workspaceClaimValue(claim, ["dos", "date_of_service", "service_date"]), "[Date of Service]");
  const patientAge = workspaceFirstValue(workspaceClaimValue(claim, ["patient_age", "age"]), "[Age]");
  const patientSex = workspaceFirstValue(workspaceClaimValue(claim, ["patient_sex", "sex", "gender"]), "[male/female]");
  const careSince = workspaceFirstValue(workspaceClaimValue(claim, ["care_since", "first_seen_date", "treatment_start_date"]), "[Date]");
  const letterDefaults = getLetterDefaults(orgCtx.settings || getOrgSettings(org_id));
  const lmnPersonalizationValues = tjhpLetterPersonalizationValues({ org_id, claim });
  const defaultLmnOpening = `I am writing on behalf of my patient, ${patientName}, to document the medical necessity of ${treatment} to treat ${diagnosis} ${diagnosisCode}.`;
  const defaultClinicalHistory = `${patientName} is a ${patientAge}-year-old ${patientSex} who has been in my care since ${careSince}. The patient has been diagnosed with ${diagnosis} and is experiencing [list symptoms]. Previous treatments for this condition have included [list previous medications, therapies, or conservative measures], which were [unsuccessful, insufficient, contraindicated, or caused adverse effects].`;
  const defaultTreatmentRationale = `Based on the patient’s clinical history, ${treatment} is medically necessary to [explain treatment purpose, such as reduce pain, improve function, prevent deterioration, or treat the diagnosed condition]. Without this intervention, the patient’s condition may worsen or require additional care. Clinical evidence, payer guidelines, and the patient’s documented history support the medical necessity of this treatment.`;
  const defaultTreatmentPlan = `The recommended plan is to provide ${treatment} for [duration/frequency], with follow-up and monitoring as clinically appropriate.`;
  const defaultConclusion = `I believe ${treatment} is medically necessary for ${patientName}'s care and well-being. Please provide coverage or reconsider the denial for this treatment.`;
  const lmnOpening = String(letterDefaults.lmn_opening || "").trim()
    ? tjhpApplyLetterPersonalizationPlaceholders(letterDefaults.lmn_opening, lmnPersonalizationValues)
    : defaultLmnOpening;
  const lmnClinicalHistory = String(letterDefaults.lmn_clinical_history || "").trim()
    ? tjhpApplyLetterPersonalizationPlaceholders(letterDefaults.lmn_clinical_history, lmnPersonalizationValues)
    : defaultClinicalHistory;
  const lmnTreatmentRationale = String(letterDefaults.lmn_treatment_rationale || "").trim()
    ? tjhpApplyLetterPersonalizationPlaceholders(letterDefaults.lmn_treatment_rationale, lmnPersonalizationValues)
    : defaultTreatmentRationale;
  const lmnTreatmentPlan = String(letterDefaults.lmn_treatment_plan || "").trim()
    ? tjhpApplyLetterPersonalizationPlaceholders(letterDefaults.lmn_treatment_plan, lmnPersonalizationValues)
    : defaultTreatmentPlan;
  const lmnConclusion = String(letterDefaults.lmn_conclusion || "").trim()
    ? tjhpApplyLetterPersonalizationPlaceholders(letterDefaults.lmn_conclusion, lmnPersonalizationValues)
    : defaultConclusion;

  return `${orgName}
${practiceAddress}
Phone Number: ${phoneNumber}
Email: ${emailAddress}

${nowISO().slice(0, 10)}

${payer}
${payerAddress}

Re: Letter of Medical Necessity for ${patientName}
Policy Number: ${policyNumber}
Case/Reference Number: ${caseReference}
Claim Number: ${claimNumber}
Date of Service: ${dateOfService}

To Whom It May Concern,

${lmnOpening}

Patient Clinical History
${lmnClinicalHistory}

Treatment Rationale
${lmnTreatmentRationale}

Treatment Plan
${lmnTreatmentPlan}

Conclusion
${lmnConclusion}

Please contact my office using the phone number or email address listed above with any questions.

${["Sincerely,", "", tjhpPacketClosingTextForWorkspace(org_id, ws?.appeal?.packet_sections?.signature || "")].filter(Boolean).join("\n")}`;
}

