async function pullWorkspaceDocumentBySource(org_id, claim, docKey, sourceType, channel){
  if (sourceType === "ehr") {
    return await pullWorkspaceDocumentFromEHR(org_id, claim, docKey);
  }

  if (sourceType === "clearinghouse") {
    return await pullWorkspaceDocumentFromClearinghouse(org_id, claim, docKey);
  }

  if (sourceType === "payer_portal") {
    return await pullWorkspaceDocumentFromPayerPortal(org_id, claim, docKey);
  }

  if (sourceType === "contract_rules" || sourceType === "system") {
    return {
      ok:false,
      reason:"source_document_required",
      message:"This item is currently system-derived. Attach the source document if the payer requires submission proof."
    };
  }

  return { ok:false, reason:"unsupported_source_type" };
}

function attachPulledWorkspaceDocument(ws, claim, channel, docKey, sourceType, pulled){
  ensureWorkspacePacket(ws);

  const stored = workspaceWritePulledFile({
    org_id: ws.org_id || claim.org_id,
    doc_key: docKey,
    filename: pulled.filename || `${docKey}.pdf`,
    content: pulled.content,
    mime: pulled.mime || "application/pdf"
  });

  const attachment = {
    attachment_id: uuid(),
    filename: stored.filename,
    stored_path: stored.stored_path,
    mime_type: stored.mime_type,
    kind: workspaceAttachmentKindForDocKey(docKey),
    uploaded_at: nowISO(),
    pulled_at: nowISO(),
    doc_key: docKey,

    source_type: sourceType,
    source_label: workspaceSourceLabel(sourceType),
    source_system: workspaceSourceLabel(sourceType),
    source_status: "pulled",

    proof_level: "pulled_source_document",
    is_source_document: true
  };

  ws.attachments = Array.isArray(ws.attachments) ? ws.attachments : [];
  ws.attachments = ws.attachments.filter(a => String(a.doc_key || "") !== String(docKey));
  ws.attachments.push(attachment);

  workspaceUpsertPacketItem(ws, docKey, {
    status: "present",
    attachment_id: attachment.attachment_id,
    updated_at: nowISO(),
    source_type: sourceType,
    source_label: workspaceSourceLabel(sourceType),
    source_status: "pulled",
    proof_level: "pulled_source_document",
    is_source_document: true
  });

  ws.activity = ws.activity || {};
  ws.activity.last_document_pull_at = nowISO();

  ws.audit = Array.isArray(ws.audit) ? ws.audit : [];
  ws.audit.push({
    event_id: uuid(),
    type: "document_pulled",
    doc_key: docKey,
    source_type: sourceType,
    attachment_id: attachment.attachment_id,
    created_at: nowISO()
  });

  return attachment;
}

function workspaceEnhancedCompleteness(ws, channel, claim){
  ensureWorkspacePacket(ws);
  ensurePacketSections(ws, claim);

  const claimCtx = claim || (ws?.org_id && ws?.billed_id ? getBilledById(ws.org_id, ws.billed_id) : null);
  const docs = workspaceRequiredDocConfig(channel);

  const requiredDocs = docs.filter(d => d.required);
  const totalRequired = requiredDocs.length;
  const haveRequired = requiredDocs.filter(d => workspaceDocPresent(ws, d, claimCtx)).length;

  const sectionKey = packetNarrativeKey(channel);
  const sections = channel === "negotiation"
    ? ["header","claim_summary","financial_summary","variance_explanation","requested_amount","requested_action","attachments_index","signature"]
    : ["header","claim_summary","financial_summary","argument","requested_action","attachments_index","signature"];

  const packetSections = ws[channel]?.packet_sections || {};
  const filledSections = sections.filter(k => String(packetSections[k] || "").trim()).length;

  const total = totalRequired + sections.length;
  const complete = haveRequired + filledSections;
  const pct = total ? Math.round((complete / total) * 100) : 0;

  return {
    total,
    complete,
    pct,
    requiredMissing: requiredDocs.filter(d => !workspaceDocPresent(ws, d, claimCtx)),
    docs,
    sectionKey,
    requiredComplete: haveRequired,
    requiredTotal: totalRequired
  };
}

function computeWorkspaceQuickScore(ws, claim, derived, channel){
  const completeness = workspaceEnhancedCompleteness(ws, channel, claim);
  const docs = workspaceRequiredDocConfig(channel);

  let score = 45;

  const hasRequiredProof = (key) => {
    const doc = docs.find(d => d.key === key) || { key };
    return workspaceDocPresent(ws, doc, claim);
  };

  if (channel === "appeal") {
    if (hasRequiredProof("denial_letter")) score += 14;
    if (hasRequiredProof("eob_era")) score += 12;
    if (hasRequiredProof("claim_form")) score += 10;

    if (hasRequiredProof("payer_policy")) score += 5;
    if (hasRequiredProof("lmn")) score += 5;
    if (hasRequiredProof("office_notes")) score += 4;
    if (hasRequiredProof("prior_auth")) score += 4;
  } else {
    if (hasRequiredProof("eob_era")) score += 14;
    if (hasRequiredProof("claim_form")) score += 10;
    if (hasRequiredProof("contract_excerpt")) score += 14;

    if (hasRequiredProof("variance_calc")) score += 6;
    if (hasRequiredProof("fee_schedule")) score += 5;
    if (hasRequiredProof("payment_history")) score += 3;
    if (hasRequiredProof("payer_correspondence")) score += 3;
  }

  score += Math.round((completeness.pct || 0) * 0.16);

  const missingRequiredPenalty = Number(completeness.requiredMissing?.length || 0) * 8;
  score -= missingRequiredPenalty;

  score = Math.max(10, Math.min(95, score));

  const recoveryBase =
    Number(derived?.underpaidAmount || 0) ||
    Number(derived?.atRiskAmount || 0) ||
    Number(claim?.underpaid_amount || 0) ||
    Number(claim?.at_risk_amount || 0) ||
    0;

  const estimatedRecovery = Math.round(recoveryBase * (score / 100));

  return {
    probability: score,
    estimatedRecovery,
    completeness
  };
}

function renderWorkspaceIntelligence(ws, claim, derived, channel){
  const score = computeWorkspaceQuickScore(ws, claim, derived, channel);

  const riskLevel =
    score.probability >= 80 ? "High Confidence" :
    score.probability >= 60 ? "Moderate Confidence" :
    "Low Confidence";

  const docs = workspaceRequiredDocConfig(channel);
  const missingRequired = docs.filter(d => d.required && !workspaceDocPresent(ws, d, claim));

  const drivers = [];

  missingRequired.forEach(d => drivers.push(`Missing ${d.label}`));

  if (channel === "appeal") {
    if (!workspaceDocPresent(ws, {key:"payer_policy"}, claim) && !workspaceDocPresent(ws, {key:"lmn"}, claim)) {
      drivers.push("Appeal argument may need policy or medical-necessity support");
    }
  } else {
    if (!workspaceDocPresent(ws, {key:"contract_excerpt"}, claim)) {
      drivers.push("Negotiation needs contract or allowed-rule proof");
    }
    if (!String(ws?.negotiation?.packet_sections?.variance_explanation || "").trim()) {
      drivers.push("Variance explanation should clearly compare expected vs paid");
    }
  }

  const driverText = drivers.length
    ? `Risk Factors: ${drivers.slice(0,4).join(", ")}`
    : "Packet has the core proof needed for this workflow";

  const actionSignal =
    score.probability >= 80 ? "Proceed to Submission" :
    score.probability >= 60 ? "Review Before Submitting" :
    "Improve Packet Before Submission";

  return `
    <div class="ws-intel-card">
      <div class="ws-intel-header">
        <div style="display:flex;align-items:center;gap:6px;">
          <span>📊</span>
          <span>Revenue Intelligence</span>
        </div>
      </div>

      <div class="ws-intel-main">
        <div>
          <div class="ws-intel-score">${score.probability}%</div>
          <div class="ws-intel-label">Success Probability</div>
        </div>

        <div style="text-align:right;">
          <div style="font-size:18px;font-weight:900;">
            ${formatMoneyUI(score.estimatedRecovery)}
          </div>
          <div class="ws-intel-label">Estimated Recovery</div>
        </div>
      </div>

      <div class="ws-intel-bar">
        <div class="ws-intel-bar-fill" style="width:${score.probability}%;"></div>
      </div>

      <div class="ws-intel-sub">
        ${safeStr(riskLevel)}
      </div>

      <div class="ws-intel-risk">
        ${safeStr(driverText)}
      </div>

      <div style="margin-top:10px;font-weight:800;">
        ${safeStr(actionSignal)}
      </div>
    </div>
  `;
}

function renderWorkspaceIntelligenceStrip(ws, claim, derived, channel, outcomeInsightText=""){
  const score = computeWorkspaceQuickScore(ws, claim, derived, channel);
  const auto = buildWorkspaceAutomationReadiness(ws, claim, channel);
  const completeness = workspaceEnhancedCompleteness(ws, channel, claim);
  const lines = String(outcomeInsightText || "")
    .split("\n")
    .map(x => x.trim())
    .filter(Boolean);

  const missingCount = Number(auto.requiredSourceProofNeeded || 0);
  const confidence =
    score.probability >= 80 ? "High confidence" :
    score.probability >= 60 ? "Moderate confidence" :
    "Needs strengthening";

  const helping = [];
  const attention = [];

  if (Number(completeness.pct || 0) >= 80) helping.push("Packet structure is mostly complete.");
  if (Number(auto.requiredPresent || 0) > 0) helping.push(`${Number(auto.requiredPresent || 0)} required proof item${Number(auto.requiredPresent || 0) === 1 ? "" : "s"} ready.`);
  if (Number(score.estimatedRecovery || 0) > 0) helping.push(`${formatMoneyUI(score.estimatedRecovery || 0)} estimated recovery opportunity remains.`);

  if (missingCount > 0) attention.push(`${missingCount} required proof item${missingCount === 1 ? "" : "s"} still missing.`);
  if (score.probability < 60) attention.push("Success probability is below target until proof and packet support are strengthened.");
  if (!lines.length) attention.push("No historical outcomes yet, so baseline packet guidance is being used.");

  return `
    <details class="ws-intel-strip">
      <summary>
        <div>
          <strong>Outcome Intelligence <span class="tooltip" data-tip="Shows learning from prior appeal and negotiation outcomes. When there is not enough history, this uses baseline packet guidance until completed outcomes are available.">ⓘ</span></strong>
          <div class="muted small">${safeStr(confidence)} · insight only, not another KPI panel</div>
        </div>
        <div class="ws-intel-strip-metrics">
          <span>${safeStr(channel === "negotiation" ? "Negotiation" : "Appeal")} insight</span>
          <span>${missingCount ? `${missingCount} proof gap${missingCount === 1 ? "" : "s"}` : "Proof on track"}</span>
        </div>
      </summary>

      <div class="ws-intel-strip-body">
        <div class="ws-intel-insight-grid">
          <div>
            <strong>What is helping</strong>
            <ul>${(helping.length ? helping : ["Packet is ready for review once source proof is complete."]).map(x => `<li>${safeStr(x)}</li>`).join("")}</ul>
          </div>
          <div>
            <strong>What still needs attention</strong>
            <ul>${(attention.length ? attention : ["No major outcome intelligence warnings detected."]).map(x => `<li>${safeStr(x)}</li>`).join("")}</ul>
          </div>
        </div>

        <div class="muted small" style="margin-top:10px;">
          ${lines.length
            ? lines.slice(0, 4).map(x => `• ${safeStr(x)}`).join("<br/>")
            : "Outcome learning will become more specific as appeals and negotiations are completed and tracked."
          }
        </div>
      </div>
    </details>
  `;
}

function renderWorkspaceStrategyPanel(ws, claim, derived, channel){
  const isNegotiation = channel === "negotiation";
  const docs = workspaceRequiredDocConfig(channel);
  const missingRequired = docs.filter(d => d.required && !workspaceDocPresent(ws, d, claim));

  const expected = Number(derived?.expectedInsurance || claim?.expected_amount || claim?.expected_insurance || 0);
  const paid = Number(derived?.paidAmount || claim?.paid_amount || claim?.insurance_paid || 0);
  const billed = Number(derived?.billedAmount || claim?.amount_billed || claim?.billed_amount || 0);
  const atRisk = Number(derived?.underpaidAmount || derived?.atRiskAmount || claim?.underpaid_amount || claim?.at_risk_amount || 0);

  const payer = claim?.payer || "the payer";
  const claimNo = claim?.claim_number || claim?.claim_id || "";

  const strategyTitle = isNegotiation
    ? "Contract / Underpayment Negotiation Strategy"
    : "Denial Reversal Appeal Strategy";

  const whyHere = isNegotiation
    ? `This claim is in negotiation because ${payer} paid ${formatMoneyUI(paid)} against an expected amount of ${formatMoneyUI(expected)}, leaving ${formatMoneyUI(atRisk)} in reimbursement variance.`
    : `This claim is in appeal because ${payer} denied or failed to pay the claim. The goal is to reverse the denial or force reprocessing with supporting evidence.`;

  const recommended = isNegotiation
    ? "Lead with the expected-versus-paid variance, attach EOB/ERA and claim form, then cite contract or allowed-rule support for the corrected payment."
    : "Lead with the denial reason, attach the denial notice and EOB/ERA, then support reprocessing with claim form, policy language, and medical/coding evidence when relevant.";

  const nextAction = missingRequired.length
    ? `Upload or validate: ${missingRequired.map(d => d.label).join(", ")}.`
    : isNegotiation
      ? "Review the variance explanation and requested amount, then export or submit the negotiation packet."
      : "Review the appeal argument and requested action, then export or submit the appeal packet.";

  const proofList = docs
    .filter(d => d.required || workspaceDocPresent(ws, d, claim))
    .slice(0, 6)
    .map(d => {
      const present = workspaceDocPresent(ws, d, claim);
      return `<li>${present ? "✓" : "•"} ${safeStr(d.label)}${d.why ? ` — <span class="muted">${safeStr(d.why)}</span>` : ""}</li>`;
    })
    .join("");

  return `
    <div class="ws-panel" style="border-left:4px solid #111827;">
      <h3>${safeStr(strategyTitle)}</h3>

      <div class="muted small" style="margin-bottom:8px;">
        Claim #${safeStr(claimNo)} · ${safeStr(payer)} · Billed ${formatMoneyUI(billed)} · Expected ${formatMoneyUI(expected)} · Paid ${formatMoneyUI(paid)} · Opportunity ${formatMoneyUI(atRisk)}
      </div>

      <div style="font-weight:800;margin-top:8px;">Why this claim is here</div>
      <div class="muted" style="margin-top:4px;">${safeStr(whyHere)}</div>

      <div style="font-weight:800;margin-top:10px;">Recommended strategy</div>
      <div class="muted" style="margin-top:4px;">${safeStr(recommended)}</div>

      <div style="font-weight:800;margin-top:10px;">Proof needed</div>
      <ul style="margin-top:6px;padding-left:18px;">${proofList}</ul>

      <div class="ws-callout ${missingRequired.length ? "warn" : "ok"}" style="margin-top:10px;">
        <strong>Next best action:</strong> ${safeStr(nextAction)}
      </div>
    </div>
  `;
}

function renderSubmissionPanel(ws, claim, channel){
  const submission = ws.submission || {};
  const currentRound = Number(ws[channel]?.round || 1) || 1;
  const previousSubmission = ws.submission || {};

  return `
    <div class="ws-panel">
      <h3>Submission Tracking</h3>

      <div class="ws-chip-row">
        <span class="ws-chip ${submission.status === "submitted" ? "ok" : "warn"}">
          ${submission.status || "Draft"}
        </span>
        <span class="ws-chip">Round ${currentRound}</span>
      </div>

      ${previousSubmission.submitted_at ? `
        <div class="insight-card" style="margin-top:10px;">
          <strong>Previous Submission</strong><br/>
          Submitted: ${safeStr(previousSubmission.submitted_at || "-")}<br/>
          Follow-up: ${safeStr(previousSubmission.follow_up_date || "-")}
        </div>
      ` : ``}

      ${submission.status === "submitted" ? `
        <div class="ws-callout ok" style="margin-top:10px;">
          Submitted via ${safeStr(submission.method || "N/A")}
          <br/>
          Follow-up: ${safeStr(submission.follow_up_date || "Not set")}
          <br/>
          Submitted: ${safeStr(submission.submitted_at || "")}
        </div>
      ` : ``}

      <form method="POST" action="/ai-workspace/submit" style="margin-top:10px;">
        <input type="hidden" name="billed_id" value="${safeStr(claim.billed_id)}"/>
        <input type="hidden" name="channel" value="${safeStr(channel)}"/>

        <label class="small">Method</label>
        <select name="method">
          <option>Portal</option>
          <option>Fax</option>
          <option>Mail</option>
          <option>Phone</option>
        </select>

        <label class="small">Follow-up Date</label>
        <input type="date" name="follow_up_date"/>
        <div class="small muted" style="margin-top:4px;">If left blank, the system will set a default follow-up date 14 days after submission.</div>

        <button class="btn secondary" style="margin-top:8px;">
          Submit Round ${currentRound}
        </button>
      </form>
      <script>
(function(){
  if (window.__tjhpWorkflowSubmitGuardBound) return;
  window.__tjhpWorkflowSubmitGuardBound = true;

  function showWorkflowSubmitError(form, message, focusEl){
    var card = form && form.closest ? form.closest("[data-workflow-submit-card]") : null;
    var box = form ? form.querySelector("[data-workflow-submit-error]") : null;
    if (box) { box.textContent = message; box.style.display = "block"; }
    try { (card || form).scrollIntoView({ behavior: "smooth", block: "center" }); } catch(e) {}
    if (focusEl && typeof focusEl.focus === "function") setTimeout(function(){ focusEl.focus(); }, 180);
  }

  document.addEventListener("submit", function(e){
    var form = e.target;
    if (!form || !form.matches || !form.matches("[data-workflow-submit-form]")) return;
    var incomplete = String(form.getAttribute("data-source-proof-incomplete") || "") === "1";
    if (!incomplete) return;
    var checkbox = form.querySelector("[name='confirm_missing_source_docs']");
    if (!checkbox || !checkbox.checked) {
      e.preventDefault();
      showWorkflowSubmitError(form, "Confirm that you want to proceed with system-found evidence or missing source proof before submitting.", checkbox);
      return false;
    }
  }, true);
})();
</script>
    </div>
  `;
}

function renderPacketReadinessSummary(ws, channel){
  const enhanced = workspaceEnhancedCompleteness(ws, channel);
  const ready = canMarkReady(ws, channel);
  const tone = ready.ok ? "ok" : "warn";
  return `
    <div class="ws-panel">
      <h3>Packet Readiness</h3>
      <div class="ws-score">
        <div class="ws-score-num">${enhanced.pct}%</div>
        <div class="ws-score-sub">${enhanced.complete} of ${enhanced.total} preview elements completed</div>
      </div>
      <div class="ws-chip-row">
        <span class="ws-chip ${tone}">${ready.ok ? "Ready for Review" : "Missing Required Items"}</span>
        <span class="ws-chip">${channel === "appeal" ? "Appeal Packet" : "Negotiation Packet"}</span>
      </div>
      ${
        ready.ok
          ? `<div class="ws-callout ok" style="margin-top:10px;">This packet has the required documents for review. Export will match the live preview.</div>`
          : `<div class="ws-callout warn" style="margin-top:10px;">Missing required documents: ${ready.missing.map(workspaceDocLabel).join(", ")}.</div>`
      }
    </div>
  `;
}

function renderWorkflowPanel(ws, claim, channel, opts = {}){
  const submission = ws.submission || {};
  const currentRound = Number(ws[channel]?.round || 1) || 1;
  const previousSubmission = ws.submission || {};
  const enhanced = workspaceEnhancedCompleteness(ws, channel);
  const ready = canMarkReady(ws, channel);
  const autoReadiness = buildWorkspaceAutomationReadiness(ws, claim, channel);
  const sourceProofNeeded = Number(autoReadiness.requiredSourceProofNeeded || 0);
  const sourceProofIncomplete = sourceProofNeeded > 0;
  const blockedReason = String(
    opts.submitBlocked ||
    (submission.status === "blocked" ? submission.blocked_reason : "") ||
    ""
  ).trim();

  const blockedMessage =
    blockedReason === "confirm_missing_source_docs_required"
      ? "Confirm that you want to proceed with system-found evidence or missing source proof before submitting."
      : blockedReason === "override_reason_required"
        ? "Reason is optional now. Confirm the source-proof override checkbox, then submit again."
        : "";
  const isSubmitted = submission.status === "submitted";
  const tone = ready.ok ? "ok" : "warn";
  const packetSubmissions = Array.isArray(ws.packet_submissions) ? ws.packet_submissions : [];
  const latestSubmittedPacket = packetSubmissions
    .filter(s => s && String(s.channel || "") === String(channel) && String(s.status || "") === "submitted")
    .sort((a,b) => new Date(b.submitted_at || 0) - new Date(a.submitted_at || 0))[0] ||
    (submission.status === "submitted" ? submission : null);
  const lastSubmittedLabel = latestSubmittedPacket
    ? (latestSubmittedPacket.label || `${channel === "negotiation" ? "Negotiation" : "Appeal"} Round ${latestSubmittedPacket.round || ""} · v${latestSubmittedPacket.version || ""}`)
    : "";

  return `
    <div id="workflow" class="ws-panel" data-workflow-submit-card>
      <h3>⚙️ Workflow</h3>
      ${blockedMessage ? `<div class="ws-callout warn" data-submit-blocked-message style="margin-bottom:10px;">${safeStr(blockedMessage)}</div>` : ""}
      <div class="ws-score">
        <div class="ws-score-num">${autoReadiness.submissionPct}%</div>
        <div class="ws-score-sub">
          Source proof readiness ${autoReadiness.submissionPct}% · Draft readiness ${autoReadiness.draftPct}% · ${enhanced.complete} of ${enhanced.total} preview elements completed
        </div>
      </div>
      <div class="ws-chip-row">
        <span class="ws-chip ${isSubmitted ? "ok" : tone}">${isSubmitted ? "Submitted" : (ready.ok ? "Ready for Review" : "Source proof needed")}</span>
        ${latestSubmittedPacket ? `<span class="ws-chip ok">Last submitted: ${safeStr(lastSubmittedLabel)}</span><span class="ws-chip warn">Next draft: Round ${currentRound}</span>` : `<span class="ws-chip warn">Draft</span><span class="ws-chip">Round ${currentRound}</span>`}
      </div>
      ${
        isSubmitted
          ? ``
          : ready.ok
          ? (
              autoReadiness.submissionPct >= 100
                ? `<div class="ws-callout ok" style="margin-top:10px;">Packet has required source documents attached or pulled for submission proof.</div>`
                : (() => {
                    const missingSourceProofLabels = (autoReadiness.required || [])
                      .filter(r => !workspaceIsSubmissionProof(r))
                      .map(r => r.label || workspaceDocLabel(r.key));
                    return `<div class="ws-callout warn" style="margin-top:10px;">Source proof still needed before payer submission: ${safeStr(missingSourceProofLabels.join(", "))}. System-found evidence can help draft the packet, but uploaded or pulled source files are stronger when the payer requires actual document proof.</div>`;
                  })()
            )
          : `<div class="ws-callout warn" style="margin-top:10px;">Source proof needed: ${ready.missing.map(workspaceDocLabel).join(", ")}.</div>`
      }

      ${submission.status === "submitted" ? `
        <div class="ws-callout ok" style="margin-top:10px;">
          Last submitted: ${safeStr(lastSubmittedLabel || "-")}<br/>
          Submitted via: ${safeStr(submission.method || "N/A")}
          <br/>
          Follow-up: ${safeStr(submission.follow_up_date || "Not set")}
          <br/>
          Submitted: ${safeStr(submission.submitted_at || "")}<br/>
          Next draft: Round ${currentRound}
        </div>
      ` : ``}

      ${previousSubmission.submitted_at ? `
        <div class="insight-card" style="margin-top:10px;">
          <strong>Previous Submission</strong><br/>
          Submitted: ${safeStr(previousSubmission.submitted_at || "-")}<br/>
          Follow-up: ${safeStr(previousSubmission.follow_up_date || "-")}
        </div>
      ` : ``}

      <form method="POST" action="/ai-workspace/submit" class="ws-submit-form" data-workflow-submit-form data-source-proof-incomplete="${sourceProofIncomplete ? "1" : "0"}">
        <div class="ws-callout warn" data-workflow-submit-error style="display:none;"></div>
        <input type="hidden" name="billed_id" value="${safeStr(claim.billed_id)}"/>
        <input type="hidden" name="channel" value="${safeStr(channel)}"/>

        <div class="ws-submit-grid">
          <div class="ws-submit-field">
            <label class="small">Method</label>
            <select name="method">
              <option>Portal</option>
              <option>Fax</option>
              <option>Mail</option>
              <option>Phone</option>
            </select>
          </div>
          <div class="ws-submit-field">
            <label class="small">Follow-up Date</label>
            <input type="date" name="follow_up_date"/>
        <div class="small muted" style="margin-top:4px;">If left blank, the system will set a default follow-up date 14 days after submission.</div>
          </div>
          <div class="ws-submit-field" style="grid-column:1 / -1;">
            <label class="small">Optional reason for submitting without source proof</label>
            <textarea name="override_reason" placeholder="Optional. Add context for why this packet can proceed with system-found evidence or missing source proof." style="min-height:84px;"></textarea>
          </div>
        </div>

        <label class="small ws-submit-confirm">
          <input type="checkbox" name="confirm_missing_source_docs" value="1"/>
          Proceed with system-found evidence or missing source proof
        </label>

        <button class="btn secondary" style="margin-top:8px;">
          Submit Round ${currentRound}
        </button>
      </form>
      <script>
(function(){
  if (window.__tjhpWorkflowSubmitGuardBound) return;
  window.__tjhpWorkflowSubmitGuardBound = true;

  function showWorkflowSubmitError(form, message, focusEl){
    var card = form && form.closest ? form.closest("[data-workflow-submit-card]") : null;
    var box = form ? form.querySelector("[data-workflow-submit-error]") : null;
    if (box) { box.textContent = message; box.style.display = "block"; }
    try { (card || form).scrollIntoView({ behavior: "smooth", block: "center" }); } catch(e) {}
    if (focusEl && typeof focusEl.focus === "function") setTimeout(function(){ focusEl.focus(); }, 180);
  }

  document.addEventListener("submit", function(e){
    var form = e.target;
    if (!form || !form.matches || !form.matches("[data-workflow-submit-form]")) return;
    var incomplete = String(form.getAttribute("data-source-proof-incomplete") || "") === "1";
    if (!incomplete) return;
    var checkbox = form.querySelector("[name='confirm_missing_source_docs']");
    if (!checkbox || !checkbox.checked) {
      e.preventDefault();
      showWorkflowSubmitError(form, "Confirm that you want to proceed with system-found evidence or missing source proof before submitting.", checkbox);
      return false;
    }
  }, true);
})();
</script>
    </div>
  `;
}

