function workspaceEvidenceUsageForSection(ws, channel, sectionKey){ return workspaceEvidenceUsageRows(ws).filter(r => r.channel === channel && r.target_section_key === sectionKey); }
function tjhpRecordEvidenceUsageFromSuggestion(ws, suggestion, user){ ws.evidence_usage = Array.isArray(ws.evidence_usage) ? ws.evidence_usage : []; const existing = ws.evidence_usage.find(r => r && r.suggestion_id === suggestion.suggestion_id); const row = existing || { usage_id: tjhpEvidenceUsageId(), suggestion_id: suggestion.suggestion_id }; row.org_id = suggestion.org_id || ws.org_id || ""; row.billed_id = suggestion.billed_id || ws.billed_id || ""; row.channel = suggestion.channel || ""; row.target_section_key = suggestion.target_section_key || ""; row.target_section_label = suggestion.target_section_label || tjhpWorkspaceSectionLabel(suggestion.target_section_key || ""); row.source_attachment_ids = Array.isArray(suggestion.source_attachment_ids) ? suggestion.source_attachment_ids : []; row.source_filenames = Array.isArray(suggestion.source_filenames) ? suggestion.source_filenames : []; row.evidence_title = suggestion.title || ""; row.evidence_summary = suggestion.rationale || ""; row.applied_text_excerpt = String(suggestion.suggested_text || "").slice(0, 240); row.applied_at = suggestion.applied_at || nowISO(); row.applied_by = suggestion.applied_by || user?.email || user?.user_id || "user"; row.active = true; row.updated_at = nowISO(); if (!existing) ws.evidence_usage.push(row); return row; }
function tjhpEvidenceUsageStatusForAttachment(ws, attachment_id){ const aid = String(attachment_id || ""); if (!aid) return "not_used"; const usage = workspaceEvidenceUsageRows(ws).some(r => Array.isArray(r.source_attachment_ids) && r.source_attachment_ids.includes(aid)); if (usage) return "applied"; const sug = (Array.isArray(ws?.evidence_draft_suggestions) ? ws.evidence_draft_suggestions : []).find(s => s && Array.isArray(s.source_attachment_ids) && s.source_attachment_ids.includes(aid) && s.status !== "dismissed"); if (sug) return sug.status === "applied" ? "applied" : "suggested"; const att = (Array.isArray(ws?.attachments) ? ws.attachments : []).find(a => String(a?.attachment_id || "") === aid); const ex = att?.evidence_extraction || {}; if (ex.needs_review) return "needs_review"; if (ex.status === "reviewed") return "reviewed"; if (ex.status === "extracted") return "extracted"; return "not_used"; }
function tjhpEvidenceUsageLabelsForAttachment(ws, attachment_id){ const aid = String(attachment_id || ""); const out = []; workspaceEvidenceUsageRows(ws).forEach(r => { if (Array.isArray(r.source_attachment_ids) && r.source_attachment_ids.includes(aid)) out.push(`Applied to ${r.target_section_label || tjhpWorkspaceSectionLabel(r.target_section_key || "") || "Section"}`); }); const suggestedTargets = new Set(); (Array.isArray(ws?.evidence_draft_suggestions) ? ws.evidence_draft_suggestions : []).forEach(s => { if (s && s.status === "pending" && Array.isArray(s.source_attachment_ids) && s.source_attachment_ids.includes(aid)) suggestedTargets.add(s.target_section_label || tjhpWorkspaceSectionLabel(s.target_section_key || "") || "Section"); }); suggestedTargets.forEach(t => out.push(`Suggested for ${t}`)); const status = tjhpEvidenceUsageStatusForAttachment(ws, aid); if (status === "needs_review") out.push("Needs review"); if (status === "extracted" || status === "not_used") out.push("Extracted, not used yet"); if (status === "reviewed") out.push("Reviewed"); return out; }
