const FORCE_UPLOAD_SMOKE_TESTS = process.env.TJHP_FORCE_UPLOAD_SMOKE_TESTS === "true";

const SHOULD_RUN_UPLOAD_SMOKE_TESTS =
  WANTS_UPLOAD_SMOKE_TESTS &&
  (
    FORCE_UPLOAD_SMOKE_TESTS ||
    (!IS_PROD && !IS_RAILWAY_RUNTIME)
  );


