      const claim = eligibility.claim || {};
      const linkedBilledId = String(eligibility.billed_id || tjhpPriorAuthClaimField(claim, ["billed_id","claim_id","claim_number"]) || "billed_route_form_match").trim();
      const linkedClaimId = String(tjhpPriorAuthClaimField(claim, ["claim_id","billed_id","claim_number"]) || linkedBilledId).trim();
      const existingNotes = String(ready.case.notes || "").trim();
      const claimLabel = String(eligibility.claim_number || linkedClaimId || linkedBilledId || "selected billed claim").trim();
      const linkNote = `[${new Date().toISOString()}] Linked prior authorization to billed claim ${claimLabel}. Match confidence: ${eligibility.confidence || "unknown"}; reasons: ${Array.isArray(eligibility.reasons) && eligibility.reasons.length ? eligibility.reasons.join(", ") : "not recorded"}.`;
      const linked = upsertPriorAuthCase(org_id, { ...ready.case, status: "Linked to Claim", linked_billed_id: linkedBilledId, linked_claim_id: linkedClaimId, notes: existingNotes ? `${existingNotes}\n${linkNote}` : linkNote }, "smoke");
