      const actionRows = tjhpPriorAuthActionCenterRows(org_id);
      assert(!actionRows.some(x => String(x.auth_case_id || "") === String(linkedCase.auth_case_id || "")), "Linked to Claim case should leave prior-auth action queue");
      assert.strictEqual(JSON.stringify(readJSON(FILES.payments, [])), paymentsBefore);
      assert.strictEqual(JSON.stringify(readJSON(FILES.payer_contracts, [])), contractsBefore);
      assert.strictEqual(JSON.stringify(readJSON(FILES.document_ingests, [])), ingestsBefore);
      savePriorAuthCasesForOrg(org_id, []);
      writeJSON(FILES.billed, originalBilled);
      assert.strictEqual(getPriorAuthCases(org_id).length, 0);
      assert.strictEqual(JSON.stringify(readJSON(FILES.billed, [])), billedBefore);
      process.stdout.write("PRIOR_AUTH_CLAIM_LINK_ROUTE_FORM_SMOKE_TESTS_PASSED\n");
